-- Poems batch 214
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('933be701-83d5-4259-921f-51e5a7bfd7fc','秋日旅舍感懷','潘閬','宋','宋诗','song-poetry','','[]','秋色入簷楹，閒門開復扃。',48,'全唐诗/poet.song.2000.json','["秋色入簷楹，閒門開復扃。", "愁人欲長醉，薄酒又還醒。", "攪照頭將白，逢誰眼暫青。", "祇應南與北，唯此念飄零。"]'),
('a7f72769-ea87-4363-938f-b37c802078d0','歲暮自桐廬歸錢塘晚泊漁浦','潘閬','宋','宋诗','song-poetry','','[]','久客見華髮，孤櫂桐廬歸。',48,'全唐诗/poet.song.2000.json','["久客見華髮，孤櫂桐廬歸。", "新月無朗照，落日有餘暉。", "漁浦風水急，龍山煙火微。", "時聞沙上雁，一一背人飛。"]'),
('5e7544f2-cf28-4654-8566-c1d64473c445','孤山寺易從房留師','潘閬','宋','宋诗','song-poetry','','[]','寶塔孤峰頂，題居積翠中。',48,'全唐诗/poet.song.2000.json','["寶塔孤峰頂，題居積翠中。", "四邊湖水繞，一逕郭門通。", "香滴松梢雨，凉生竹簟風。", "閒吟與閒坐，此興與誰同。"]'),
('bc1f10ea-ffe4-4630-bd06-ebd5cfe0e8a9','春日對酒書事','潘閬','宋','宋诗','song-poetry','','[]','車馬不暫駐，年光如瀉波。',48,'全唐诗/poet.song.2000.json','["車馬不暫駐，年光如瀉波。", "人間歡樂少，陌上別離多。", "往事祇如此，浮生終若何。", "花前一尊酒，得失且高歌。"]'),
('5aac67f6-a767-4cf2-a72d-4924ec1c6818','與張覃秀才鄴中途次言別','潘閬','宋','宋诗','song-poetry','','[]','南北各何之，重來寧有期。',48,'全唐诗/poet.song.2000.json','["南北各何之，重來寧有期。", "相將行數里，欲別立多時。", "野店人煙迥，前村草木衰。", "祇應今夜夢，未苦遠分離。"]'),
('a482054d-6bf8-4038-aab9-76e0025a8ff3','敘事答所知','潘閬','宋','宋诗','song-poetry','','[]','久客向天末，唯將鸞鶴羣。',48,'全唐诗/poet.song.2000.json','["久客向天末，唯將鸞鶴羣。", "盈虧頻歎月，舒卷幾憐雲。", "有志思光國，無才可佐君。", "知音時見贈，應達聖朝聞。"]'),
('b7ce02fc-2684-404f-88cd-614817fb6d4d','暮春漳川閒居收事','潘閬','宋','宋诗','song-poetry','','[]','吟齋漳水濱，孤僻度殘春。',48,'全唐诗/poet.song.2000.json','["吟齋漳水濱，孤僻度殘春。", "長喜詩無病，不憂家更貧。", "鐘聲來遠寺，山色徧諸鄰。", "門有誰相訪，僧過豈厭頻。"]'),
('d8b12352-f14c-4760-82d1-6cb27b5f1dac','夏日宿西禪院','潘閬','宋','宋诗','song-poetry','','[]','此地絕炎蒸，深疑到不能。',48,'全唐诗/poet.song.2000.json','["此地絕炎蒸，深疑到不能。", "夜凉如有雨，院靜若無僧。", "枕潤連雲石，窗明照佛燈。", "浮生多賤骨，時日恐難勝。"]'),
('4c2371a0-6350-448e-909e-c1f0f0a5fd10','舟中自吳之越寄潤州柳侍御開楊博士邁','潘閬','宋','宋诗','song-poetry','','[]','兩岸山光合，況當三月天。',48,'全唐诗/poet.song.2000.json','["兩岸山光合，況當三月天。", "好花紅照水，芳草綠隨船。", "貨藥村橋醉，收帆野渡眠。", "因思二朝客，同泛恐無緣。"]'),
('950c4582-e8c9-4002-8d6e-dbbfe6d94b0f','上李學士','潘閬','宋','宋诗','song-poetry','','[]','名場欲獨立，一念一心寒。',48,'全唐诗/poet.song.2000.json','["名場欲獨立，一念一心寒。", "白日昇天易，明時取仕難。", "家園半牢落，鬚髮漸衰殘。", "試把平生業，來投作者看。"]'),
('506accd8-82a3-4bcb-846d-3589dc76b24f','中秋無月','潘閬','宋','宋诗','song-poetry','','[]','西風妒秋月，浮雲重疊生。',48,'全唐诗/poet.song.2000.json','["西風妒秋月，浮雲重疊生。", "一夕不見光，雙目如失明。", "立恐疾足折，坐覺愁抱盈。", "況當百蟲苦，遶階千萬聲。"]'),
('5b190fb2-01f7-49d9-976f-3d54fea5c966','秋日題琅琊山寺','潘閬','宋','宋诗','song-poetry','','[]','巖下多幽景，且無塵事喧。',48,'全唐诗/poet.song.2000.json','["巖下多幽景，且無塵事喧。", "鐘聲晴徹郭，山色曉當門。", "深洞藏泉脈，懸崖露樹根。", "更期來此宿，絕頂聽寒猿。"]'),
('aeeede4e-3ffc-4c69-bced-65f79fbeccd6','落葉','潘閬','宋','宋诗','song-poetry','','[]','片片落復落，園林漸向空。',48,'全唐诗/poet.song.2000.json','["片片落復落，園林漸向空。", "幾番經夜雨，一半是秋風。", "靜擁莎階下，閒堆蘚徑中。", "谷松與巖檜，寧共此時同。"]'),
('e2d9b4a1-f2bb-49d7-93ac-d9473c13ac4f','敘吟','潘閬','宋','宋诗','song-poetry','','[]','高吟見太平，不恥老無成。',48,'全唐诗/poet.song.2000.json','["高吟見太平，不恥老無成。", "髮任莖莖白，詩須字字清。", "搜疑滄海竭，得恐鬼神驚。", "此外非關念，人間萬事輕。"]'),
('d235fa60-1702-4a5d-95ca-c2e8c8f4e8f1','北高峰塔','潘閬','宋','宋诗','song-poetry','','[]','北高峰上塔，竟上最高層。',48,'全唐诗/poet.song.2000.json','["北高峰上塔，竟上最高層。", "嘗謂人難到，何當我獨登。", "天香聞不斷，海月見微稜。", "懶下紅塵路，重來恐未能。"]'),
('a4424e0e-3d46-4568-8631-ab74cc9e34c0','寄陳希夷','潘閬','宋','宋诗','song-poetry','','[]','不信先生語，剛來帝里遊。',48,'全唐诗/poet.song.2000.json','["不信先生語，剛來帝里遊。", "清宵無好夢，白日有閒愁。", "世態既如此，壯心應已休。", "求歸歸未得，吟上水邊樓。"]'),
('5f21616d-4f65-464d-82e3-06de353a9d4d','自諸暨抵剡  其一','潘閬','宋','宋诗','song-poetry','','[]','莫歎塵泥汩，且圖山水游。',48,'全唐诗/poet.song.2000.json','["莫歎塵泥汩，且圖山水游。", "雙峰天姥翠，一舸剡溪秋。", "不見戴安道，有懷王子猷。", "西風無限意，盡屬釣魚舟。"]'),
('427508b6-5f5f-4ffa-85d4-5d8462ae2713','自諸暨抵剡  其二','潘閬','宋','宋诗','song-poetry','','[]','夷猶雙槳去，暮不辨東西。',48,'全唐诗/poet.song.2000.json','["夷猶雙槳去，暮不辨東西。", "夕照偏依樹，秋光半落溪。", "風高一雁小，雲薄四天低。", "莽蕩孤帆卸，水村楊柳堤。"]'),
('fdcd1271-a4f7-479e-8650-30c4d3edf90b','自諸暨抵剡  其三','潘閬','宋','宋诗','song-poetry','','[]','秋渚涵空碧，秋山刷眼青。',48,'全唐诗/poet.song.2000.json','["秋渚涵空碧，秋山刷眼青。", "排頭煙樹老，撲面水風醒。", "上瀨復下瀨，長亭仍短亭。", "夜船明月好，客夢滿流螢。"]'),
('67a71f0a-ed6b-4a77-ae98-a7cc0b1828b0','自諸暨抵剡  其四','潘閬','宋','宋诗','song-poetry','','[]','出得雲門路，風悽日夕曛。',48,'全唐诗/poet.song.2000.json','["出得雲門路，風悽日夕曛。", "船撐鑑湖月，路指沃州雲。", "山色周遭見，谿流屈曲分。", "一觴還一詠，誰是右將軍。"]'),
('db0df112-0294-4d5f-95a0-7af3797eefad','瓜州臨江亭留題','潘閬','宋','宋诗','song-poetry','','[]','誰構危亭已半空，野人時得恣疏慵。',64,'全唐诗/poet.song.2000.json','["誰構危亭已半空，野人時得恣疏慵。", "閒觀揚子江心浪，靜聽金山寺裏鐘。", "醉卧豈能妨燕雀，狂吟爭不動魚龍。", "夜來雨歇蛙聲亂，憶著嵩陽千萬峰。"]'),
('79ffca60-759f-477d-93f4-23500a184d5c','秋日登樓客次懷張覃進士','潘閬','宋','宋诗','song-poetry','','[]','聞說飄零亦異鄉，登樓吟望益悲凉。',64,'全唐诗/poet.song.2000.json','["聞說飄零亦異鄉，登樓吟望益悲凉。", "當時欲別言難盡，他日相逢話更長。", "蟬噪水村千萬樹，雁過雲岫兩三行。", "明朝策蹇還無定，空倚危欄到夕陽。"]'),
('1677ff42-31dd-4933-9c7f-26e70e20cdc0','寄贈柳殿院開授崇儀使赴邊上','潘閬','宋','宋诗','song-poetry','','[]','從來長見說兵機，今日君恩志豈違。',64,'全唐诗/poet.song.2000.json','["從來長見說兵機，今日君恩志豈違。", "驄馬不騎騎鐵馬，繡衣休挂挂戎衣。", "雄師已聽心皆伏，醜虜將聞魄盡飛。", "應笑苦吟頭白者，二南章句轉衰微。"]'),
('53630e2a-d1cd-49f6-9ebb-057c95770264','維揚秋日牡丹因寄六合縣尉郭承範','潘閬','宋','宋诗','song-poetry','','[]','遶欄忽見思傍徨，造化功深莫可量。',64,'全唐诗/poet.song.2000.json','["遶欄忽見思傍徨，造化功深莫可量。", "穠艷算無三月盛，殘紅更向九秋芳。", "萬家珠翠還爭賞，一郡笙歌又是狂。", "惆悵東籬下黄菊，有誰來折泛瑶觴。"]'),
('8f6a8908-57e0-40af-8015-df6d2c0358ff','樽前勉兄長','潘閬','宋','宋诗','song-poetry','','[]','一家久寄浙江濱，倏忽如今二十春。',64,'全唐诗/poet.song.2000.json','["一家久寄浙江濱，倏忽如今二十春。", "須信百年都似夢，莫嗟萬事不如人。", "樽中有酒何妨醉，篋裏無金未是貧。", "但看故鄉榮達者，算來多葬北邙塵。"]'),
('8d4283cd-1454-479e-a6de-439c0f44786e','赴滁州散參軍途中書事','潘閬','宋','宋诗','song-poetry','','[]','微軀不殺謝天恩，容養疏慵世未聞。',64,'全唐诗/poet.song.2000.json','["微軀不殺謝天恩，容養疏慵世未聞。", "昔日已爲閒助教，今朝又作散參軍。", "高吟瘦馬衝殘雪，遠看孤鴻入斷雲。", "到任也應無別事，願將清俸買香焚。"]'),
('9c6bf8b0-3b24-4e27-a2e2-25ea204d3abe','聞高舍人錫下世','潘閬','宋','宋诗','song-poetry','','[]','早掌綸言世盡知，豈期謫宦至于斯。',64,'全唐诗/poet.song.2000.json','["早掌綸言世盡知，豈期謫宦至于斯。", "生前是客能投卷，死後何人爲撰碑。", "讒佞萬端應已矣，文章千古恐無之。", "野夫舊句多蒙賞，昨日閒思淚暗垂。"]'),
('e4b8c08a-0b0e-4454-9ee8-a52272ef7ff8','長安道中','潘閬','宋','宋诗','song-poetry','','[]','游子辭鄉早，高堂親已老。',24,'全唐诗/poet.song.2000.json','["游子辭鄉早，高堂親已老。", "燕來不東飛，寄書何日到。"]'),
('45dac1ad-b6cd-4925-a25d-eba01a2d4921','題思歸鳥','潘閬','宋','宋诗','song-poetry','','[]','高枝枝上鳥，終日叫思歸。',24,'全唐诗/poet.song.2000.json','["高枝枝上鳥，終日叫思歸。", "如斯羽翼全，何不望鄉飛。"]'),
('bb11c19d-6a88-40ea-933b-4d83906a912f','謝寇員外準見示詩卷','潘閬','宋','宋诗','song-poetry','','[]','一軸新詩意轉深，幾迴看了又重尋。',32,'全唐诗/poet.song.2000.json','["一軸新詩意轉深，幾迴看了又重尋。", "最憐積水浮秋漢，閒望滄溟盡日吟。"]'),
('88d6bc30-bfc1-461b-a37d-23f4b056bd80','送成庫部肅建安監稅','潘閬','宋','宋诗','song-poetry','','[]','萬樹青青带雨寒，離亭相別淚闌干。',32,'全唐诗/poet.song.2000.json','["萬樹青青带雨寒，離亭相別淚闌干。", "莫將便作無情物，亦待抽身入建安。"]'),
('b723c0fd-2b4b-4eb8-b1ad-820a81eaeac4','中秋月','潘閬','宋','宋诗','song-poetry','','[]','待月中秋上古城，迥然光掩別宵明。',32,'全唐诗/poet.song.2000.json','["待月中秋上古城，迥然光掩別宵明。", "野人望久翻惆悵，無奈浮雲滅又生。"]'),
('2bd1a552-b8cc-45a8-97a5-0d99cc4074f1','呈錢塘知府薛諫議','潘閬','宋','宋诗','song-poetry','','["\u897f\u6e56"]','再到錢塘眼塹清，騎馿看月又南行。',32,'全唐诗/poet.song.2000.json','["再到錢塘眼塹清，騎馿看月又南行。", "可憐一片西湖水，不得垂綸老此生。"]'),
('52da2910-921d-4b2a-83bd-232a2689bd5c','金陵禁林有感','潘閬','宋','宋诗','song-poetry','','[]','六代繁華難重問，此時興廢動吟情。',32,'全唐诗/poet.song.2000.json','["六代繁華難重問，此時興廢動吟情。", "空流一带秦淮水，朝暮惟聞鳴咽聲。"]'),
('95db513a-04cd-4fd8-9137-ba43e87c3af4','到錢塘却寄姑蘇太守','潘閬','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','姑蘇太守義何長，東泛仙舟已不忘。',32,'全唐诗/poet.song.2000.json','["姑蘇太守義何長，東泛仙舟已不忘。", "更借洞庭湖上月，數宵相送到錢塘。"]'),
('6bfc8a1e-a19b-4fa2-812e-e0d49febc67d','贈林處士逋','潘閬','宋','宋诗','song-poetry','','[]','雲翦烏妙霧翦衣，存神養氣語還稀。',32,'全唐诗/poet.song.2000.json','["雲翦烏妙霧翦衣，存神養氣語還稀。", "人人盡喚孫思邈，只恐身輕白日飛。"]'),
('14462790-9b77-42dc-a75e-22cfd0e364bb','宿靈隠寺','潘閬','宋','宋诗','song-poetry','','[]','繞寺千千萬萬峰，滿天風雪打杉松。',32,'全唐诗/poet.song.2000.json','["繞寺千千萬萬峰，滿天風雪打杉松。", "地爐火暖黄昏睡，更有何人似我慵。"]'),
('701b804c-803b-41cf-8b02-ab2dd79fcc24','贈吳處士棋','潘閬','宋','宋诗','song-poetry','','[]','昔日長饒國手先，如今多病卧林泉。',32,'全唐诗/poet.song.2000.json','["昔日長饒國手先，如今多病卧林泉。", "有時閒倚青松笑，猶憶曾輸一著玄。"]'),
('f67e9390-e507-4d31-bccb-779cea1dae17','留別金山寺','潘閬','宋','宋诗','song-poetry','','[]','山頂風摇萬樹鳴，扁舟欲解覺難行。',32,'全唐诗/poet.song.2000.json','["山頂風摇萬樹鳴，扁舟欲解覺難行。", "羨師齋後關門睡，不管波濤四面生。"]'),
('83db9b40-2569-4c4c-9d2a-4f02ab9fb67f','書璿公房牡丹','潘閬','宋','宋诗','song-poetry','','[]','寺中聞說牡丹花，多少人爭耳傍誇。',32,'全唐诗/poet.song.2000.json','["寺中聞說牡丹花，多少人爭耳傍誇。", "潦倒參軍來看晚，數枝已謝病僧家。"]'),
('ae84e060-5c12-42bd-a05c-9a2e4973a14e','旅舍秋夕書懷','潘閬','宋','宋诗','song-poetry','','[]','邊鴻過盡背枕卧，弟姪無書憂膽破。',32,'全唐诗/poet.song.2000.json','["邊鴻過盡背枕卧，弟姪無書憂膽破。", "蛩聲更苦不忍聞，半夜起來塞耳坐。"]'),
('0b86a720-92d5-4d76-94ed-0ea8759e4130','中秋與柳贊善開宗贊善坦寇學士準宿宋拾遺白宅不見月','潘閬','宋','宋诗','song-poetry','','[]','共約中秋來看月，一輪終不見清輝。',32,'全唐诗/poet.song.2000.json','["共約中秋來看月，一輪終不見清輝。", "衆人眠後唯孤坐，翻憶無雲宿翠微。"]'),
('73c544e0-dc8a-4486-9c4c-26171ac8dcf1','寄石隠之','潘閬','宋','宋诗','song-poetry','','[]','獨上危樓返照間，亂鴉羣鳥噪迴還。',32,'全唐诗/poet.song.2000.json','["獨上危樓返照間，亂鴉羣鳥噪迴還。", "故人歲暮在何處，空見千山與萬山。"]'),
('5a2772bb-caa4-4cf4-9ef9-65ad6dfefdd8','送馮尊師德之出長安','潘閬','宋','宋诗','song-poetry','','[]','浩浩霜風萬木寒，高吟大醉出長安。',32,'全唐诗/poet.song.2000.json','["浩浩霜風萬木寒，高吟大醉出長安。", "杖頭一卷金丹訣，塵世何人借得看。"]'),
('48517647-8cc3-4024-8eb0-979448af7a7b','與道士馮德之話別','潘閬','宋','宋诗','song-poetry','','[]','一宿山房話別離，慇懃勸我酒盈卮。',32,'全唐诗/poet.song.2000.json','["一宿山房話別離，慇懃勸我酒盈卮。", "更教弟子橫琴送，彈徹悲風盡淚垂。"]'),
('4b84bdfa-e29c-48da-8aac-81112fdffa90','聞陳贄郎中下世','潘閬','宋','宋诗','song-poetry','','[]','有家數口寄伊川，孤宦東西二十年。',32,'全唐诗/poet.song.2000.json','["有家數口寄伊川，孤宦東西二十年。", "見說葬時無一物，空留滿篋舊文編。"]'),
('aba291c7-2fc3-4b90-9bc6-4797705cdd2c','喜臘雪','潘閬','宋','宋诗','song-poetry','','[]','久旱臘月如夏熱，夜來忽降一尺雪。',32,'全唐诗/poet.song.2000.json','["久旱臘月如夏熱，夜來忽降一尺雪。", "叫謝上天聲應徹，且壓瘴氣不作孽。"]'),
('c948c8ff-7e24-4eea-aedc-126ca3bb2283','宮詞','潘閬','宋','宋诗','song-poetry','','[]','學畫蛾眉獨出羣，當時人道便承恩。',32,'全唐诗/poet.song.2000.json','["學畫蛾眉獨出羣，當時人道便承恩。", "年年不見君王面，花落黄昏空掩門。"]'),
('262df22f-9a89-4f15-881f-798b8c59283f','過華山','潘閬','宋','宋诗','song-poetry','','[]','高愛三峰插太虛，掉頭吟望倒騎馿。',32,'全唐诗/poet.song.2000.json','["高愛三峰插太虛，掉頭吟望倒騎馿。", "旁人大笑從他笑，終擬移家向此居。"]'),
('195ae4c6-d7ad-4c29-9acb-1ae7067b2f3c','題資福院石井','潘閬','宋','宋诗','song-poetry','','[]','炎炎畏日樹將焚，却恨都無一點雲。',32,'全唐诗/poet.song.2000.json','["炎炎畏日樹將焚，却恨都無一點雲。", "强跨蹇馿來得到，皆疑渴殺老參軍。"]'),
('2520643b-4a48-4857-a835-83c1c9ea2ae0','曹娥廟','潘閬','宋','宋诗','song-poetry','','[]','曹娥廟前秋草平，曹娥廟裏秋月明。',32,'全唐诗/poet.song.2000.json','["曹娥廟前秋草平，曹娥廟裏秋月明。", "扁舟一夜炯無寐，近聽潮聲似哭聲。"]'),
('2dfbe4ad-d32c-4b1a-a91a-4de97d796086','九華山','潘閬','宋','宋诗','song-poetry','','["\u534e\u5c71", "\u4e5d\u534e\u5c71"]','將齊華嶽猶多六，若並巫山又欠三。',32,'全唐诗/poet.song.2000.json','["將齊華嶽猶多六，若並巫山又欠三。", "好是雨餘江上望，白雲堆裏潑濃藍。"]'),
('f92ffb26-33e3-4694-8231-65891abcb318','離滁陽','潘閬','宋','宋诗','song-poetry','','[]','長亭黄葉正紛紛，一曲驪歌酒十分。',32,'全唐诗/poet.song.2000.json','["長亭黄葉正紛紛，一曲驪歌酒十分。", "須信滁陽人有意，滿城來送散參軍。"]'),
('8715cbe7-5d3c-4d52-907b-50cc6483c74a','書詩卷末','潘閬','宋','宋诗','song-poetry','','[]','一卷詩成二十年，畫曾忘食夜忘眠。',32,'全唐诗/poet.song.2000.json','["一卷詩成二十年，畫曾忘食夜忘眠。", "莫言不及相如賦，誰敢高吟漢帝前。"]'),
('c3e08355-f4f0-499d-a11c-1ba8d51b7de1','登應天寺塔','潘閬','宋','宋诗','song-poetry','','[]','閑上應天寺裏塔，九層突兀入幽雲。',64,'全唐诗/poet.song.2000.json','["閑上應天寺裏塔，九層突兀入幽雲。", "下窺已覺紅塵別，低語猶疑碧落聞。", "秦望山高如髻簇，照湖水闊若甌分。", "野人不管興亡事，空憑危欄到日曛。"]'),
('2f6f9bae-7e03-44cf-a1b3-3c1de3c78e20','泊禹祠','潘閬','宋','宋诗','song-poetry','','[]','禹廟高高萬木齊，蟾蜍影裏月光低。',32,'全唐诗/poet.song.2000.json','["禹廟高高萬木齊，蟾蜍影裏月光低。", "山中不慣聞寒漏，一夜猿驚與鳥啼。"]'),
('4a06f53a-cde7-4469-adbf-a168c61c2f49','癸未歲秋七月禱禹廟','潘閬','宋','宋诗','song-poetry','','[]','萬古稽山下，森森大禹祠。',48,'全唐诗/poet.song.2000.json','["萬古稽山下，森森大禹祠。", "幽人來暗禱，靈魄望潛知。", "帝慮河頻决，民憂業旋移。", "自慙無異策，載拜淚雙垂。"]'),
('28572d11-0751-444c-a978-3fe3e47e33a4','寄會稽仲休山人','潘閬','宋','宋诗','song-poetry','','[]','近携琴鶴遊東越，曾接談諧氣味深。',64,'全唐诗/poet.song.2000.json','["近携琴鶴遊東越，曾接談諧氣味深。", "佛意已知師達了，儒書却爲俗披尋。", "稽山有雪寒凝骨，鑑水無風冷徹心。", "別後相思向誰說，祗應霜鬢暗相侵。"]'),
('b32f2a8f-b766-436f-a9da-8eccfbe19597','題蕭山祇園寺門','潘閬','宋','宋诗','song-poetry','','[]','門掩多年生綠苔，想師心地似寒灰。',32,'全唐诗/poet.song.2000.json','["門掩多年生綠苔，想師心地似寒灰。", "勞心擾擾休來此，我是閒人尚不開。"]'),
('497d63d6-a4b1-4e53-b3ee-e0777b136907','送崇教大師惠思歸山','潘閬','宋','宋诗','song-poetry','','[]','受知聖睠與誰同，師號封題寄梵宮。',64,'全唐诗/poet.song.2000.json','["受知聖睠與誰同，師號封題寄梵宮。", "爲謝國恩來闕下，又承天澤去山中。", "禪餘靜對江亭月，吟苦凉生海樹風。", "若到赤城逢羽客，但言孤鶴在金籠。"]'),
('dd52fc91-055f-4ace-bce2-8a5733709df3','游當塗','潘閬','宋','宋诗','song-poetry','','[]','扁舟不復見袁宏，故壘猶連謝尚城。',48,'全唐诗/poet.song.2000.json','["扁舟不復見袁宏，故壘猶連謝尚城。", "騎鯨仙子千年恨，化石佳人萬古情。", "牛渚磯前浪如屋，區區名利與生輕。"]'),
('2789699f-0900-42fb-a545-ede875e4150b','夏','潘閬','宋','宋诗','song-poetry','','[]','野花成子落，江燕引雛飛。',24,'全唐诗/poet.song.2000.json','["野花成子落，江燕引雛飛。", "暗草薰苔徑，晴楊拂石磯。"]'),
('477196df-3237-4265-95fc-8c59fe1b1f02','落花','潘閬','宋','宋诗','song-poetry','','[]','花殘雨又風，飄紫復飄紅。',48,'全唐诗/poet.song.2000.json','["花殘雨又風，飄紫復飄紅。", "不到三春盡，都經數夜空。", "繞闌仍聚散，逐水尚西東。", "可惜多情蝶，徘徊晚照中。"]'),
('dcece281-eb7a-4368-8985-6686fe4a1821','遊龍虎山贈天師  其一','潘閬','宋','宋诗','song-poetry','','[]','遠挹高風自漢廷，老松猶带昔年青。',64,'全唐诗/poet.song.2000.json','["遠挹高風自漢廷，老松猶带昔年青。", "留侯高卧衣冠冷，鼻祖重來印劍靈。", "鶴和猿吟清徹底，龍蟠虎踞翠爲屏。", "真人一笑梅花發，三十六天春不扃。"]'),
('f0e6091d-a592-4099-b7cd-c9e800213426','遊龍虎山贈天師  其二','潘閬','宋','宋诗','song-poetry','','[]','鐵鞋踏破幾山行，惟此山行越樣清。',64,'全唐诗/poet.song.2000.json','["鐵鞋踏破幾山行，惟此山行越樣清。", "顧我塵中一簪紱，任他世上幾公卿。", "分安淡泊全真性，身厭輕肥已半生。", "漢鼎餘丹今在否，願須匕粒守三彭。"]'),
('80381b01-8201-4b05-ba66-31ec03a2a4f9','句  其一','潘閬','宋','宋诗','song-poetry','','[]','何須三叫絕，已恨一聲多。',12,'全唐诗/poet.song.2000.json','["何須三叫絕，已恨一聲多。"]'),
('305b84a0-468d-4843-8d79-b96be01994ad','句  其二','潘閬','宋','宋诗','song-poetry','','[]','莫嗟黑髮從頭白，終見黄河到底清。',16,'全唐诗/poet.song.2000.json','["莫嗟黑髮從頭白，終見黄河到底清。"]'),
('be6a43d5-6c28-4535-8841-0f2d2ab35cba','句  其三','潘閬','宋','宋诗','song-poetry','','[]','到底不能成一曲。',8,'全唐诗/poet.song.2000.json','["到底不能成一曲。"]'),
('042618d6-ede7-44c0-a65c-3443b839e492','句  其四','潘閬','宋','宋诗','song-poetry','','[]','土床安睡穩，紙被轉身鳴。',12,'全唐诗/poet.song.2000.json','["土床安睡穩，紙被轉身鳴。"]'),
('14d58678-27d3-4e30-9b0b-de57da67ad15','句  其五','潘閬','宋','宋诗','song-poetry','','[]','滁上相逢俱禁煙。',8,'全唐诗/poet.song.2000.json','["滁上相逢俱禁煙。"]'),
('d09f8e6f-539e-4cbf-a03b-792204d6aeb0','句  其六','潘閬','宋','宋诗','song-poetry','','[]','窺魚白鳥明殘照，抱石幽雲點半山。',16,'全唐诗/poet.song.2000.json','["窺魚白鳥明殘照，抱石幽雲點半山。"]'),
('c06d1f26-747e-4a35-8c5e-3846ae0bf478','句  其七','潘閬','宋','宋诗','song-poetry','','[]','歸來遍檢登科記，未見連年放弟兄。',16,'全唐诗/poet.song.2000.json','["歸來遍檢登科記，未見連年放弟兄。"]'),
('4b4db052-806c-43a6-9307-487ca4bd5d63','句  其八','潘閬','宋','宋诗','song-poetry','','[]','峽口聞猿夜。',6,'全唐诗/poet.song.2000.json','["峽口聞猿夜。"]'),
('fa302b38-a2fc-478f-b00f-5e3fa2239705','句  其九','潘閬','宋','宋诗','song-poetry','','[]','出秋霜，價錢可，贏得撥灰兼弄火，暢殺我。',20,'全唐诗/poet.song.2000.json','["出秋霜，價錢可，贏得撥灰兼弄火，暢殺我。"]'),
('5e3e3079-d6e9-4d09-afa6-4664c4cbf169','句  其一○','潘閬','宋','宋诗','song-poetry','','[]','散拽禪師來踘蹴，亂拖游女上秋千。',16,'全唐诗/poet.song.2000.json','["散拽禪師來踘蹴，亂拖游女上秋千。"]'),
('0fc9ba72-370c-4231-91dc-23b3ba555439','目存  其一','潘閬','宋','宋诗','song-poetry','','[]','詩題：古意首句：妾有羅衣裳。',14,'全唐诗/poet.song.2000.json','["詩題：古意首句：妾有羅衣裳。"]'),
('3becda0b-cf29-43ca-b4e7-34a30c201aeb','目存  其二','潘閬','宋','宋诗','song-poetry','','[]','詩題：渭上秋夕閒望首句：秋色滿秦川。',18,'全唐诗/poet.song.2000.json','["詩題：渭上秋夕閒望首句：秋色滿秦川。"]'),
('7559eb03-7fc5-4adf-9130-849952b152c5','清風十韻','張秉','宋','宋诗','song-poetry','','[]','何處來蘋末，蕭騷盡四鄰。',120,'全唐诗/poet.song.2000.json','["何處來蘋末，蕭騷盡四鄰。", "金莖吹曉露，玉宇動輕塵。", "易水離歌闋，齊紈怨思新。", "泛蘭迷舊澤，落帽會佳辰。", "籬菊飄香遠，庭桐墜葉頻。", "帆開五湖客，槎去九霄人。", "曲沼鋪紋簟，平蕪偃綠茵。", "鴻飛資羽翮，鷹擊助精神。", "仙馭歸堪待，琴松韻更真。", "披襟同楚樹，千古自相親。"]'),
('8d35ae30-2bbc-4bd3-8b98-5658d54a0fc1','戊申年七夕五絕  其一','張秉','宋','宋诗','song-poetry','','[]','斜漢西傾桂魄新，停梭今夕度天津。',32,'全唐诗/poet.song.2000.json','["斜漢西傾桂魄新，停梭今夕度天津。", "世間縱有支機石，誰是成都賣卜人。"]'),
('063e42b2-6341-4b96-a77d-ef09edbc1489','戊申年七夕五絕  其二','張秉','宋','宋诗','song-poetry','','[]','紅蕖爛熳碧池香，羅綺三千侍漢皇。',32,'全唐诗/poet.song.2000.json','["紅蕖爛熳碧池香，羅綺三千侍漢皇。", "阿母暫來成底事，茂陵宮桂已蒼蒼。"]'),
('5bc37238-08a5-48c1-bd91-b67fc6875337','戊申年七夕五絕  其三','張秉','宋','宋诗','song-poetry','','[]','香階寶砌靜無塵，遥指星河再拜人。',32,'全唐诗/poet.song.2000.json','["香階寶砌靜無塵，遥指星河再拜人。", "若把離情今夕說，世間生死最傷神。"]'),
('3f575554-3726-4ee8-bb32-b27d01a77388','戊申年七夕五絕  其四','張秉','宋','宋诗','song-poetry','','[]','北斗城高禁漏多，漢家宮殿奏笙歌。',32,'全唐诗/poet.song.2000.json','["北斗城高禁漏多，漢家宮殿奏笙歌。", "漫教青鳥傳消息，金簡長生得也麽。"]'),
('9766aa0f-96af-4c26-b73f-53679f19cbb5','戊申年七夕五絕  其五','張秉','宋','宋诗','song-poetry','','[]','珠箔風輕月似鈎，還看錦繡結高樓。',32,'全唐诗/poet.song.2000.json','["珠箔風輕月似鈎，還看錦繡結高樓。", "堪傷乞巧年年事，未識君王已白頭。"]'),
('9fe184ea-47c4-4d45-8576-8b9e599e13a3','鄭州聯句','張秉','宋','宋诗','song-poetry','','[]','函關秋霽雁初迴，六里商於曉色開。',32,'全唐诗/poet.song.2000.json','["函關秋霽雁初迴，六里商於曉色開。", "四皓有靈應笑我，謫官方始入山來。"]'),
('88828215-8862-46b8-a598-d23fa1d1440b','句','張秉','宋','宋诗','song-poetry','','[]','疊石自然成鴈塔，貯泓依舊作龍塘。',16,'全唐诗/poet.song.2000.json','["疊石自然成鴈塔，貯泓依舊作龍塘。"]'),
('ca496da5-b9ae-4bcb-96b7-814f9270232d','禁林讌會之什','韓丕','宋','宋诗','song-poetry','','[]','鼇宮明麗倚春寒，讌會羣仙喜縱觀。',96,'全唐诗/poet.song.2000.json','["鼇宮明麗倚春寒，讌會羣仙喜縱觀。", "聖作照臨新日月，御書飛動集龍鸞。", "綺談雅似聞天樂，瓊夜香勝飲露盤。", "坐久杳同玄圃外，吟餘飄若碧雲端。", "演綸視草微才怯，□□□□霈澤寬。", "因想前賢倍知幸，多云遭值太平難。"]'),
('7f541392-8966-4c64-8f65-c7dd2b07d2c8','寄岳陽劉從事','韓丕','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','秋來憶故人，寓目臨大野。',48,'全唐诗/poet.song.2000.json','["秋來憶故人，寓目臨大野。", "遠近聞清商，依稀奏豳雅。", "經霜樹半紅，無風葉自下。", "一片洞庭心，聊憑塞鴻寫。"]'),
('e97ddc7b-0bce-4849-8bd1-da49bdc8bd0d','菊','韓丕','宋','宋诗','song-poetry','','[]','造化功夫異異端，自緣開晚少人看。',32,'全唐诗/poet.song.2000.json','["造化功夫異異端，自緣開晚少人看。", "若教總似陶潛眼，肯向芳春賞牡丹。"]'),
('80a613ae-2b88-45c2-9eea-feeb548fa165','代書寄集賢李昌武學士','錢熙','宋','宋诗','song-poetry','','[]','大庾山橫贛水濱，南飛一雁久離群。',32,'全唐诗/poet.song.2000.json','["大庾山橫贛水濱，南飛一雁久離群。", "蓮花幕裏誰知我，竹葉樽前獨憶君。"]'),
('387fa242-8c0e-496c-884c-d79dee51df3c','雞冠花','錢熙','宋','宋诗','song-poetry','','[]','亭亭高出竹籬間，露滴風吹血染乾。',32,'全唐诗/poet.song.2000.json','["亭亭高出竹籬間，露滴風吹血染乾。", "學得京城梳洗樣，舊羅包却綠雲鬟。"]'),
('9a586890-87ea-413c-9b49-0168faa20419','九日溪偶成','錢熙','宋','宋诗','song-poetry','','[]','漁家深處住，鷗鷺泊柴扉。',48,'全唐诗/poet.song.2000.json','["漁家深處住，鷗鷺泊柴扉。", "雨過山迷徑，潮來風滿衣。", "岸幽分遠景，波冷漾清暉。", "却憶曾遊賞，嚴陵有舊磯。"]'),
('9ab12b5a-da10-4f01-a08a-1447102b72d1','清源山','錢熙','宋','宋诗','song-poetry','','[]','巍峨堆壓郡城陰，秀出天涯幾萬尋。',32,'全唐诗/poet.song.2000.json','["巍峨堆壓郡城陰，秀出天涯幾萬尋。", "翠影倒時吞半郭，嵐光凝處滴疏林。"]'),
('42878063-70bb-4295-9cc6-46510c2029c4','龍首山','錢熙','宋','宋诗','song-poetry','','[]','殘年仍置閏，五日恰逢春。',48,'全唐诗/poet.song.2000.json','["殘年仍置閏，五日恰逢春。", "携酒客獨嘗，敲門僧不嗔。", "雙松如拱立，萬井自橫陳。", "精舍故盤礴，元規塵上人。"]'),
('1adacf68-bead-4b1f-ac2b-8f29013d3e3d','句','錢熙','宋','宋诗','song-poetry','','[]','鶴歸已改新城郭，牛卧重尋舊墓田。',16,'全唐诗/poet.song.2000.json','["鶴歸已改新城郭，牛卧重尋舊墓田。"]'),
('47ea78a8-dddd-4fd9-bc9a-3dac738cc7ed','寒食訪僧','鄭文寶','宋','宋诗','song-poetry','','[]','客舍愁經百五春，雨餘溪寺綠無塵。',64,'全唐诗/poet.song.2000.json','["客舍愁經百五春，雨餘溪寺綠無塵。", "金花開處鞦韆鼓，粉頰誰家鬭草人。", "水上碧桃流片段，梁間新燕語逡巡。", "高僧不飲客携酒，來勸先朝放逐臣。"]'),
('edf4bfb0-5c08-4256-86d0-d5086918f0ed','郢城新亭','鄭文寶','宋','宋诗','song-poetry','','[]','每到新亭即厭歸，野香經雨長松圍。',64,'全唐诗/poet.song.2000.json','["每到新亭即厭歸，野香經雨長松圍。", "四簷山色消繁暑，一局棋聲下翠微。", "冰片角巾簪澗月，錦文拳石砌苔磯。", "近來學得籠中鶻，迴避流鶑笑不飛。"]'),
('2b5cae14-2e0b-4bee-8367-d2f66aadb608','寒食日經秀上人房','鄭文寶','宋','宋诗','song-poetry','','[]','花時懶看花，來訪野僧家。',24,'全唐诗/poet.song.2000.json','["花時懶看花，來訪野僧家。", "勞師擊新火，勸我雨前茶。"]'),
('5993fa70-6236-45b0-9eb7-45b7592bf6a7','過信陽軍白雪驛','鄭文寶','宋','宋诗','song-poetry','','[]','得罪先朝出粉圍，五原功業有誰知。',32,'全唐诗/poet.song.2000.json','["得罪先朝出粉圍，五原功業有誰知。", "年餘放逐無人識，白雪關頭一望時。"]'),
('b9981aab-873d-4ad7-8b0b-5be8756fdd66','送曹緯劉鼎二秀才','鄭文寶','宋','宋诗','song-poetry','','[]','旦夕春風老，離心共黯然。',48,'全唐诗/poet.song.2000.json','["旦夕春風老，離心共黯然。", "小舟聞笛夜，微雨養花天。", "手筆人皆有，曹劉世所賢。", "郴侯重才子，從此看鶑遷。"]'),
('deebae54-ed1e-49b8-add2-692b55d76e1a','送枝江秦長官罷秩','鄭文寶','宋','宋诗','song-poetry','','[]','衆論才名外，親人似古人。',48,'全唐诗/poet.song.2000.json','["衆論才名外，親人似古人。", "官嫌容易達，家愛等閑貧。", "解印詩權在，移風澤國春。", "政聲交不得，慚見數鄉民。"]'),
('f8f1d665-bacc-41c0-8743-7acf6141a5fc','溫泉','鄭文寶','宋','宋诗','song-poetry','','[]','潺湲如燎嶺雲陰，玉石魚龍換古今。',64,'全唐诗/poet.song.2000.json','["潺湲如燎嶺雲陰，玉石魚龍換古今。", "只見開元無事久，不知貞觀用功深。", "籠無解語衣無雪，堆有黄沙粟有金。", "惆悵群邪負恩澤，始知夷甫少經心。"]'),
('ba77125a-dbcd-43af-84e5-86f4ebfc6ef6','讀江總傳','鄭文寶','宋','宋诗','song-poetry','','[]','行人慵過景陽宮，宮畔離離禾黍風。',64,'全唐诗/poet.song.2000.json','["行人慵過景陽宮，宮畔離離禾黍風。", "庭玉有花空怨白，井蓮無步莫愁紅。", "吟詩功業才雖大，亡國君臣道最同。", "爭忍暮年歸故里，綸竿迴避釣魚翁。"]'),
('d4510c9a-5f45-479f-a78a-50ac3f43eb65','爽約','鄭文寶','宋','宋诗','song-poetry','','[]','吟遶虛廊更向闌，繡窗燈影背欄干。',32,'全唐诗/poet.song.2000.json','["吟遶虛廊更向闌，繡窗燈影背欄干。", "燕棲鶑宿無人語，一夜蕭蕭細雨寒。"]'),
('94c35a5a-dbff-4fc8-94c3-03885a3b8545','題松滋東禪院','鄭文寶','宋','宋诗','song-poetry','','[]','百花深處小危樓，千步蒼苔到葉舟。',32,'全唐诗/poet.song.2000.json','["百花深處小危樓，千步蒼苔到葉舟。", "一夜楚江寒食雨，離人白盡未歸頭。"]'),
('57392998-5668-4c8f-a13f-2605d05a5b88','雙筍石','鄭文寶','宋','宋诗','song-poetry','','[]','流水驚前事，清風似昔時。',24,'全唐诗/poet.song.2000.json','["流水驚前事，清風似昔時。", "重吟金谷詠，如見峴山碑。"]'),
('09dc766e-76cd-4023-9c6a-3ca61a5832c8','香木槽','鄭文寶','宋','宋诗','song-poetry','','[]','沉檀香植在天涯，賤等荆衡水面槎。',32,'全唐诗/poet.song.2000.json','["沉檀香植在天涯，賤等荆衡水面槎。", "何必爲槽飼雞犬，不如煨燼向豪家。"]'),
('3eac9b17-0108-4ab3-ab1a-7f5e85474c6b','題緱氏山王子晉祠','鄭文寶','宋','宋诗','song-poetry','','[]','秋陰漠漠秋雲輕，緱氏山頭月正明。',32,'全唐诗/poet.song.2000.json','["秋陰漠漠秋雲輕，緱氏山頭月正明。", "帝子西飛仙馭遠，不知何處作吹笙。"]'),
('c81053f7-c474-481e-84ab-7f1e8dfcd82d','絕句三首  其一','鄭文寶','宋','宋诗','song-poetry','','["\u53cb\u60c5", "\u67f3\u6811", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u9001\u522b"]','亭亭畫舸繫寒潭，直到行人酒半酣。',32,'全唐诗/poet.song.2000.json','["亭亭畫舸繫寒潭，直到行人酒半酣。", "不管煙波與風雨，載將離恨過江南。"]'),
('57b0c14c-414f-4bf5-a8c0-be77d40113b7','絕句三首  其二','鄭文寶','宋','宋诗','song-poetry','','[]','一夜西風旅雁秋，背身調鏃索征裘。',32,'全唐诗/poet.song.2000.json','["一夜西風旅雁秋，背身調鏃索征裘。", "關山落盡黄榆葉，駐馬誰家唱石州。"]'),
('06ce69ca-0fd9-4703-b0ce-533f930a413f','絕句三首  其三','鄭文寶','宋','宋诗','song-poetry','','[]','江雲薄薄日斜暉，江館蕭條獨掩扉。',32,'全唐诗/poet.song.2000.json','["江雲薄薄日斜暉，江館蕭條獨掩扉。", "梁燕不在人事改，雨中猶作一雙飛。"]'),
('0f84de89-eb81-4ca8-9e06-4d013910bccb','句  其一','鄭文寶','宋','宋诗','song-poetry','','[]','水暖鳬醫行哺子，溪深桃李卧開花。',16,'全唐诗/poet.song.2000.json','["水暖鳬醫行哺子，溪深桃李卧開花。"]'),
('eb082ca1-9758-4bc1-8d75-895be663d111','句  其二','鄭文寶','宋','宋诗','song-poetry','','[]','百草千花路，華風細雨天。',12,'全唐诗/poet.song.2000.json','["百草千花路，華風細雨天。"]'),
('6233ccad-72da-433d-b6e1-5053c0e6470c','句  其三','鄭文寶','宋','宋诗','song-poetry','','[]','過關已躍樗蒲馬，誤喘猶驚顧兔屏。',16,'全唐诗/poet.song.2000.json','["過關已躍樗蒲馬，誤喘猶驚顧兔屏。"]'),
('dab71b3a-8605-4b6c-9f66-5cd50b56c219','句  其四','鄭文寶','宋','宋诗','song-poetry','','[]','星沉會節歌鐘早，天半上陽煙樹微。',16,'全唐诗/poet.song.2000.json','["星沉會節歌鐘早，天半上陽煙樹微。"]'),
('5dfb83ab-552e-46c7-8504-6c22a7b3cee6','句  其五','鄭文寶','宋','宋诗','song-poetry','','[]','越絕曉殘蝴蝶夢，單于秋引畫龍聲。',16,'全唐诗/poet.song.2000.json','["越絕曉殘蝴蝶夢，單于秋引畫龍聲。"]'),
('d4f0c925-5ca1-44f0-97db-4c2a84135260','句  其六','鄭文寶','宋','宋诗','song-poetry','','[]','杜曲花光濃似酒，灞陵春色老於人。',16,'全唐诗/poet.song.2000.json','["杜曲花光濃似酒，灞陵春色老於人。"]'),
('a19298bc-0148-48ad-b109-4bdd47514d0f','句  其七','鄭文寶','宋','宋诗','song-poetry','','[]','滿帆西日催行客，一夜東風落楚梅。',16,'全唐诗/poet.song.2000.json','["滿帆西日催行客，一夜東風落楚梅。"]'),
('fd3b7f69-3ff4-44b6-b4fb-bb95a5f84bbb','句  其八','鄭文寶','宋','宋诗','song-poetry','','[]','失意慣中遷客酒，多年不見侍臣花。',16,'全唐诗/poet.song.2000.json','["失意慣中遷客酒，多年不見侍臣花。"]'),
('3b0b341d-7b3d-47bd-b5d1-6d776dc92677','句  其九','鄭文寶','宋','宋诗','song-poetry','','[]','舊井霜封仙界橘，雙溪晴落海邊鷗。',16,'全唐诗/poet.song.2000.json','["舊井霜封仙界橘，雙溪晴落海邊鷗。"]'),
('985e5421-dfa2-46e3-a37f-c207ba65db84','句  其一○','鄭文寶','宋','宋诗','song-poetry','','[]','人辭碧落春風晚，花老朱陵古渡頭。',16,'全唐诗/poet.song.2000.json','["人辭碧落春風晚，花老朱陵古渡頭。"]'),
('61fe0eac-cf6c-44a1-abbd-2929c18bc323','句  其一一','鄭文寶','宋','宋诗','song-poetry','','[]','承露氣清駒送日，觚稜人靜鳥呼風。',16,'全唐诗/poet.song.2000.json','["承露氣清駒送日，觚稜人靜鳥呼風。"]'),
('2679a4c5-df2b-4705-ba71-9d58833feaf8','句  其一二','鄭文寶','宋','宋诗','song-poetry','','[]','鬢間相似雪，峰外寂寒煙。',12,'全唐诗/poet.song.2000.json','["鬢間相似雪，峰外寂寒煙。"]'),
('1711857c-ab94-485a-8a6f-f4d588476a27','句  其一三','鄭文寶','宋','宋诗','song-poetry','','[]','眼界入去中。',6,'全唐诗/poet.song.2000.json','["眼界入去中。"]'),
('322529aa-926d-436f-9ea2-f205ebdadebd','句  其一四','鄭文寶','宋','宋诗','song-poetry','','[]','久欠遊山債。',6,'全唐诗/poet.song.2000.json','["久欠遊山債。"]'),
('30c1e308-d57a-434e-85ba-64d92bac4f8f','句  其一五','鄭文寶','宋','宋诗','song-poetry','','[]','偷分暇日工。',6,'全唐诗/poet.song.2000.json','["偷分暇日工。"]'),
('69b073f6-c87d-4605-85d5-f759f65f8e16','句  其一六','鄭文寶','宋','宋诗','song-poetry','','[]','登臨雖未立。',6,'全唐诗/poet.song.2000.json','["登臨雖未立。"]'),
('beaf3ae2-b956-437d-969d-af9937cda0e8','思古堂','陳世卿','宋','宋诗','song-poetry','','[]','思古堂前酒一尊，共談時事出孤村。',32,'全唐诗/poet.song.2000.json','["思古堂前酒一尊，共談時事出孤村。", "臨期上馬無他囑，多買詩書教子孫。"]'),
('5c88cfa8-25a2-4362-bac2-738b58c64300','翠竹峰','陳世卿','宋','宋诗','song-poetry','','[]','翠竹峰前是我家，歸來重整舊生涯。',32,'全唐诗/poet.song.2000.json','["翠竹峰前是我家，歸來重整舊生涯。", "煙霞尚有留人意，爭奈門前駟馬車。"]'),
('8fbe1d28-6f30-4f2d-8a58-2170468ff189','淘金山','陳世卿','宋','宋诗','song-poetry','','[]','未覆一簣土，便作千仞觀。',24,'全唐诗/poet.song.2000.json','["未覆一簣土，便作千仞觀。", "一自登巉巖，培塿視群山。"]'),
('fcacf340-70d7-4c21-9a55-a960bc3e6c0a','遊黄楊巖','陳世卿','宋','宋诗','song-poetry','','[]','朔風夜號空，于隅幾枝木。',168,'全唐诗/poet.song.2000.json','["朔風夜號空，于隅幾枝木。", "深山自春色，芳草不凋綠。", "朋來得進遊，招提藏翠麓。", "新酒赤如丹，竹萌肥勝肉。", "一醉出門去，缺月掛修竹。", "歸路沙溪淺，危橋濺寒玉。", "夜過渭濱居，門庭應不俗。", "對座寂無言，泉聲如擊築。", "宗明更可人，相邀勤秉燭。", "開緘得捷音，豺狼俱面北。", "迴櫂今可矣，賞心嗟未足。", "西去有奇巖，祥雲覆華屋。", "箕踞列千人，未充空洞腹。", "更約林宗俱，來伴白雲宿。"]'),
('8f1b607b-2297-4691-ad19-11296c3ced48','高巖立春日','王世則','宋','宋诗','song-poetry','','[]','二年白玉堂，揮翰供帖子。',96,'全唐诗/poet.song.2000.json','["二年白玉堂，揮翰供帖子。", "風生起草臺，墨照澄心紙。", "三年文昌省，拜賜近天咫。", "紅蓼肦御盤，金幡裊宮蕊。", "晚爲日南客，環堵隠烏几。", "朝來聞擊鼓，土牛出墟市。", "幽懷不自閒，欲逐春事起。", "安是五畝園，種蔬引江水。"]'),
('44ddff73-4d28-44f9-b454-e4279ac2172c','遊真祺觀','邵奕','宋','宋诗','song-poetry','','[]','肩輿迢遞訪遊仙，自是山中別有天。',64,'全唐诗/poet.song.2000.json','["肩輿迢遞訪遊仙，自是山中別有天。", "松影參差籠玉殿，鶴聲嘹喨下芝田。", "青蒼巘色臨門外，斷續泉流遶檻前。", "便可相從解簪紱，時清難戀薜蘿烟。"]'),
('4bedba56-c358-46ab-a6b0-e38797a6bfc5','句  其一','馮伉','宋','宋诗','song-poetry','','[]','算來真是風騷將，李杜壇邊好策勳。',16,'全唐诗/poet.song.2000.json','["算來真是風騷將，李杜壇邊好策勳。"]'),
('1f3a9ea2-bfc6-44a9-9370-40e9912a274b','句  其二','馮伉','宋','宋诗','song-poetry','','[]','傳語東歸王副使，也須別却海棠回。',16,'全唐诗/poet.song.2000.json','["傳語東歸王副使，也須別却海棠回。"]'),
('cc4ad864-57b7-4ae9-a3df-9e425c2721fb','登第遺鄉人','李巽','宋','宋诗','song-poetry','','[]','當年蹤跡困泥塵，不意乘時亦化鱗。',32,'全唐诗/poet.song.2000.json','["當年蹤跡困泥塵，不意乘時亦化鱗。", "爲報鄉閭親戚道，如今席帽已離身。"]'),
('33a7b57f-79eb-435a-abd3-99ac200abdc6','題義門胡氏華林書院','李巽','宋','宋诗','song-poetry','','[]','孝義門風累世修，帝恩旌表耀南州。',64,'全唐诗/poet.song.2000.json','["孝義門風累世修，帝恩旌表耀南州。", "藏書不特延多士，貢幣仍聞亞列侯。", "高閣聲寒慈竹雨，小池香老瑞蓮秋。", "人來辱示朝賢什，吟咏渾消萬斛愁。"]'),
('68df7197-90a2-4445-b2f7-20611838756a','題鐵作池上亭','歐陽程','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','鑿開幽境泛流萍，迴合波閒小洞庭。',64,'全唐诗/poet.song.2000.json','["鑿開幽境泛流萍，迴合波閒小洞庭。", "寒影倒吞凌漢樹，冷光高浴半天星。", "魚翻綿鬣波紋皺，鷺洗霜翎水氣腥。", "昨夜蛟龍忽飛去，滿天風雨震雷霆。"]'),
('d05beb89-9c69-4ebc-a611-e9a57680db72','句','夏侯嘉正','宋','宋诗','song-poetry','','[]','兩制誠堪美，青雲侍玉輿。',12,'全唐诗/poet.song.2000.json','["兩制誠堪美，青雲侍玉輿。"]'),
('6d504e03-92bf-4f90-b18e-51e067a2d4f6','太虛觀','周絳','宋','宋诗','song-poetry','','[]','骨化黄金鶴化胎，仙翁輕舉出塵埃。',64,'全唐诗/poet.song.2000.json','["骨化黄金鶴化胎，仙翁輕舉出塵埃。", "石幢雲鎖水常在，玉馬星馳煉未回。", "綠草晚煙梅雨發，失藤餘萼麥風開。", "丹泉長活芙蓉死，會買張山卜築來。"]'),
('3bc37652-ef30-4347-b934-b7b4bba3fc68','題澹山巖','蔣緯','宋','宋诗','song-poetry','','[]','風生崖木響，靄散洞門寬。',48,'全唐诗/poet.song.2000.json','["風生崖木響，靄散洞門寬。", "幽徑盤危入，青天一面看。", "三冬僧定煖，五月客游寒。", "縱有通神筆，亦應圖出難。"]'),
('22e82e0c-1b78-4e5f-b275-c119900ff1cc','答陳摶','葛守忠','宋','宋诗','song-poetry','','["\u534e\u5c71"]','華嶽三峰客，幽居不記年。',48,'全唐诗/poet.song.2000.json','["華嶽三峰客，幽居不記年。", "煙霞爲活計，雲水作家緣。", "種藥茅庭畔，栽松澗壑邊。", "暫離仙洞去，可應帝王宣。"]'),
('5dd87de3-ddfb-4484-aa84-41a5bc455893','送人南歸','王操','宋','宋诗','song-poetry','','[]','相送當摇落，孤舟泛渺瀰。',48,'全唐诗/poet.song.2000.json','["相送當摇落，孤舟泛渺瀰。", "去帆看已遠，臨水立多時。", "別浦寒鴻下，空山夜鶴移。", "他年重會面，冷鬢共成絲。"]'),
('cdc91486-5201-4168-84ae-d9f22c4e104c','喜故人至','王操','宋','宋诗','song-poetry','','[]','地僻無賓侶，柴門畫始開。',48,'全唐诗/poet.song.2000.json','["地僻無賓侶，柴門畫始開。", "谿山寒葉落，江國故人來。", "話舊驚霜鬢，論詩滯酒杯。", "相留喜同宿，不寐曙光回。"]'),
('26a8579c-d1b9-4e30-890b-9914f6c904c2','上李昉相公  其一','王操','宋','宋诗','song-poetry','','[]','弱冠登龍入粉闈，少年清貴古來稀。',64,'全唐诗/poet.song.2000.json','["弱冠登龍入粉闈，少年清貴古來稀。", "袖中詔草朝天去，頭上宮花侍宴歸。", "卓筆玉堂寒漏迥，捲簾池館水禽飛。", "三台位近猶多遜，閒聽秋霖憶翠微。"]'),
('b86c1258-05c1-4723-861a-7655410e824c','上李昉相公  其二','王操','宋','宋诗','song-poetry','','[]','朝苑優游數十春，文章敵手更無人。',64,'全唐诗/poet.song.2000.json','["朝苑優游數十春，文章敵手更無人。", "對敭旒冕如僚友，下直門闌似隠淪。", "倚檻白雪供醉望，搘筇黄葉落吟身。", "年來得意知難絕，大半門生作侍臣。"]'),
('b6d8340b-b29a-455d-b5fa-4f308d3d6572','洛陽春','王操','宋','宋诗','song-poetry','','[]','帝里山河景莫裁，就中春色似先來。',64,'全唐诗/poet.song.2000.json','["帝里山河景莫裁，就中春色似先來。", "暖融殘雪當時盡，花得東風一夜開。", "艷日綺羅香上苑，沸天簫鼓動瑶臺。", "芳心只恐煙花暮，閒立高樓望幾回。"]'),
('506cbecd-a0de-4675-97de-285ed7e39895','村家','王操','宋','宋诗','song-poetry','','[]','野景村家好，柴籬夾樹身。',48,'全唐诗/poet.song.2000.json','["野景村家好，柴籬夾樹身。", "牧童眠向日，山犬吠隨人。", "地僻鄉音別，年豐酒昧醇。", "風光吟有興，桑麥暖逢春。"]'),
('d8144aab-74c7-4f76-8291-fe5542e8f32b','塞上','王操','宋','宋诗','song-poetry','','[]','無定河邊路，風高雪灑春。',48,'全唐诗/poet.song.2000.json','["無定河邊路，風高雪灑春。", "沙平寬似海，鵰遠立如人。", "絕域居中土，多年息戰塵。", "邊城吹暮角，久客自悲辛。"]'),
('36a1d250-06a3-4b23-82b9-92814d3179b1','遊邊上','王操','宋','宋诗','song-poetry','','[]','佩劍游邊地，悲風捲敗莎。',48,'全唐诗/poet.song.2000.json','["佩劍游邊地，悲風捲敗莎。", "鵰饑窺壞塚，馬渴嗅冰河。", "塞闊人煙絕，春深霰雪多。", "蕃戎如畫看，散騎立高坡。"]'),
('6285e2ee-65dc-4eaf-8915-8eb1d9dfeb65','并州道中','王操','宋','宋诗','song-poetry','','[]','從軍無住計，近臘塞門行。',48,'全唐诗/poet.song.2000.json','["從軍無住計，近臘塞門行。", "風劈面疑裂，凍粘髭有聲。", "太陽過午暗，暮雪照入明。", "馬上聞吹角，依依認漢城。"]'),
('93d2cd76-d8c8-4083-9243-f3a09f24ea58','贈劉將軍','王操','宋','宋诗','song-poetry','','[]','三十懸鈎事聖朝，功名常愛霍嫖姚。',64,'全唐诗/poet.song.2000.json','["三十懸鈎事聖朝，功名常愛霍嫖姚。", "錦衣香重花垂足，玉带光寒雪遶腰。", "秣馬暖思秦地草，弦弓秋憶雁門鵰。", "清時閒却英雄興，醉聽笙歌擲酒瓢。"]'),
('87ffdf5b-2db9-45a2-b5bd-5c05cca93ce5','黄葵','王操','宋','宋诗','song-poetry','','[]','昔年南國看黄葵，雲鬢金釵向後垂。',32,'全唐诗/poet.song.2000.json','["昔年南國看黄葵，雲鬢金釵向後垂。", "今日林容籬落下，秋風寂寞兩三枝。"]'),
('273b879a-6863-4a57-bf6a-94dd87c3d8c7','題水心寺壁','王操','宋','宋诗','song-poetry','','[]','分飛南渡春風晚，却返家林舊業空。',32,'全唐诗/poet.song.2000.json','["分飛南渡春風晚，却返家林舊業空。", "無限離情似楊柳，萬條垂向楚江東。"]'),
('9c38e456-67d5-4f1a-923d-c461e8b7e9ce','句  其一','王操','宋','宋诗','song-poetry','','[]','馬摇金勒嘶村墅，人搶花毬落野田。',16,'全唐诗/poet.song.2000.json','["馬摇金勒嘶村墅，人搶花毬落野田。"]'),
('d3c73bfa-13e4-4bd0-a59d-862f87fec76c','句  其二','王操','宋','宋诗','song-poetry','','[]','彩牋分捲碧雲薄，臘燭對燒紅淚乾。',16,'全唐诗/poet.song.2000.json','["彩牋分捲碧雲薄，臘燭對燒紅淚乾。"]'),
('7e4c6dfd-9bb8-4215-8d73-5842c65d813f','句  其三','王操','宋','宋诗','song-poetry','','[]','堂親垂白日，稚子欲行時。',12,'全唐诗/poet.song.2000.json','["堂親垂白日，稚子欲行時。"]'),
('698edab3-8e07-4d9e-8aa2-3bfff2b5aa1c','偈','釋知幻','宋','宋诗','song-poetry','','[]','當初不肯住長安，現相須歸泗水間。',32,'全唐诗/poet.song.2000.json','["當初不肯住長安，現相須歸泗水間。", "今日又還思展化，東來海上鎮狼山。"]'),
('77c8fe71-7a6a-4902-aaaf-143278602324','述懷二首  其一','郭昭乾','宋','宋诗','song-poetry','','[]','箕穎久淪沒，矯矯誰能羣。',48,'全唐诗/poet.song.2000.json','["箕穎久淪沒，矯矯誰能羣。", "憶昔讓王者，高風殊可聞。", "我懷在寥廓，思勒滄浪勳。", "何時凌紫蹻，翛然絕塵氛。"]'),
('a9e86383-f55e-4887-aa9e-7e66d15c9195','述懷二首  其二','郭昭乾','宋','宋诗','song-poetry','','[]','皇皇長安都，赫赫金張第。',48,'全唐诗/poet.song.2000.json','["皇皇長安都，赫赫金張第。", "車馬競奔趨，窮達在片議。", "綺麗世所欣，崇高物恒忌。", "何如古逸民，蓬門卧幽閟。"]'),
('85eb3492-9547-4bb5-bb06-b5424f6fc867','移家','郭昭乾','宋','宋诗','song-poetry','','[]','大道夷且長，捷徑自窘步。',60,'全唐诗/poet.song.2000.json','["大道夷且長，捷徑自窘步。", "借問漫游人，胡爲局紆路。", "我馬亦既秣，風雲豈馳騖。", "遷喬非所期，舍筏聊自渡。", "世途良足吁，更駕循軌度。"]'),
('fac1ebec-2787-4e8e-a054-f93cfd29d566','送汝端兄南還兄自詫有仙授異丹故篇中及之','郭昭務','宋','宋诗','song-poetry','','[]','一榻清風喜共攀，又携姜被惜間關。',64,'全唐诗/poet.song.2000.json','["一榻清風喜共攀，又携姜被惜間關。", "虛誇海外千年藥，不借平原十日閒。", "鴻雁幾時纔北向，蓴鱸有約竟南還。", "野情縱合江南老，春草相期一解顔。"]'),
('c217a879-b3a3-425c-b583-162d31997e04','螺江廟','陳誼','宋','宋诗','song-poetry','','[]','廟裏杉松蕭颯風，廟前江水碧溶溶。',32,'全唐诗/poet.song.2000.json','["廟裏杉松蕭颯風，廟前江水碧溶溶。", "凭闌不見當時事，落日遠山千萬重。"]'),
('4c5c2347-d94e-46c2-9d4c-71ad67876af5','酬种放徵君一百韻','王禹偁','宋','宋诗','song-poetry','','["\u534e\u5c71"]','太歲在辛卯，九月萬木落。',288,'全唐诗/poet.song.2000.json','["太歲在辛卯，九月萬木落。", "是時太陰虧，占云臣道剝。", "王生出紫微，譴逐走商洛。", "扶親又抱子，迤邐過京索。", "弊車載書史，病馬懸囊橐。", "西都不敢住，空負香山約。", "閿鄉正南路，秦嶺峭如削。", "肩輿礙巨石，十步三四却。", "妻孥亦徒步，磧礫不容脚。", "山店蓋木皮，烟火渾燻灼。", "夜深聞贙虎，全家屢驚戄。", "山泉何縈回，切冽無橋彴。", "卸鞍引羸蹄，解襪事芒屩。", "晨瀾髮可鑑，朝涉脛如斮。", "商山六百里，天設皆巖崿。", "上洛在其中，狴牢曾未若。", "逐臣自可死，何必在遠惡。", "刺史不我顧，古寺聊淹泊。", "卜居雜民甿，致養無精糳。", "知道由自寬，有親强爲樂。", "側聞种先生，終南卧雲壑。", "長沮既躬耕，元禮仍開學。", "王績婦未娶，介潔翹孤鶴。", "之推母偕隠，教誨脩天爵。"]'),
('588e1df5-9cc1-43b5-95b3-707edefbc8fb','寄獻鄜州行軍司馬宋侍郎','王禹偁','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','鉅賢如木鐸，一振聲蓋代。',288,'全唐诗/poet.song.2000.json','["鉅賢如木鐸，一振聲蓋代。", "丈人文曲星，譴謫落下界。", "辭源發崑崙，意盡若到海。", "昔在神德朝，少秀負文彩。", "擢第應制舉，召試拂華蓋。", "醉揮拔萃判，一字不復改。", "傳寫遍都下，紙貴無可買。", "一命佐著作，蕓閣垂纓珮。", "歌詩數千首，人口炙與鱠。", "志大輕俸錢，痛飲負酒債。", "庸蜀既即敘，出命玉津宰。", "題柱薄長卿，銘閣笑張載。", "錦水清見髮，峨嵋綠于黛。", "物華曾不負，詩酒聊自待。", "旨甘豈擇祿，印綬久不解。", "陶潜腰任折，萊子衣有彩。", "蹉跎歷四邑，塵土不可擺。", "吾皇在藩邸，聞名四聰駭。", "即位未浹旬，獨許延英對。", "相見恨已晚，欣然契嘉會。", "諫官聊假道，紫微遽真拜。", "制誥復西漢，碑板揭東岱。", "金鑾赴夜召，顧問及遠大。", "白麻幾千紙，意出元白外。"]'),
('ede0b3b9-07cd-4a7a-99c8-11db1d40807f','寄題陝府南溪兼簡孫何兄弟','王禹偁','宋','宋诗','song-poetry','','[]','申湖在陝服，自昔名所重。',288,'全唐诗/poet.song.2000.json','["申湖在陝服，自昔名所重。", "許昌遺唐律，人口尚傳誦。", "舊迹固蓁莽，勝概猶出衆。", "前年謫商於，過此方憂恐。", "無暇濯溪泉，惻惻心甚痛。", "量移遇恩宥，方寸稍放縱。", "故人孫漢公，勤懇事迎送。", "柅車得三宿，延我入溪洞。", "春殘尚有蝶，夏首始見蝀。", "朱櫻實頗繁，黄鳥聲亦哢。", "地幽接府署，亭高瞰村壟。", "縈砌水逶迤，入簷山巃嵷。", "鯉翻自躍金，蝸曳燒餘汞。", "石危君子介，筍亂小人勇。", "虛凉集鷗鷺，爽塏無蚊蠓。", "芰葉巧如剪，萍根密非種。", "逕苔自斑駁，岸草互蓊菶。", "官醖綠開瓶，時果青出籠。", "醉中猛別後，依約似一夢。", "唯愁當要路，時復棲闒茸。", "解梁雖近山，墝埆費耕墥。", "常風有盬南，日夕塵塕埲。", "雲泉既遼遠，草樹非秀聳。", "况茲炎蒸月，縶縛何所動。"]'),
('9a81ce69-bc88-4eab-8bc4-51a71ba2372a','七夕','王禹偁','宋','宋诗','song-poetry','','[]','去年七月七，直廬閑獨坐。',288,'全唐诗/poet.song.2000.json','["去年七月七，直廬閑獨坐。", "西日下紫微，東窗暈青瑣。", "露柳蜩忽鳴，風簾燕頻過。", "寂寂紅藥階，槿花開一朵。", "時清無詔誥，性澹忘物我。", "兀然何所營，橫枕通中卧。", "夢入無何鄉，蛺蝶甚幺麽。", "孰謂處深嚴，自得放慵惰。", "中官傳宣旨，御詩令屬和。", "驚起儼衣冠，拜舞蒼苔破。", "逸翰龍蛇走，雅調金石播。", "洋洋百世音，乃賡强牽課。", "暮隨丞相出，自謂天上墮。", "歸來備乞巧，酒肴間瓜果。", "海物雜時味，羅列繁且夥。", "家人樂熙熙，兒戲舞娑娑。", "寵辱方若驚，倚伏忽成禍。", "九月謫商於，羈縻復窮餓。", "鳳儀困鴟嚇，驥足翻鼈跛。", "山城已僻陋，旅舍甚叢脞。", "夏旱麥禾死，春霜花木挫。", "吾親極衰耄，吾命何轗軻。", "稚子啼我前，孺人病我左。", "玄髮半凋落，紫綬空垂拖。"]'),
('eb91d85e-9df4-4dcf-9adc-fc6c83b59a93','讀漢文紀','王禹偁','宋','宋诗','song-poetry','','[]','西漢十二帝，孝文最稱賢。',120,'全唐诗/poet.song.2000.json','["西漢十二帝，孝文最稱賢。", "百金惜人力，露臺草芊眠。", "千里却駿骨，鸞旗影遷延。", "上林慎夫人，衣短無花鈿。", "細柳周將軍，不拜容櫜鞬。", "霸業固以盛，帝道或未全。", "賈生多謫宦，鄧通終鑄錢。", "謾道膝前席，不如衣後穿。", "使我千古下，覽之一泫然。", "頼有佞倖傳，賢哉司馬遷。"]'),
('658c2769-b4a0-4c35-9646-c30240bd7144','合崖湫','王禹偁','宋','宋诗','song-poetry','','[]','合崖何嵌崆，湫水何浺瀜。',180,'全唐诗/poet.song.2000.json','["合崖何嵌崆，湫水何浺瀜。", "渟污暨積潦，滯泥不朝宗。", "有時見鬼怪，無人薦王公。", "止可飲麋鹿，未嘗産蛟龍。", "山甿自神之，祠祀衆口同。", "今春商於旱，太守職憂農。", "先請境內山，熊耳有如聾。", "乃迎是湫水，盈乎素缶中。", "州民與郡吏，覡女雜巫童。", "朝祈又夕禱，拜起虔且恭。", "馨爐復奠爵，牲幣潔而豐。", "適與天雨會，三日勢濛濛。", "致謝送水歸，盡禮有始終。", "水旱蓋定數，災祥與政通。", "傅巖道喪久，咄爾貪天功。"]'),
('b7f783a6-c71a-47c7-878c-ac9e55a6aa88','吾志','王禹偁','宋','宋诗','song-poetry','','[]','吾生非不辰，吾志復不卑。',120,'全唐诗/poet.song.2000.json','["吾生非不辰，吾志復不卑。", "致君望堯舜，學業根孔姬。", "自爲志得行，功業如臯夔。", "既登俊秀科，又在清切司。", "諫紙無直言，綸誥多愧辭。", "黽勉爲何事，親老與妻兒。", "一旦命執法，嫉惡寄所施。", "丹筆方肆直，皇情已見疑。", "斥逐深山中，窮辱何羸羸。", "于張及不得，安用此生爲。"]'),
('0973bc28-7ab4-4867-82e8-54b8e9a471e5','携稚子東園刈菜因書觸目兼寄均州宋四閣長','王禹偁','宋','宋诗','song-poetry','','[]','大燕引新雛，小鴉哺老烏。',96,'全唐诗/poet.song.2000.json','["大燕引新雛，小鴉哺老烏。", "青青樹木間，禽鳥聲歡娛。", "我携二稚子，東園擷春蔬。", "可以奉晨羞，采采供貧厨。", "非肉誠不飽，割身實無餘。", "緬懷宋閣老，同日出京都。", "謫宦不携家，留妻事老姑。", "塊然武當下，此樂固亦無。"]'),
('7b2a835c-26de-4639-a76c-4c2ef7e3c209','四皓廟  其一','王禹偁','宋','宋诗','song-poetry','','[]','秦皇焚舊典，漢祖溺儒冠。',180,'全唐诗/poet.song.2000.json','["秦皇焚舊典，漢祖溺儒冠。", "萬民在塗炭，四老方宴安。", "白雲且高卧，紫芝非素餐。", "南山正優游，東朝忽艱難。", "高步揖萬乘，拂衣歸重巒。", "飛鴻自冥冥，束帛徒戔戔。", "古廟對山開，清風向人寒。", "更無隠遁士，空有賓客官。", "况我謫宦來，塵跡污祠壇。", "朝衣慚蕙带，佩玉愧紉蘭。", "或依階下樹，陶暑解馬鞍。", "或借廟前水，乘秋把魚竿。", "吾道多齟齬，吾生利盤桓。", "登山殊未倦，飲水聊盡驩。", "精靈莫相笑，此意樂且盤。"]'),
('ee57e2d6-d621-4a30-b340-72ed4b53d043','四皓廟  其二','王禹偁','宋','宋诗','song-poetry','','[]','小言望小利，載在禮經中。',48,'全唐诗/poet.song.2000.json','["小言望小利，載在禮經中。", "遂有鷹犬輩，拔劍各爭功。", "一出定萬乘，去若冥冥鴻。", "寂寂千古下，孰繼採芝翁。"]'),
('fe3e5584-38ee-4e3b-84c1-2f8fbaac7759','不見陽城驛','王禹偁','宋','宋诗','song-poetry','','[]','不見陽城驛，空吟昔人詩。',288,'全唐诗/poet.song.2000.json','["不見陽城驛，空吟昔人詩。", "誰改避賢郵，唱首元微之。", "微之謫江陵，顦悴爲判司。", "路宿商山驛，一夕見嗟咨。", "所嗟陽道州，抗直貞元時。", "時亦被斥逐，南荒終一麾。", "題詩改驛名，格力何高奇。", "樂天在翰林，亦和遷客詞。", "遂使道州名，光與日月馳。", "是後數十年，借問經者誰。", "留題富水驛，始見杜紫微。", "紫微言驛名，不合輕改移。", "欲遣朝天者，惕然知在茲。", "一以諱事神，名呼不忍爲。", "一以名警衆，名存教可施。", "爲善雖不同，同歸化之基。", "邇來又百稔，編集空鱗差。", "我遷上雒郡，罪譴身縶維。", "舊詩猶可誦，古驛殊無遺。", "富水地雖在，陽城名豈知。", "空想數君子，貫若珠纍纍。", "三章詩未泯，千古名亦隨。", "德音苟不嗣，吾道當已而。", "前賢尚如此，今我復何悲。"]'),
('7aa4ec4f-3d57-4a84-88a9-53855bb7a1a5','感流亡','王禹偁','宋','宋诗','song-poetry','','[]','謫居歲云暮，晨起厨無烟。',264,'全唐诗/poet.song.2000.json','["謫居歲云暮，晨起厨無烟。", "頼有可愛日，懸在南榮邊。", "高舂已數丈，和暖如春天。", "門臨商於路，有客憇簷前。", "老翁與病嫗，頭鬢皆皤然。", "呱呱三兒泣，呱呱一夫鰥。", "道糧無斗粟，路費無百錢。", "聚頭未有食，顔色頗饑寒。", "試問何許人，答云家長安。", "去年關輔旱，逐熟入穰川。", "婦死埋异鄉，客貧思故園。", "故園雖孔邇，秦嶺隔藍關。", "山深號六里，路峻名七盤。", "襁負且乞丐，凍餒復險艱。", "唯愁大雨雪，殭死山谷間。", "我聞斯人語，倚戶獨長歎。", "爾爲流亡客，我爲冗散官。", "左宦無俸祿，奉親乏甘鮮。", "因思筮仕來，倏忽過十年。", "峨冠蠹黔首，旅進長素餐。", "文翰皆徒爾，放逐固宜然。", "家貧與親老，睹翁聊自寬。"]'),
('31c433a5-b696-4c9a-9170-d91ea9494e05','除夜','王禹偁','宋','宋诗','song-poetry','','[]','四十强而仕，禮文可遵守。',108,'全唐诗/poet.song.2000.json','["四十强而仕，禮文可遵守。", "筮仕已十年，明朝三十九。", "自知得祿早，左宦誠宜有。", "年雖過潘岳，未爲全白首。", "貧猶勝墨子，黔突聊供口。", "若比張辟彊，吾甘爲老醜。", "若比太公望，吾方爲少秀。", "任從新歲來，且獻高堂壽。", "更解金貂冠，多貰商山酒。"]'),
('da3ad020-76a7-40a3-81a0-f98c444ef1a1','竹䶉','王禹偁','宋','宋诗','song-poetry','','[]','商嶺多修篁，蒼翠連山谷。',252,'全唐诗/poet.song.2000.json','["商嶺多修篁，蒼翠連山谷。", "有鼠生其中，薦食無厭足。", "春筍齧生犀，秋筠折寒玉。", "飫飽致肥腯，優游恣蕃育。", "林密鳶不攫，穴深犬難逐。", "鳳凰餓欲死，彼實無一掬。", "唯此竹間䶉，琅玕長滿腹。", "暖戲綠叢陰，舉頭傲鴻鵠。", "不知商山民，愛爾身上肉。", "有鍤利其鋒，有錐銛于鏃。", "開穴窘如囚，洞胸聲似哭。", "膏血尚淋灕，携來入市鬻。", "竹也比賢良，鼠兮類盲俗。", "所食既非宜，所禍誠知速。", "吁嗟狡小人，乘時竊君祿。", "貴依社樹神，俸盜太倉粟。", "笙簧佞舌鳴，藥石嘉言伏。", "朝見秉大權，夕聞罹顯戮。", "李斯具五刑，趙高夷三族。", "信有司殺者，在暗明於燭。", "彼狡勿害賢，彼鼠無食竹。"]'),
('8a3b50cb-fbf4-4862-83d5-5cab712d9544','觀鄰家園中種黍示嘉祐','王禹偁','宋','宋诗','song-poetry','','[]','比鄰有閑園，瓦礫雜荆杞。',132,'全唐诗/poet.song.2000.json','["比鄰有閑園，瓦礫雜荆杞。", "未嘗動耕牛，但見牧羣豕。", "今夏赤旱天，斲琢誰家子。", "播種甚莽鹵，苗稼安能起。", "秋來連月雨，柴門晝不啟。", "新晴一携杖，出戶聊徙倚。", "重到田中立，黍稷何薿薿。", "吐穗欲及肩，鳥雀聲亦喜。", "力穡乃有秋，斯言不虛矣。", "向使懶種植，荒榛殊未已。", "有書閑不讀，爲學還如此。"]'),
('f51704a5-da09-4c6a-b879-ba04ab4a5f09','蔬食示舍弟禹圭并嘉祐','王禹偁','宋','宋诗','song-poetry','','[]','吾爲士大夫，汝爲隸子弟。',144,'全唐诗/poet.song.2000.json','["吾爲士大夫，汝爲隸子弟。", "身未列官常，庶人亦何异。", "無故不食珍，禮文明所記。", "况非膏粱家，左宦乏貲費。", "商山水復旱，穀價方騰貴。", "更恐到前春，藜藿亦不繼。", "吾聞柳公綽，近代居貴位。", "每逢水旱年，所食唯一器。", "豐稔即加籩，列鼎又何愧。", "且吾官冗散，適爲時所棄。", "汝家本寒賤，自昔無生計。", "菜茹各須甘，努力度凶歲。"]'),
('6493b796-ba47-4359-9871-086113a8b95a','懷賢詩 桑魏公','王禹偁','宋','宋诗','song-poetry','','[]','魏公王佐才，獨力造晉室。',288,'全唐诗/poet.song.2000.json','["魏公王佐才，獨力造晉室。", "揮手廓氛霾，放出扶桑日。", "感慨會風雲，周旋居密勿。", "下民得具瞻，上帝賚良弼。", "沉沉帷幄謀，落落政事筆。", "品流遂甄別，法令頗齊一。", "跋敕朝據案，論兵夜造膝。", "多士若鴛鴻，官材咸有秩。", "諸侯如狼虎，請謁盡股栗。", "秉鈞多事朝，綽綽有紀律。", "遠將留侯比，近以贊皇匹。", "志在混車書，誓將闡儒術。", "皇天未厭亂，運去何飈欻。", "高祖厭寰區，少帝無始卒。", "老成既疏遠，羣小相親昵。", "黷武兵漸驕，倒懸人不恤。", "和親絕强虜，謀帥用悍卒。", "魏公在藩垣，上疏論得失。", "七事若丹青，辭切痛入骨。", "忠言殊不省，直道果見屈。", "鐵馬從北來，煙塵晝蓬勃。", "穹廬易市朝，左袵雜纓紱。", "主辱臣不死，囚縛自安逸。", "唯公獨遇害，身殞名不沒。"]'),
('ff97b4f3-de04-4583-9c0d-8f919b4580dd','懷賢詩 李兵部','王禹偁','宋','宋诗','song-poetry','','[]','有唐張曲江，盛名何暐曄。',264,'全唐诗/poet.song.2000.json','["有唐張曲江，盛名何暐曄。", "請誅安祿山，先覺不見納。", "胡雛有反相，其事遠相接。", "賢人何代無，舊史聊可獵。", "兵部事晉朝，文學中科甲。", "强臣方跋扈，朝士多恇怯。", "獨持上方劍，願斬奔鯨鬣。", "堂堂張彥澤，反勢淩閶闔。", "拜章請顯戮，直氣不可壓。", "三進叩玉墀，植笏立蓂莢。", "皇情彌慰撫，清問屢應答。", "終焉念小恩，曾不顧大業。", "高吟歸去詩，潺湲淚承睫。", "旋踵即亂華，有同虞不臘。", "張公領鐵馬，朝市胡塵合。", "刺謁甚閑詳，辭氣殊不懾。", "虎狼不敢害，加禮爲下榻。", "當年棄謇諤，異代居調燮。", "相位席不暖，帝澤安可洽。", "斯人既淪亡，此風亦蕭颯。", "滑稽何足累，大節世已乏。", "安用學腐儒，矻矻守禮法。"]'),
('b2eaea49-4baf-425e-b2ff-19670cb3ab2f','懷賢詩 王樞密','王禹偁','宋','宋诗','song-poetry','','[]','西樞經緯才，慷慨遇真主。',252,'全唐诗/poet.song.2000.json','["西樞經緯才，慷慨遇真主。", "文學中甲科，風雲參霸府。", "直躬在密勿，未始畏彊禦。", "憑案讀古書，箕踞視太祖。", "澤欲浸生民，化將還邃古。", "拆寺遇武宗，排佛如韓愈。", "盡髮羣苾蒭，使之藝禾黍。", "兵威遂强盛，人力不耗蠹。", "世宗征淮甸，委任當留務。", "馬前拜侯伯，階下列椹斧。", "叱咤氣生風，將校汗如雨。", "手築太平基，胼胝不輟杵。", "具瞻人有望，衰運時不與。", "修短天難忱，殲奪民何怙。", "恩深與小斂，撫槨甚悲沮。", "云亡復殄瘁，前哲非虛語。", "世豈乏賢良，才難具文武。", "曆象過羲和，文章敵燕許。", "可能隨衆人，冥寞歸塵土。", "子孫雖衆多，必復事未睹。", "誰銘遷客詩，高揭王公墓。"]'),
('6fdfa2de-c1a2-42ee-a058-82a3f21595f8','五哀詩 故尚書兵部侍郎琅琊王公','王禹偁','宋','宋诗','song-poetry','','[]','琅琊名父子，少孤起徒步。',288,'全唐诗/poet.song.2000.json','["琅琊名父子，少孤起徒步。", "贄謁桑魏公，藻鑑非易與。", "撫頂久歎惜，王楊許爲伍。", "諸侯取爲官，佐幕大名府。", "主帥杜重威，功大心跋扈。", "天驥被縶維，神龜罹網罟。", "六師薄孤壘，三面開生路。", "主人既釋放，賓筵因詿誤。", "逼脅本非辜，貶謫尋不赴。", "折腰紆墨綬，搨翼久未舉。", "梁竦耻州縣，長卿有辭賦。", "裏行旌邑政，柱史登朝序。", "抨彈志不樂，潤色才有素。", "錦窠應列宿，星垣吟藥樹。", "丹青生帝典，金玉鏗王度。", "東觀秉直筆，南宮司貢部。", "時英萃門下，藹藹騰嘉譽。", "鵬掀六月風，豹蔚七日霧。", "多才同列忌，嫉惡姦人怒。", "排斥屢專城，織羅仍典午。", "名宦頗流離，衣食常貧窶。", "文明起代邸，振拔非不遇。", "紫微雖正拜，白髮已遲暮。", "史魚直有遺，棖也剛不吐。"]'),
('7feae814-4a72-4bf2-8b93-3eeabdf747b8','五哀詩 故尚書虞部員外郎知制誥貶萊州司馬渤海高公','王禹偁','宋','宋诗','song-poetry','','[]','文自咸通後，流散不復雅。',120,'全唐诗/poet.song.2000.json','["文自咸通後，流散不復雅。", "因仍歷五代，秉筆多艷冶。", "高公在紫微，濫觴誘學者。", "自此遂彬彬，不蕩亦不野。", "惜哉傷躁進，忤旨出閣下。", "吾君登大寶，兌澤連霶灑。", "均陽又淮陽，移徙曾不暇。", "遂無牽復命，虛偶文明化。", "何路得自新，賫志入長夜。", "人謂責太深，終于郡司馬。"]'),
('e6be7f1f-cd72-4b3e-a469-8b7bfbab9cb9','謁廣慈大師詩頌  其一','趙抃','宋','宋诗','song-poetry','','[]','乞得鄉州樂矣哉，雪峰安靜此徘徊。',32,'全唐诗/poet.song.20000.json','["乞得鄉州樂矣哉，雪峰安靜此徘徊。", "浙江莫謂音書隔，一日潮聲兩度來。"]'),
('da61887e-72f0-4817-92ff-4aae749f1834','謁廣慈大師詩頌  其二','趙抃','宋','宋诗','song-poetry','','[]','大空西山小空東，侍者神通未知窮。',32,'全唐诗/poet.song.20000.json','["大空西山小空東，侍者神通未知窮。", "庵來不言還作麽，數珠提起□裴公。"]'),
('76e00f59-4a59-445e-8f20-c79754112417','重遊龍井','趙抃','宋','宋诗','song-poetry','','[]','湖山深處梵王家，半紀重來兩鬢華。',32,'全唐诗/poet.song.20000.json','["湖山深處梵王家，半紀重來兩鬢華。", "珍重老師迎意厚，龍泓亭上點龍茶。"]'),
('2b39b7b5-6a6f-4220-a6fa-18117dbd3a80','石橋','趙抃','宋','宋诗','song-poetry','','[]','曉登山閣一爐香，瞻企神僧到上方。',32,'全唐诗/poet.song.20000.json','["曉登山閣一爐香，瞻企神僧到上方。", "人度石橋何所畏，如來原是世津梁。"]'),
('6b58cfd5-df70-49be-9d18-2f2774e61efe','題甘棠樓','趙抃','宋','宋诗','song-poetry','','[]','闌干十二壓仙瀛，占得龍峰作畫屏。',64,'全唐诗/poet.song.20000.json','["闌干十二壓仙瀛，占得龍峰作畫屏。", "林映遠籠千里月，湖光寒照一天星。", "望來瀑布真霜練，飛過沙禽半雪翎。", "人賞不知春已老，隔橋依舊柳青青。"]'),
('6968586c-22c5-4304-b554-f8b254c63623','繡川湖','趙抃','宋','宋诗','song-poetry','','[]','東南山水聞之久，未省人曾說義烏。',32,'全唐诗/poet.song.20000.json','["東南山水聞之久，未省人曾說義烏。", "萬頃波濤驚客眼，始知中有繡川湖。"]'),
('4bb60cb2-06b3-4637-afdb-9907d0733775','上趙少師','趙抃','宋','宋诗','song-poetry','','[]','義高德厚賢在躬，進榮退美光初終。',224,'全唐诗/poet.song.20000.json','["義高德厚賢在躬，進榮退美光初終。", "越有神明相元功，疾憂之外康寧中。", "乃眷乃顧爰徂東，徒御雖寡人望雄。", "其高可仰厚可宗，茲行允美江淮風。", "父老相呼告兒童，三朝無事繄厥忠。", "公謀公惠世所蒙，肆安於賈田安農。", "溫衣蔽體食飽胸，小攘大竊消姦兇。", "州牢縣獄囚多空，歡心和氣成年豐。", "汝曹雖騃念所從，汝心汝貌加愛恭。", "薪蒸勿采米忽春，亟歌屢舞馳省公。", "有人昔與公車逢，汝陰潁尾洛陽嵩。", "山有迹兮水有蹤，水之鶴兮山之松。", "一朝賜號逍遥翁，馬資僕費官與供。", "汝曹努力吾老癃，公若再來勤筑宮。"]'),
('0b5e0376-db63-41cd-83e6-01734b35b1ed','又題祠館','趙抃','宋','宋诗','song-poetry','','[]','德澤涵濡得二難，百年祠館見遺安。',32,'全唐诗/poet.song.20000.json','["德澤涵濡得二難，百年祠館見遺安。", "蒼蒼一片墳臺石，留在行人下馬看。"]'),
('639ad04d-d652-4d7f-8ee2-6efc84acf05a','題石龍山','趙抃','宋','宋诗','song-poetry','','[]','石龍山頂拔巍顛，我此登臨骨凜然。',32,'全唐诗/poet.song.20000.json','["石龍山頂拔巍顛，我此登臨骨凜然。", "直上更無容足地，速回猶在夕陽天。"]'),
('9b4b22fa-d47c-485e-b947-3e3a8b30fe6e','題東報恩寺','趙抃','宋','宋诗','song-poetry','','[]','松撼寒聲竹鎖陰，梵宮瀟灑稱行吟。',64,'全唐诗/poet.song.20000.json','["松撼寒聲竹鎖陰，梵宮瀟灑稱行吟。", "庭前花意自榮落，門外山光同古今。", "夜榻近軒孤月滿，曉鋤尋藥亂雲深。", "中間若了休休事，不信歡愁解到心。"]'),
('1160840e-1785-4f8f-8647-79ac34b12329','題瑞巖聖壽寺','趙抃','宋','宋诗','song-poetry','','[]','寶界香園接翠微，此焉空寂遠塵機。',64,'全唐诗/poet.song.20000.json','["寶界香園接翠微，此焉空寂遠塵機。", "寒冰扣曉人無垢，古劍藏秋谷有輝。", "水石潺頑迷客徑，松雲灑落護禪扉。", "我來笑被名韁鎖，斜日匆匆策馬歸。"]'),
('d8a2a27c-abe1-45cf-bad8-f51a436a02ec','句  其一','趙抃','宋','宋诗','song-poetry','','[]','馬尋舊路知歸去，龜放長淮不再來。',16,'全唐诗/poet.song.20000.json','["馬尋舊路知歸去，龜放長淮不再來。"]'),
('39a78d9a-91d4-4a5f-bf3b-a8965cf55def','句  其二','趙抃','宋','宋诗','song-poetry','','[]','乍辭龍尾道，來刺虎頭城。',12,'全唐诗/poet.song.20000.json','["乍辭龍尾道，來刺虎頭城。"]'),
('9b80490b-250b-4490-b6de-4c563f893f0c','句  其三','趙抃','宋','宋诗','song-poetry','','[]','靈山一片雲邊雨，每爲熙朝作歲豐。',16,'全唐诗/poet.song.20000.json','["靈山一片雲邊雨，每爲熙朝作歲豐。"]'),
('f9c194af-6322-4fb5-94c4-bbd5d15b652f','引流聯句','趙揚','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.20000.json','["無正文。"]'),
('58322372-4865-4b79-a77f-fca782918c13','引流聯句','趙抗','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.20000.json','["無正文。"]'),
('ea5b8e38-5a90-4b58-8fe7-87d10f02c7dd','句','王照','宋','宋诗','song-poetry','','[]','回首高齋拭淚痕。',8,'全唐诗/poet.song.20000.json','["回首高齋拭淚痕。"]'),
('bd8ce915-af85-4ede-9945-dddf454912ec','信相院慧燈','范鎮','宋','宋诗','song-poetry','','[]','行樂到蕭寺，像殿何煌煌。',132,'全唐诗/poet.song.20000.json','["行樂到蕭寺，像殿何煌煌。", "僧年過九十，細話燈焰長。", "方憶髫齔時，初離父母鄉。", "是時循舊迹，晝夜不暫忘。", "自事膏火來，日就與月將。", "始卒未嘗暗，眉髮皆如霜。", "禦風設絳紗，求福兼異香。", "寒村會織女，借餘坐如匡。", "陋巷苦志士，鑿壁偷隣光。", "太息日已暮，百結忡心腸。", "類此事億萬，聊書成短章。"]'),
('f01307eb-df58-4b72-b5b5-09905a9f3923','送程端明再鎮成都','范鎮','宋','宋诗','song-poetry','','[]','成都一都會，千里带坤維。',120,'全唐诗/poet.song.20000.json','["成都一都會，千里带坤維。", "自昔公坐嘯，至今人去思。", "朝廷慎東注，方面要安綏。", "遂爾重藩屏，因之職殿帷。", "龍光出劍匣，謳頌走江湄。", "曉雪離都馭，春風入境旗。", "壺漿故父老，竹成舊童兒。", "疊足相歡躍，同心仰福禧。", "邦人顧若此，邑子更何其。", "會講中和化，重爲樂職詩。"]'),
('0c8b03cd-c272-4239-bcd8-e229807cd9ef','遊昭覺寺','范鎮','宋','宋诗','song-poetry','','[]','炎蒸無處避，此地忽如寒。',48,'全唐诗/poet.song.20000.json','["炎蒸無處避，此地忽如寒。", "松砌行無際，石房禪自安。", "鴛鴦秋沼漲，蝙蝠晚庭寬。", "登眺見田舍，衡茅半不完。"]'),
('674592f6-9467-4a13-a9e0-ed24ad0bcfd7','浄眾寺新禪院','范鎮','宋','宋诗','song-poetry','','[]','金寺西郊外，一來煩惱攄。',48,'全唐诗/poet.song.20000.json','["金寺西郊外，一來煩惱攄。", "凡逢似仙境，鮮不屬僧居。", "岸綠見翹鷺，溪清無隱魚。", "殘陽已周覽，欲去幾躊躇。"]'),
('fbd7b814-9c11-4bd7-8ba3-70d1a549a648','武侯廟柏','范鎮','宋','宋诗','song-poetry','','[]','滿葉是清霜，培根無沃土。',48,'全唐诗/poet.song.20000.json','["滿葉是清霜，培根無沃土。", "恥作秦皇松，寧爲馮異樹。", "英靈自有風，蔭蔚長如雨。", "可憐青青姿，不知人事古。"]'),
('ec3dff25-9b97-40ff-b854-b9fde8f87dd8','留題張少愚屋壁','范鎮','宋','宋诗','song-poetry','','[]','高隱郫城下，平地仍徑還。',48,'全唐诗/poet.song.20000.json','["高隱郫城下，平地仍徑還。", "門開值冠蓋，簾卷爲江山。", "沛雨人間待，浮雲天外閒。", "泥封詔不起，明夕奉慈顔。"]'),
('3089f593-6512-44a0-b13e-66e203b813b9','送羅勝卿同年提舉玉局觀','范鎮','宋','宋诗','song-poetry','','[]','匹馬西歸去，知君得意偏。',48,'全唐诗/poet.song.20000.json','["匹馬西歸去，知君得意偏。", "人情重鄉里，官職更神仙。", "曉後無衙喏，旬頭有俸錢。", "何須駕白鶴，辛苦上青天。"]'),
('adc902b7-1298-4eed-8e50-828e22a2c1ec','送羅郎中登管勾玉局觀','范鎮','宋','宋诗','song-poetry','','[]','五門門裏觀，松檜日蕭疎。',48,'全唐诗/poet.song.20000.json','["五門門裏觀，松檜日蕭疎。", "道話忘心境，仙歌作步虛。", "壇場高突兀，廊廡四紆餘。", "世事多紛擾，君心定了如。"]'),
('dd402c0f-be98-4a34-8c08-ddf9c5958027','韓太丞同守成都次韻  其一','范鎮','宋','宋诗','song-poetry','','[]','盛府佳招貴，嚴宸雅寄深。',48,'全唐诗/poet.song.20000.json','["盛府佳招貴，嚴宸雅寄深。", "輿題仲舉坐，闕掛子牟心。", "漢竹分新契，潘花過舊陰。", "當年百里驥，方此試駸駸。"]'),
('d38d9024-f13d-4663-bc02-a66a6fd60f7f','韓太丞同守成都次韻  其二','范鎮','宋','宋诗','song-poetry','','[]','近境連桑陌，先遊盛竹林。',48,'全唐诗/poet.song.20000.json','["近境連桑陌，先遊盛竹林。", "併將懷舊意，持作惠時心。", "藻思春生筆，清機月滿襟。", "成風錦江曲，迥上玉山岑。"]'),
('8bdb5539-3d6c-46cf-a671-28a97b0b62e6','韓太丞同守成都次韻  其三','范鎮','宋','宋诗','song-poetry','','[]','春色草將深，春寒柳未陰。',48,'全唐诗/poet.song.20000.json','["春色草將深，春寒柳未陰。", "青天指行棧，淥水蕩離襟。", "後乘何爲託，前旌喻此心。", "南枝倦飛翼，憑爲寄歸音。"]'),
('f5af9540-8ca4-4977-9167-0fbd72ff8862','仲遠龍圖見邀學射之遊先寄五十六言','范鎮','宋','宋诗','song-poetry','','[]','幾年魂夢寄西州，春晚歸逢學射遊。',64,'全唐诗/poet.song.20000.json','["幾年魂夢寄西州，春晚歸逢學射遊。", "十里香風塵不動，半山晴日雨初收。", "指撝武弁呈飛騎，次第紅粧數勝籌。", "夾道綺羅瞻望處，管絃旌旆擁遨頭。"]'),
('e822a3e4-3d48-4070-b25a-5471500227ef','和閻寺丞海雲寺','范鎮','宋','宋诗','song-poetry','','[]','春日金田驩且譁，始因民俗好紛奢。',64,'全唐诗/poet.song.20000.json','["春日金田驩且譁，始因民俗好紛奢。", "管絃齊奏喧聞野，鶯燕高飛不在花。", "雕檻憑時見城郭，迴廊行處有烟霞。", "方塘靈石從來信，不獨當年太守誇。"]'),
('4c4be8d0-fa20-4294-ae73-eba46d83f8c3','登崇聖閣','范鎮','宋','宋诗','song-poetry','','[]','金地環迴半錦城，累年斤斧不停聲。',64,'全唐诗/poet.song.20000.json','["金地環迴半錦城，累年斤斧不停聲。", "遠村民舍烟未起，滿寺僧筵鐘盡鳴。", "欄檻高低資眺覽，市廛言笑尚分明。", "阿房昔日徒虛語，壯麗應虧此畫楹。"]'),
('3433ec85-c2a9-4d78-807d-df00d033f07f','和提刑海棠','范鎮','宋','宋诗','song-poetry','','[]','不知真宰是誰專，生得韶光此樹偏。',64,'全唐诗/poet.song.20000.json','["不知真宰是誰專，生得韶光此樹偏。", "吟筆偶遺工部意，賦詞今識翰林權。", "風翻翠幕晨香入，霞照危牆夕影連。", "移植上園如得地，芳名應在紫薇先。"]'),
('644f5a1e-9444-47a6-adec-6acbab6293b4','和成都吳仲庶見寄來韵  其一','范鎮','宋','宋诗','song-poetry','','[]','歲華今緩昔如流，舊日樊籠可自由。',64,'全唐诗/poet.song.20000.json','["歲華今緩昔如流，舊日樊籠可自由。", "官事了時無盡極，人生安處且閒休。", "愚忠皎皎丹心老，歸思綿綿兩鬢秋。", "縱使海棠時節過，急行須及浣花遊。"]'),
('57ee2c95-4e4d-4884-9e82-5d6bf5a6c3fa','和成都吳仲庶見寄來韵  其二','范鎮','宋','宋诗','song-poetry','','[]','濯錦江深惠澤流，西人都未究蹤由。',64,'全唐诗/poet.song.20000.json','["濯錦江深惠澤流，西人都未究蹤由。", "耕疇擁耒春還動，織戶鳴機夜不休。", "講德定應勞四子，富民須合用千秋。", "鳳凰臺上需賢久，却恐龜城作蹔遊。"]'),
('d6e7c06c-c8bc-41ca-bd3e-2fa6e77596b9','和成都吳仲庶見寄來韵  其三','范鎮','宋','宋诗','song-poetry','','[]','山橫雙劔水雙流，栖北巢南去未由。',64,'全唐诗/poet.song.20000.json','["山橫雙劔水雙流，栖北巢南去未由。", "三尺素琴彈浩浩，一爐丹藥詠休休。", "白巖霜重紅梨曉，銀礫烟深紫芋秋。", "每夜夢魂歸處路，只應明月見神遊。"]'),
('a6ac6f78-8c4f-4420-a1c8-19c06b864956','題曹山人墅居','范鎮','宋','宋诗','song-poetry','','[]','橋外浣花溪水通，山人高隱在其中。',32,'全唐诗/poet.song.20000.json','["橋外浣花溪水通，山人高隱在其中。", "一江絲竹喧天沸，爭及松篁半日風。"]'),
('248744cd-f7fd-4f1e-9a6f-7fe9c2fa34d5','雞鳴臺','范鎮','宋','宋诗','song-poetry','','[]','古人惟恃眾心城，何事秦皇苦好兵。',32,'全唐诗/poet.song.20000.json','["古人惟恃眾心城，何事秦皇苦好兵。", "本設函關禁奸詐，不知半夜有雞鳴。"]'),
('94f14796-c0f3-40eb-8fe7-8140bba884b9','上巖','范鎮','宋','宋诗','song-poetry','','[]','巖雨晴猶滴，溪泉直復迂。',24,'全唐诗/poet.song.20000.json','["巖雨晴猶滴，溪泉直復迂。", "傾崖目眩轉，亂石步崎嶇。"]'),
('752c0868-bf9f-413d-af76-7d8386902dcf','成都觀牡丹','范鎮','宋','宋诗','song-poetry','','[]','自古成都勝，開花不似今。',48,'全唐诗/poet.song.20000.json','["自古成都勝，開花不似今。", "徑圍三尺大，顔色幾重深。", "未放香噴雪，仍藏蕊散金。", "要知空色論，聊見主人心。"]'),
('5cc7316d-8d2e-48af-9aad-f95549e96893','題靜照堂','范鎮','宋','宋诗','song-poetry','','[]','堂構虛閒處，師心靜照中。',48,'全唐诗/poet.song.20000.json','["堂構虛閒處，師心靜照中。", "當門自流水，滿院占清風。", "趺坐通禪觀，高談說性空。", "那知人世上，日月有樊籠。"]'),
('5e7790a0-9752-44ee-80a0-a27dd5fd0afb','次張寺丞園','范鎮','宋','宋诗','song-poetry','','[]','園林再到身猶健，官職全拋夢乍醒。',32,'全唐诗/poet.song.20000.json','["園林再到身猶健，官職全拋夢乍醒。", "惟有南山與君眼，相逢不改舊時青。"]'),
('fd9b4ba3-56c3-4d4c-ad18-768e8ffe8289','馮允南遠貺佳作有舜律遠相通之句因次韵寄之','范鎮','宋','宋诗','song-poetry','','[]','盛旦真明聖，平生伏至公。',240,'全唐诗/poet.song.20000.json','["盛旦真明聖，平生伏至公。", "遭逢不世出，覆露與天同。", "諒直誠多勉，謀猷媿罔功。", "后王明若日，夷夏慶同風。", "喜氣中兼外，歡謠北至東。", "敢圖嚴密禁，擢處太清宮。", "峻拔山形大，高明地望雄。", "起居無忘古，坐卧只思忠。", "論樂嗟淪廢，求音扣寂空。", "大和非隱伏，至理自穹崇。", "曖昧幽還顯，尊卑降復隆。", "使人思舞鳳，如弋慕飛鴻。", "世事安清謐，人心處正中。", "至醇當直詣，精義故旁通。", "本自關瑶律，還須撫素桐。", "天材由聖作，物理要人窮。", "往古爲經始，來今是考終。", "云爲極微妙，襟抱貯沖融。", "斂聚陰陽氣，窺觀造化工。", "因君說樂事，詩詠照光虹。"]'),
('479923c0-400a-42c9-a94e-9bef4908fb68','奉和馮允南二首  其一','范鎮','宋','宋诗','song-poetry','','[]','小馬輕輿蜀道難，身披裘褐頂峨冠。',64,'全唐诗/poet.song.20000.json','["小馬輕輿蜀道難，身披裘褐頂峨冠。", "已從林下幽人往，猶作朝中舊德看。", "漁釣喜歡新得侶，道途瞻顧尚呼官。", "多慚鄉友貽清唱，天外鸞音與鳳翰。"]'),
('2f753757-6f41-41db-9d8e-19542ddc1c60','奉和馮允南二首  其二','范鎮','宋','宋诗','song-poetry','','[]','常望鄉山憶翠微，此來時節更春暉。',64,'全唐诗/poet.song.20000.json','["常望鄉山憶翠微，此來時節更春暉。", "林間怨鶴久招隱，花外啼鵑仍勸歸。", "雲似隨人飛縹縹，雨如先道灑霏霏。", "迴思仕宦平生事，六十三年始悟非。"]'),
('f8ce68a1-acf8-4684-a511-433eabae4fa5','送祖龍學擇之赴陜府酌飲贈別次歐陽永叔韵','范鎮','宋','宋诗','song-poetry','','[]','史君分陜惜別難，緩聽長吟速行酒。',144,'全唐诗/poet.song.20000.json','["史君分陜惜別難，緩聽長吟速行酒。", "荆山北面黄河南，千里封疆爲己有。", "往來無窮西復東，衮衮輪蹄利名走。", "甘棠雖云勿翦伐，未必從前不傷手。", "當時遺愛安在哉，賴有聲詩傳不朽。", "擇之寸刃如新硎，歷年何啻十有九。", "胸中藴蓄富術業，此行直欲古人偶。", "近世只知厨傳爲，不顧虛名似箕斗。", "寄言道路如采詩，但問樵夫與田叟。"]'),
('01087e4c-f235-406f-a165-04089c7b1078','秋懷答司馬君實','范鎮','宋','宋诗','song-poetry','','[]','疇昔共登仕，爾來三十秋。',72,'全唐诗/poet.song.20000.json','["疇昔共登仕，爾來三十秋。", "常睎絲繩直，竊恥鴟夷柔。", "蹄涔學鉅海，螘垤依崇丘。", "行之不自疑，親寡憎怨稠。", "於今不亟去，淪胥恐同流。", "努力買良田，遠追沮溺遊。"]'),
('771b6f38-825d-4be1-ab72-404a5b5a6310','李才元寄示蜀中花圖','范鎮','宋','宋诗','song-poetry','','[]','牡丹名品眾，特地盛于今。',48,'全唐诗/poet.song.20000.json','["牡丹名品眾，特地盛于今。", "西子含羞甚，東君著意深。", "障行施爛錦，屋貯用黄金。", "妾婢羣花卉，那能不妬心。"]'),
('2c02df47-19f8-461e-9c5c-af4a196384aa','望湖臺','范鎮','宋','宋诗','song-poetry','','[]','臺上望城下，迢遥知幾尋。',24,'全唐诗/poet.song.20000.json','["臺上望城下，迢遥知幾尋。", "湖光隱隱見，多礙柳烟深。"]'),
('21e2f83f-5f3a-43ee-bd92-ccc0cf64dd20','萬艘潭','范鎮','宋','宋诗','song-poetry','','[]','私船官運鬭縱橫，殖貨交通繞近城。',32,'全唐诗/poet.song.20000.json','["私船官運鬭縱橫，殖貨交通繞近城。", "燈火夜涼人未散，古潭宜復萬艘名。"]'),
('76ae26d9-d179-41ad-8423-36f13c3a5d65','金蓮泉','范鎮','宋','宋诗','song-poetry','','[]','道侶殷勤鑿石渠，金蓮泉脈入靈都。',32,'全唐诗/poet.song.20000.json','["道侶殷勤鑿石渠，金蓮泉脈入靈都。", "暗穿竹徑仍清冷，爲我烹茶敵酪奴。"]'),
('d14c968c-8f42-4386-99c3-6cae246cb7d4','奉和君實早朝書事','范鎮','宋','宋诗','song-poetry','','[]','日氣曉先赤，天形秋轉高。',48,'全唐诗/poet.song.20000.json','["日氣曉先赤，天形秋轉高。", "風輕金轡勒，霜重毳衣袍。", "匹馬精神倦，前騶意思豪。", "近來君在告，連直幾番鼇。"]'),
('8afad2c9-9d24-4f5d-b3d0-e7020e3e9e37','聞蟬','范鎮','宋','宋诗','song-poetry','','[]','山中氣候別，二月已聞蟬。',48,'全唐诗/poet.song.20000.json','["山中氣候別，二月已聞蟬。", "乍到清凉景，翻疑暑伏天。", "此身多暇日，何事更驚年。", "雜溜淙淙響，相和勝管絃。"]'),
('8a6e52fd-3a74-4550-a296-84be275ad000','宿憩鶴寺','范鎮','宋','宋诗','song-poetry','','[]','憩鶴山間憩竹輿，宛然身世住空虛。',32,'全唐诗/poet.song.20000.json','["憩鶴山間憩竹輿，宛然身世住空虛。", "地仙縱與天仙別，明月清風也不疏。"]'),
('036dd6e3-857a-4fa8-b96e-1fdb44b75815','和司馬君實遊噴玉潭','范鎮','宋','宋诗','song-poetry','','[]','畏風垂首立，臨水側身行。',48,'全唐诗/poet.song.20000.json','["畏風垂首立，臨水側身行。", "更拂懸崖壁，援毫寫姓名。", "一道來何處，千尋正面前。", "時時玉麈下，紛泊鬢毛間。"]'),
('bc3f41fe-1a96-4c17-b3ad-4f1b565b9c15','遊噴玉潭','范鎮','宋','宋诗','song-poetry','','[]','大風吹沙高翳天，萬木簸蕩鳴空山。',96,'全唐诗/poet.song.20000.json','["大風吹沙高翳天，萬木簸蕩鳴空山。", "夜來奧熱今斗寒，下輿亂石崎嶇間。", "急著冒絮衣純棉，兩邊荆棘難躋攀。", "行到君實所詫處，却坐拂拭塵土顔。", "千尺瀑布才涓涓，深潭寂寞神龍跧。", "此來好事慎勿傳，乞得性命成生還。"]'),
('52061ede-3213-4029-8d62-588c63b1a350','壽安','范鎮','宋','宋诗','song-poetry','','[]','錦屏山下錦江人，西去東來自在身。',32,'全唐诗/poet.song.20000.json','["錦屏山下錦江人，西去東來自在身。", "正是春天好時節，枉遭風起作埃塵。"]'),
('3fab7609-59c6-4450-b09e-68178a0e8fce','和君實噴玉潭','范鎮','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','夜月光華照潔清，春雲容與覆崢嶸。',32,'全唐诗/poet.song.20000.json','["夜月光華照潔清，春雲容與覆崢嶸。", "都城咫尺無人到，却使廬山浪得名。"]'),
('080cee13-16de-4f13-9bcc-9b8021572194','和君實疊石溪','范鎮','宋','宋诗','song-poetry','','[]','到處窺泉竇，逢人問草名。',48,'全唐诗/poet.song.20000.json','["到處窺泉竇，逢人問草名。", "簪裳已無累，猜鳥不須驚。", "對景有詩癖，酌泉無酒狂。", "山間少塵土，雲際足春陽。"]'),
('101602e5-6c94-4093-95f0-702cb46264f3','疊石溪','范鎮','宋','宋诗','song-poetry','','[]','昨旦愁風色，今朝喜日華。',168,'全唐诗/poet.song.20000.json','["昨旦愁風色，今朝喜日華。", "從容下官道，迤邐見人家。", "盛服緣崖看，焚香滿路遮。", "樵柯成市井，陶穴乃生涯。", "春石聲相應，沉泥處或漥。", "累牆甆隱轔，開徑石槎牙。", "柴積高於阜，釣槃疾甚車。", "自非秦世避，誰道舜風遐。", "拄杖逢山斗，迴輿值水斜。", "遠林行翠鳳，幽隧轉青蛇。", "泉眼思搴藻，雲頭望采花。", "仰身書疊壁，平坐挹飛霞。", "有景殊難紀，茲遊信可誇。", "君如別業就，後會固無差。"]'),
('350edd40-d571-4f91-b6e0-90feaae60746','鎮卜居許下雖未有涯先作五十六言奉寄子華相公持國端明玉汝待制','范鎮','宋','宋诗','song-poetry','','[]','四十年來作往還，如今那怪鬢毛斑。',64,'全唐诗/poet.song.20000.json','["四十年來作往還，如今那怪鬢毛斑。", "鳧居雁戶得安處，鶴怨猿驚羞故山。", "靜樂顧子難獨享，公忙何日見君閑。", "相將嵩少深深處，更共眠雲紫翠間。"]'),
('bbd6ec44-e661-403c-970e-51189d6816b6','和君實喜雨三首  其一','范鎮','宋','宋诗','song-poetry','','[]','夜中間點滴，曉後見沉陰。',48,'全唐诗/poet.song.20000.json','["夜中間點滴，曉後見沉陰。", "正懼一時旱，何妨三日霖。", "著花開稍晚，入麥潤還深。", "想象離欄處，高張爛錦衾。"]'),
('51f44424-c011-4093-9f79-15521e35f04b','和君實喜雨三首  其二','范鎮','宋','宋诗','song-poetry','','[]','圖館春無賴，田家歲有收。',48,'全唐诗/poet.song.20000.json','["圖館春無賴，田家歲有收。", "那能垤鸛詠，還似土龍求。", "木蔭疏成密，雲容去復留。", "已然爲惡客，泥濘亦須遊。"]'),
('293096a0-9c98-45ab-9564-a14f57e587ca','和君實喜雨三首  其三','范鎮','宋','宋诗','song-poetry','','[]','一春憂旱熯，田里欲蹉跎。',48,'全唐诗/poet.song.20000.json','["一春憂旱熯，田里欲蹉跎。", "正合爲霖望，翻成擊壤歌。", "風緣簾隙至，雲壓舍簷過。", "大尹今朝喜，應同野老多。"]'),
('c5fc859a-b6d6-4cff-93e3-119f57a15e95','西湖泛舟輒用前韻寄呈君實','范鎮','宋','宋诗','song-poetry','','["\u897f\u6e56"]','畫船容與到橋還，舉袂依然洛酒斑。',64,'全唐诗/poet.song.20000.json','["畫船容與到橋還，舉袂依然洛酒斑。", "湖上曉光涵潩水，坐中晴色見嵩山。", "心緣念別如多事，身爲移居似不閑。", "疊石石淙雖兩處，福昌陽翟正中間。"]'),
('8412b1d9-ed1b-4ab1-ad97-ab35561fbbf5','和君實新買疊石溪莊','范鎮','宋','宋诗','song-poetry','','[]','畫處始知蛇足剩，管中那識豹文斑。',64,'全唐诗/poet.song.20000.json','["畫處始知蛇足剩，管中那識豹文斑。", "從來有道須康世，未省升平却住山。", "學富名高難自晦，眼昏心悸始能閑。", "計君疊山溪邊景，不得從容歲月閒。"]'),
('39337423-12bd-499e-9255-ad043b592e44','贈僧中海淵還閬','范鎮','宋','宋诗','song-poetry','','[]','舊鄉山水遶禪扃，日日山光與水聲。',32,'全唐诗/poet.song.20000.json','["舊鄉山水遶禪扃，日日山光與水聲。", "歸去定貪山水樂，不教魂夢到神京。"]'),
('d421283f-5167-4b36-ae68-d77ec25a0206','送張職方守筠州','范鎮','宋','宋诗','song-poetry','','[]','南國一麾守，知公安此行。',48,'全唐诗/poet.song.20000.json','["南國一麾守，知公安此行。", "家山雖萬里，子舍只鄰城。", "驛問中宵至，風謠接畛聲。", "定應持課最，同命到天京。"]'),
('67148cf1-0a8b-49f3-a925-db1461ec1dac','吏隱堂','范鎮','宋','宋诗','song-poetry','','[]','花陰柳榻常欹枕，月色侵門不下關。',32,'全唐诗/poet.song.20000.json','["花陰柳榻常欹枕，月色侵門不下關。", "因諷君詩想佳景，夜凉依約夢魂間。"]'),
('1e1cf5b4-7b36-4a58-aae9-c192c64f8861','七夕','范鎮','宋','宋诗','song-poetry','','[]','翠幕瑶梯百尺樓，樓前星斗自悠悠。',32,'全唐诗/poet.song.20000.json','["翠幕瑶梯百尺樓，樓前星斗自悠悠。", "天家仙會能多少，未到平明已別愁。"]'),
('e9f2f66a-1128-4cb7-be98-217825d32880','再至史局','范鎮','宋','宋诗','song-poetry','','[]','史局逾年別，重來已涕零。',24,'全唐诗/poet.song.20000.json','["史局逾年別，重來已涕零。", "朱書未絕筆，又欲汗新青。"]'),
('4602e576-e475-4234-984a-5510e5177f2e','黄葵','范鎮','宋','宋诗','song-poetry','','[]','開時閑淡斂時愁，蘭菊應容預勝流。',32,'全唐诗/poet.song.20000.json','["開時閑淡斂時愁，蘭菊應容預勝流。", "剩欲持杯相領略，一庭風露不禁秋。"]'),
('caea0d54-c1a5-40ba-a0be-3bc8cc81a76e','送司封劉孝祥知資州','范鎮','宋','宋诗','song-poetry','','[]','醮壇山下路，消息擬春風。',48,'全唐诗/poet.song.20000.json','["醮壇山下路，消息擬春風。", "遥知底處人，歡喜得西公。", "繡衣還西州，錦賬空南宮。", "使君五馬行，豈減御史驄。"]'),
('0bafca7b-66e3-419c-82ae-0f29a7ff2893','劍門關','范鎮','宋','宋诗','song-poetry','','[]','雲間雙劍峰，壁立望西東。',24,'全唐诗/poet.song.20000.json','["雲間雙劍峰，壁立望西東。", "天地本無外，江山還自通。"]'),
('900813ec-e672-4874-b0aa-9eaf8b0789d1','七夕二首  其一','范鎮','宋','宋诗','song-poetry','','[]','可憐風信重秋期，紅錦花香極所思。',32,'全唐诗/poet.song.20000.json','["可憐風信重秋期，紅錦花香極所思。", "乞巧樓中成底事，平明祗得玩蛛絲。"]'),
('68556e57-d5f1-4bb0-b67b-d9dd535aedb2','七夕二首  其二','范鎮','宋','宋诗','song-poetry','','[]','少年從此夕，漸老何所爲。',48,'全唐诗/poet.song.20000.json','["少年從此夕，漸老何所爲。", "與子思故鄉，置酒同賦詩。", "坐來霜露淡，夜久星斗稀。", "王宮直北里，天外橫歌期。"]'),
('ad6fb7da-e53e-48dd-825d-8c8015ef4c55','題招提院靜照堂','范鎮','宋','宋诗','song-poetry','','[]','牛斗光芒下，江山形勝中。',48,'全唐诗/poet.song.20000.json','["牛斗光芒下，江山形勝中。", "招提萬法本，靜照一堂空。", "花木含春意，門庭語古風。", "支郎丐詩什，愧匪二南工。"]'),
('668a8ace-9c23-4ec5-8e88-5e218158535d','寄綿竹致政楊郎中','范鎮','宋','宋诗','song-poetry','','[]','竹裏幽泉荷蓋池，主人投紱自相宜。',64,'全唐诗/poet.song.20000.json','["竹裏幽泉荷蓋池，主人投紱自相宜。", "水風吹面難成醉，山月當頭易得詩。", "漠漠稻畦翻虎掌，深深花塢結蜂脾。", "年來想像清高處，羞愧浮雲滿鬢絲。"]'),
('8a585d1e-bcb0-4657-a92e-58db4fcc2729','端居','范鎮','宋','宋诗','song-poetry','','[]','落花時節掩關初，清絕江城舊酒徒。',64,'全唐诗/poet.song.20000.json','["落花時節掩關初，清絕江城舊酒徒。", "滿屋煙霞春睡足，一谿風雨夜燈孤。", "易中有象閑消息，身外無求免嘆吁。", "多謝巖僧頻見訪，欲迴臨水又踟躕。"]'),
('ecd8bc6d-d9fe-4224-9103-d6bdd11c2f70','過友人墅居','范鎮','宋','宋诗','song-poetry','','[]','翠樹重重碧草齊，一丘真趣此衡樓。',64,'全唐诗/poet.song.20000.json','["翠樹重重碧草齊，一丘真趣此衡樓。", "地盤山影春難老，門掩江聲夢自迷。", "閑結柳條思遠道，靜書花葉寄春題。", "人間樂事無時足，便倚蘭干到日西。"]'),
('1765987d-08d2-4bba-8022-b9499385d18c','寓大邑遊仙寺','范鎮','宋','宋诗','song-poetry','','[]','炎蒸無處避，此地忽如寒。',48,'全唐诗/poet.song.20000.json','["炎蒸無處避，此地忽如寒。", "松砌行無際，石旁禪自安。", "鴛鴦秋沼漲，蝙蝠晚庭寬。", "登眺見田舍，衡茅半不完。"]'),
('d8a25910-1301-4179-8d40-1e08d6c30842','送文與可通判邛州','范鎮','宋','宋诗','song-poetry','','[]','半刺爲官美，臨邛自古名。',48,'全唐诗/poet.song.20000.json','["半刺爲官美，臨邛自古名。", "何言緹軾寵，要侍版輿行。", "仙籍新年貴，賓僚舊日榮。", "壺槳故父老，應在半途迎。"]'),
('7e007905-a5c7-467b-ba0d-6857d68da4b9','和王都尉','范鎮','宋','宋诗','song-poetry','','[]','慣乘霄漢鶴，翻說淤泥蓮。',24,'全唐诗/poet.song.20000.json','["慣乘霄漢鶴，翻說淤泥蓮。", "可惜玉臺處，等閑閑幾年。"]'),
('a777a11f-cac8-4de8-b2cf-cd87330156fc','詩四首  其一','范鎮','宋','宋诗','song-poetry','','[]','風定雪新晴，塵埃眼豁明。',24,'全唐诗/poet.song.20000.json','["風定雪新晴，塵埃眼豁明。", "青山似相識，終日伴行人。"]'),
('a7ec09a0-de94-469b-a85a-6c1d66ae6b03','詩四首  其二','范鎮','宋','宋诗','song-poetry','','[]','南來十日盡山行，北去前驅野稍平。',32,'全唐诗/poet.song.20000.json','["南來十日盡山行，北去前驅野稍平。", "邊日照人如月色，野風吹草似泉聲。"]'),
('1c39fee3-418c-4b32-81ad-b94934e62716','詩四首  其三','范鎮','宋','宋诗','song-poetry','','[]','鳴笳悲咽愁須絕，獵騎盤旋畫不成。',32,'全唐诗/poet.song.20000.json','["鳴笳悲咽愁須絕，獵騎盤旋畫不成。", "待與故人閒說此，幾時歸得到天京。"]'),
('27fe88e4-fd00-4114-bed9-e2f3045aa46e','詩四首  其四','范鎮','宋','宋诗','song-poetry','','[]','馬足知人意，駸駸不少留。',48,'全唐诗/poet.song.20000.json','["馬足知人意，駸駸不少留。", "路回山斗轉，沙漫水平流。", "雪底青春動，林梢赤氣浮。", "故園花發早，待得到家否。"]'),
('4e3d0aa4-7b77-4db4-bc69-5fd314e867c2','句  其一','范鎮','宋','宋诗','song-poetry','','[]','倏忽平爲險，分明假奪真。',12,'全唐诗/poet.song.20000.json','["倏忽平爲險，分明假奪真。"]'),
('64be3deb-1108-4eb5-bca7-884078b04e34','句  其二','范鎮','宋','宋诗','song-poetry','','[]','洞壑獨嵌空，壁溜珠玉濺。',12,'全唐诗/poet.song.20000.json','["洞壑獨嵌空，壁溜珠玉濺。"]'),
('52ad0d75-bb18-4b37-9ffb-563c8f3d26df','句  其三','范鎮','宋','宋诗','song-poetry','','[]','半天開佛閣，平地見人家。',12,'全唐诗/poet.song.20000.json','["半天開佛閣，平地見人家。"]'),
('bbb8e723-d6a2-4b5f-9c61-aa668d2ec8fe','句  其四','范鎮','宋','宋诗','song-poetry','','[]','想像通恍惚，大木涵天風。',12,'全唐诗/poet.song.20000.json','["想像通恍惚，大木涵天風。"]'),
('b2a5a974-c090-4e41-9336-e1d58122040e','句  其五','范鎮','宋','宋诗','song-poetry','','[]','雲霞揖神仙，烟火認城郭。',12,'全唐诗/poet.song.20000.json','["雲霞揖神仙，烟火認城郭。"]'),
('6d68689a-5d6d-4c38-b48c-54370e36f16e','句  其六','范鎮','宋','宋诗','song-poetry','','[]','先生已何處，依舊白雲飛。',12,'全唐诗/poet.song.20000.json','["先生已何處，依舊白雲飛。"]'),
('c35e69e2-117a-4f41-9c6c-1d1aa7842982','句  其七','范鎮','宋','宋诗','song-poetry','','[]','西山瞰大江，迤邐龍鱗溼。',12,'全唐诗/poet.song.20000.json','["西山瞰大江，迤邐龍鱗溼。"]'),
('fd160f13-f436-4e0c-8300-f02212e8b9eb','句  其八','范鎮','宋','宋诗','song-poetry','','[]','回頭戀翠峰，雲與烟相襲。',12,'全唐诗/poet.song.20000.json','["回頭戀翠峰，雲與烟相襲。"]'),
('f50eb8a9-3779-4c07-8c15-19215e0b11e1','句  其九','范鎮','宋','宋诗','song-poetry','','[]','眾山四面合，二水南北流。',12,'全唐诗/poet.song.20000.json','["眾山四面合，二水南北流。"]'),
('2d955d7e-fb87-4a8c-a6fd-dcd2e4bc3f49','句  其一○','范鎮','宋','宋诗','song-poetry','','[]','移家尚恐青山淺，隱几惟知白日長。',16,'全唐诗/poet.song.20000.json','["移家尚恐青山淺，隱几惟知白日長。"]'),
('3dc21804-c696-447a-906c-53b27ec8e50e','句  其一一','范鎮','宋','宋诗','song-poetry','','[]','不學鄉人誇駟馬，未饒吾祖泛扁舟。',16,'全唐诗/poet.song.20000.json','["不學鄉人誇駟馬，未饒吾祖泛扁舟。"]'),
('b3cdede1-5bbb-4028-bb16-7cc3391bee6f','句  其一二','范鎮','宋','宋诗','song-poetry','','[]','生平欲報國，所得是知人。',12,'全唐诗/poet.song.20000.json','["生平欲報國，所得是知人。"]'),
('c2e9aae7-fa06-4974-a98a-fdddfb7ddea0','句  其一三','范鎮','宋','宋诗','song-poetry','','[]','案前曾立二賢良。',8,'全唐诗/poet.song.20000.json','["案前曾立二賢良。"]'),
('3cdf03f8-5c7f-4350-8db8-5f3961c97742','句  其一四','范鎮','宋','宋诗','song-poetry','','[]','淡墨題名第一人，孤生何幸繼前塵。',16,'全唐诗/poet.song.20000.json','["淡墨題名第一人，孤生何幸繼前塵。"]'),
('6f134dbd-446d-4187-b21a-258f32a04ee3','句  其一','胡恢','宋','宋诗','song-poetry','','[]','建業關山千里遠，長安風雪一家寒。',16,'全唐诗/poet.song.20000.json','["建業關山千里遠，長安風雪一家寒。"]'),
('bd90c691-2253-4a4c-9199-3c40e0c75de6','句  其二','胡恢','宋','宋诗','song-poetry','','[]','怪鳥啼春不避人。',8,'全唐诗/poet.song.20000.json','["怪鳥啼春不避人。"]'),
('ba41fe33-baa2-460e-9bdd-addf4f1988be','詩一首','韓琦友','宋','宋诗','song-poetry','','[]','是非莫問門前客，得失須憑塞上翁。',32,'全唐诗/poet.song.20000.json','["是非莫問門前客，得失須憑塞上翁。", "引取碧油紅旆去，鄴王臺畔醉春風。"]'),
('01295374-0700-484f-914d-13a31ad5bb7a','耆英會詩','趙丙','宋','宋诗','song-poetry','','[]','新春鼎洛燕英髦，主禮雍容下庶僚。',64,'全唐诗/poet.song.20000.json','["新春鼎洛燕英髦，主禮雍容下庶僚。", "二相比肩官一品，十人華髮事三朝。", "星階並列瞻台曜，尊酒時行挹斗杓。", "東潁庸夫最無狀，也將顔面趁嘉招。"]'),
('57f885d4-2bbe-49a7-be9e-d1d89f9792b3','東池','趙丙','宋','宋诗','song-poetry','','[]','東池風物往來親，興在那能計酒巡。',64,'全唐诗/poet.song.20000.json','["東池風物往來親，興在那能計酒巡。", "塵外留心曾待月，壺中滿眼只知春。", "小詩前後題青竹，幽夢尋常訪白蘋。", "鷗鳥亦知今日恨，主人別得兩朱輪。"]'),
('8a79578d-4e79-498c-a238-d4e4df10adac','藥鐺偈','周貫','宋','宋诗','song-poetry','','[]','頑鈍天教合作鐺，縱生三脚豈能行。',32,'全唐诗/poet.song.20000.json','["頑鈍天教合作鐺，縱生三脚豈能行。", "雖然有耳不聽法，只愛人間戀火坑。"]'),
('6a00e574-958d-4871-aaa9-572e242bfa0b','答人','周貫','宋','宋诗','song-poetry','','[]','八十西山作酒仙，麻鞋軋斷布衣穿。',32,'全唐诗/poet.song.20000.json','["八十西山作酒仙，麻鞋軋斷布衣穿。", "相逢甲子君休問，太極光陰不計年。"]'),
('efbfed34-99aa-4719-9f40-53b0bc34f082','中秋謁李生','周貫','宋','宋诗','song-poetry','','[]','今年中秋夕，來赴去年約。',24,'全唐诗/poet.song.20000.json','["今年中秋夕，來赴去年約。", "不見破鐵鐺，彈指空剝剝。"]'),
('e6ee516f-81ab-4821-81ad-b969239d56b4','題虛白觀','周貫','宋','宋诗','song-poetry','','[]','山郭十餘里，籃輿試初程。',108,'全唐诗/poet.song.20000.json','["山郭十餘里，籃輿試初程。", "山高雲氣重，野曠煙光輕。", "斷石絡樹根，敧崖溜泉聲。", "行行款道宇，一徑掌樣平。", "仙隱記甘羅，觀名取莊生。", "寶藏絢金碧，仙佩飛瑶瓊。", "簷鐸自相語，龕燈弄微明。", "出門境界寬，一笑大江橫。", "蹁躚白羽衣，孤鶴松梢鳴。"]'),
('7dd255e2-7dac-4d9c-9503-6cff965bfc20','句','周貫','宋','宋诗','song-poetry','','[]','彈琴傷指甲，蓋席損髭鬚。',12,'全唐诗/poet.song.20000.json','["彈琴傷指甲，蓋席損髭鬚。"]'),
('364e7e3a-fb76-41fa-949b-562d2ecb9726','季冬立春後有雪呈諸公','白子儀','宋','宋诗','song-poetry','','[]','南畝先曾集素霙，繽紛又拂歲崢嶸。',64,'全唐诗/poet.song.20000.json','["南畝先曾集素霙，繽紛又拂歲崢嶸。", "得無留滯青春色，況復蔽虧紅日明。", "司曆不能分晝刻，勾芒何處待時行。", "豈如直近農耕候，萬耳聽來甘雨聲。"]'),
('a99e5e06-f61f-461b-a2d9-48a0c13b0bbb','次韻和抑之寒食  其一','白子儀','宋','宋诗','song-poetry','','[]','良辰今日正寒食，收拾賓槃宜再三。',64,'全唐诗/poet.song.20000.json','["良辰今日正寒食，收拾賓槃宜再三。", "落筆唱酬宜不倦，把花醒醉亦何慚。", "客來常滿眼無白，人道半癡心所甘。", "幸是禁烟芳節在，接䍦倒載定能堪。"]'),
('4ee5d1ce-a616-47d6-8ace-8030c64a59c2','次韻和抑之寒食  其二','白子儀','宋','宋诗','song-poetry','','[]','餘花茂草引醺酣，禮節休言爵止三。',64,'全唐诗/poet.song.20000.json','["餘花茂草引醺酣，禮節休言爵止三。", "芳歲現逢雖强笑，少年相對但多慚。", "尚驅俗駕終何適，不闢愁門却未甘。", "難把長繩繫春日，若非觴斝更誰堪。"]'),
('36794c4f-1e3c-4d84-8f7a-9a56e2b59aa1','立夏後大熱偶書','白子儀','宋','宋诗','song-poetry','','[]','朱輅初聞建赤旗，綠楊猶囀舊黄鸝。',64,'全唐诗/poet.song.20000.json','["朱輅初聞建赤旗，綠楊猶囀舊黄鸝。", "和風駘蕩無三月，炎氣憑陵又一時。", "飄去餘香花襯屐，覆來濃蔭葉成帷。", "秋光只在前山裏，不日凉襟却共披。"]'),
('993ac665-cfd1-491e-8e8a-05c278066101','端午書事','白子儀','宋','宋诗','song-poetry','','[]','火雲方熾又風薰，誰柅天邊午日輪。',64,'全唐诗/poet.song.20000.json','["火雲方熾又風薰，誰柅天邊午日輪。", "靖郭所生爲貴子，靈均已死作忠臣。", "朝衣耻立雞爭地，賓幄難量狗盜人。", "休語前書憂喜事，浴蘭角黍是良辰。"]'),
('9dcd710c-f2e6-4f0e-946e-b8c22246cd8f','暑伏偶書呈端祖抑之','白子儀','宋','宋诗','song-poetry','','[]','歲時三伏每相承，雨汗居人因不勝。',64,'全唐诗/poet.song.20000.json','["歲時三伏每相承，雨汗居人因不勝。", "況是五絃均長養，何須六幕苦炎蒸。", "中乾願沃仙盤露，上賜堪加凌室冰。", "安得天風破煩溽，釋然羣動返清澄。"]'),
('700fdab7-0bf5-4277-989f-16a166fd5f03','初伏後偶書呈抑之','白子儀','宋','宋诗','song-poetry','','[]','炎天三伏經初伏，火烈石焚疑此時。',64,'全唐诗/poet.song.20000.json','["炎天三伏經初伏，火烈石焚疑此時。", "鈎带已逢瓜入座，扶疎還愛樹成帷。", "良田廣宅富家事，萬壑千巖逋客期。", "顧念宿心俱未適，但慚種種鬢垂絲。"]'),
('df014dc7-b748-40ce-862a-f440896d0fbb','西歸中秋夜宿三泉寄仙之公南','白子儀','宋','宋诗','song-poetry','','[]','日涉征塗信馬前，鴻飛時節幾懷賢。',64,'全唐诗/poet.song.20000.json','["日涉征塗信馬前，鴻飛時節幾懷賢。", "青山漸向故園近，皓月更臨歸驛圓。", "四乘光榮慚太子，一簞窮陋本顔淵。", "江臯上客紅蓮幕，猶荷明恩未棄捐。"]'),
('3ceadf31-6bfe-4b13-a756-b8ca81eec10e','景孫八月十四日惠酒','白子儀','宋','宋诗','song-poetry','','[]','金甕蘭英見貺時，桂輪猶惜一分虧。',64,'全唐诗/poet.song.20000.json','["金甕蘭英見貺時，桂輪猶惜一分虧。", "未知望夜誰同賞，先喜醉鄉今有期。", "飛蓋正懷曹子建，登樓何待庾元規。", "薄帷長簟忘秋興，且洗清塵舉淥巵。"]'),
('0395bd1e-8a0e-4afc-a5dc-0a7d0e76f178','除夜呈抑之','白子儀','宋','宋诗','song-poetry','','[]','逸景運寒燠，良辰徒送迎。',48,'全唐诗/poet.song.20000.json','["逸景運寒燠，良辰徒送迎。", "冬權訖昏暮，歲籥改黎明。", "華髮任疎颯，宿心無變更。", "唯憑一樽酒，時得慰勞生。"]'),
('54204e17-1209-4f34-9979-7ae71482f9c1','耆英會詩二首  其一','劉几','宋','宋诗','song-poetry','','[]','司徒碩德今無比，太尉殊勳固絕倫。',64,'全唐诗/poet.song.20000.json','["司徒碩德今無比，太尉殊勳固絕倫。", "偶以暮年陪盛宴，喜將白髮照青春。", "八公有穢山空著，四皓當衰心且伸。", "元老相望疎迹在，不應此會媿前人。"]'),
('8b4b4da3-3851-49e7-84ea-f439519c744b','耆英會詩二首  其二','劉几','宋','宋诗','song-poetry','','[]','制舉省元推二相，龍頭昔日屬宣猷。',32,'全唐诗/poet.song.20000.json','["制舉省元推二相，龍頭昔日屬宣猷。", "人間盛事并遐算，一席幾盈九百籌。"]'),
('42e9bf3c-9b9a-474a-a200-f46842cf781b','耆英會詩','馮行己','宋','宋诗','song-poetry','','[]','書稱五福壽爲先，有德人方得壽延。',96,'全唐诗/poet.song.20000.json','["書稱五福壽爲先，有德人方得壽延。", "自媿櫟樗非遠器，誰應齒髮亦遐年。", "立身官未三公貴，推老名陪二相賢。", "喜把衰容模梵宇，慚無纖效勒燕然。", "當時遭遇承陶冶，今日光榮預燕筵。", "從此洛城增勝概，又新重作畫圖傳。"]'),
('b7fefab8-f56b-404d-b391-fdae63be1e43','讀元顔二公中興頌碑','陳統','宋','宋诗','song-poetry','','[]','中興碑頌□崢嶸，三百年來蠹不生。',64,'全唐诗/poet.song.20000.json','["中興碑頌□崢嶸，三百年來蠹不生。", "湘水無窮流善價，□山長在聳高名。", "文傳幼婦詞原贍，翰灑崩雲筆力精。", "按部艤舟思訪古，拂塵珍賞眼偏明。"]'),
('55e77c6f-9ffa-42cb-9a31-dc607658789b','經浯溪元次山舊隱','陳統','宋','宋诗','song-poetry','','[]','次山曾此隱，溪壑水清漪。',48,'全唐诗/poet.song.20000.json','["次山曾此隱，溪壑水清漪。", "廢宅羣山合，高名千古垂。", "修篁森釣渚，樂石聳豐碑。", "唯有喬林色，蒼蒼似昔時。"]'),
('22bd3a48-c01d-404d-8aae-952a29f995b4','靈峰院','湛俞','宋','宋诗','song-poetry','','[]','禪林瀟灑倚危巔，稅駕登臨思豁然。',64,'全唐诗/poet.song.20000.json','["禪林瀟灑倚危巔，稅駕登臨思豁然。", "萬里碧光晴望海，一堂幽響夜聽泉。", "寒龕能卧清凉地，古洞雲歸黯淡天。", "好景自嗟吟不盡，擬憑圖畫寄詩仙。"]'),
('308d01d4-3990-4874-97d9-ec85b97015ba','建茶和羅拯韻','湛俞','宋','宋诗','song-poetry','','[]','御茗毓何峰，煙嵐十二重。',24,'全唐诗/poet.song.20000.json','["御茗毓何峰，煙嵐十二重。", "玉泉新吐鳳，金餅五盤龍。"]'),
('65261add-1ec8-4e40-8a28-9668718312bf','句  其一','湛俞','宋','宋诗','song-poetry','','[]','茉莉曉迷瓊檻白，荔枝秋昳綺筵紅。',16,'全唐诗/poet.song.20000.json','["茉莉曉迷瓊檻白，荔枝秋昳綺筵紅。"]'),
('885bc01d-8ac9-445d-830d-6fdae4a2c9fa','句  其二','湛俞','宋','宋诗','song-poetry','','[]','人在蓬壺頹白玉，地連兜率布黄金。',16,'全唐诗/poet.song.20000.json','["人在蓬壺頹白玉，地連兜率布黄金。"]'),
('7378fadc-f03b-4ae8-a651-2fc705ca873b','澄虛亭','徐良佐','宋','宋诗','song-poetry','','[]','一溪水浸羣峰綠，瀲灧長湖澄數曲。',256,'全唐诗/poet.song.20000.json','["一溪水浸羣峰綠，瀲灧長湖澄數曲。", "波光如練映危亭，倚檻最宜凝遠目。", "亭前日日舟人行，千里萬里風帆輕。", "長汀回首望不盡，接天嵐氣何其清。", "隔溪南下乾元路，古松峭拔藏禪宇。", "餘不祠前千尺潭，昔有靈龜曾左顧。", "時遷歲改名獨存，德清從此民俗淳。", "山奇水秀冠南國，是處疑有桃花源。", "過橋稍轉十餘步，家家相向開朱戶。", "大都川澤氣多寒，時時猛點菰蒲雨。", "晚來忽霽涼意新，一片兩片歸巖雲。", "惆悵王維不在世，把筆欲畫今無人。", "老夫歌詩久不作，對此吟情豈宜薄。", "簿書推去試新吟，眼前好景難道著。", "城中美酒斗十千，浦口魚肥賣得錢。", "夜深却羨漁翁樂，醉飽溪心明月眠。"]'),
('18205e36-cf7c-4328-94db-3b2c96f0378a','題招提院靜照堂','王異','宋','宋诗','song-poetry','','[]','珍重慧空營妙隱，標題靜照作佳名。',64,'全唐诗/poet.song.20000.json','["珍重慧空營妙隱，標題靜照作佳名。", "新堂復勝牛車樂，舊閣如拋火宅縈。", "萬慮根源塵外息，一軒景物鑑中明。", "夜深宴坐心虛寂，檀蕙烟微風月清。"]'),
('7d5dd7c8-b560-4780-a13e-abe070201ba1','自然亭','張徵','宋','宋诗','song-poetry','','[]','久雨妨漁復滯樵，自然亭上一逍遥。',64,'全唐诗/poet.song.20000.json','["久雨妨漁復滯樵，自然亭上一逍遥。", "萬緣不自閑中起，百事唯于睡裏消。", "老去自知如蠛蠓，病來誰悟似芭蕉。", "愛名之世忘名客，幸有山林舊市朝。"]'),
('f0d4e8de-2b4c-445b-ad40-016b176a6d68','書故三司副使陳公亞之詩軸後','張徵','宋','宋诗','song-poetry','','[]','破錦囊開玉振金，舍人胸次右丞心。',64,'全唐诗/poet.song.20000.json','["破錦囊開玉振金，舍人胸次右丞心。", "爲時黼藻衣冠藪，與國丹青翰墨林。", "慷慨似誰雙舞劍，風流隨處一歌琴。", "燕貽苦志追先烈，子夏何須論淺深。"]'),
('3c8eadc7-34e6-41b3-acbc-8bf4ad9573d2','書懷呈江陰軍','裴若訥','宋','宋诗','song-poetry','','[]','男兒憂道不憂貧，匣有焦桐篋有文。',32,'全唐诗/poet.song.20000.json','["男兒憂道不憂貧，匣有焦桐篋有文。", "却訪姑蘇臺下隱，滿船明月一溪雲。"]'),
('8cc63ee0-f3f5-4559-b693-30eeeaadcf78','江陰絕句','裴若訥','宋','宋诗','song-poetry','','[]','紫蓴江上是吾家，一葉扁舟一釣車。',32,'全唐诗/poet.song.20000.json','["紫蓴江上是吾家，一葉扁舟一釣車。", "何必陶公種魚法，雨汀烟渚盡生涯。"]'),
('95e2e9bf-c37b-42ea-8068-94772079c140','句','裴若訥','宋','宋诗','song-poetry','','[]','漁人借問去何處，白酒香甜紫蟹肥。',16,'全唐诗/poet.song.20000.json','["漁人借問去何處，白酒香甜紫蟹肥。"]'),
('28bdfa27-c896-4003-9987-a0a5c3569ce0','題曲水閣','邵必','宋','宋诗','song-poetry','','[]','鑿石得春渠，波環閣勢孤。',96,'全唐诗/poet.song.20000.json','["鑿石得春渠，波環閣勢孤。", "新痕漲微雨，遠碧注平湖。", "士俗山陰舊，風光洛曲殊。", "回眸見危嶺，憑檻有驚鳧。", "墜蕊浮旋瀨，疎篁蔭疊櫨。", "人閒多拾翠，魚樂半依蒲。", "河朔誰觴友，沂津昔詠儒。", "遺芬知未泯，遊蓋此爲娛。"]'),
('594bb257-92d7-4d00-8a86-5516df4c622c','送程給事知越州','邵必','宋','宋诗','song-poetry','','[]','我嘗淮上送君行，前日郎官此日卿。',64,'全唐诗/poet.song.20000.json','["我嘗淮上送君行，前日郎官此日卿。", "一道清風新使節，萬家和氣舊民情。", "西山藥味迎秋熟，同浦波光照物明。", "佳景多才雅相值，高吟應未負平生。"]'),
('a89885eb-647e-455d-80da-c9909c7c9b03','題錢公輔眾樂亭  其一','邵必','宋','宋诗','song-poetry','','[]','海邊民物鮮歡娛，太守經營與眾俱。',64,'全唐诗/poet.song.20000.json','["海邊民物鮮歡娛，太守經營與眾俱。", "園圃新陰多杞柳，池塘生意足魚蒲。", "長空不礙高飛鵠，淺水兼容短脛鳧。", "此樂有誰知我趣，歸來紅旆日西晡。"]'),
('93f76ee2-fe80-4f47-9c49-232b180ac3aa','題錢公輔眾樂亭  其二','邵必','宋','宋诗','song-poetry','','[]','城外千帆海舶風，城中居市苦憧憧。',64,'全唐诗/poet.song.20000.json','["城外千帆海舶風，城中居市苦憧憧。", "幾生佳景爲民老，一日賢侯與我同。", "道上槐陰連帟翠，水邊人面照花紅。", "寄言樂有時還盡，徒見甘棠憶召公。"]'),
('ddbe0256-f8d0-42c4-95e1-608ab95c22ca','句','邵必','宋','宋诗','song-poetry','','[]','素壁鑱詩尚未泥。',8,'全唐诗/poet.song.20000.json','["素壁鑱詩尚未泥。"]'),
('32b90ff0-2fc4-4f40-bfe5-98c175eddadb','和陳述古仙居巖老堂詩','崔黄臣','宋','宋诗','song-poetry','','[]','牀頭數卷書，足以樂樵漁。',48,'全唐诗/poet.song.20000.json','["牀頭數卷書，足以樂樵漁。", "眾謂衣冠傳，自同巖谷居。", "潛心富仁智，育德審盈虛。", "刺史如相訪，淵明有舊廬。"]'),
('72364e75-5a38-4dca-8999-1410c3a6e12a','鼓角山','吳世延','宋','宋诗','song-poetry','','[]','黎明騎馬出城閫，鼓角山前訪故人。',32,'全唐诗/poet.song.20000.json','["黎明騎馬出城閫，鼓角山前訪故人。", "白水一陂浮鶴背，青田千里疊虬鱗。"]'),
('eb3b6d38-5cab-4f97-a9d6-f940c48f36be','和孔司封題蓬萊閣','沈紳','宋','宋诗','song-poetry','','[]','三山對峙海中央，高閣新題紫翠房。',64,'全唐诗/poet.song.20000.json','["三山對峙海中央，高閣新題紫翠房。", "玉鉉相君頒瑞地，金貂仙子挂冠鄉。", "雲隨步武鼇頭穩，風滿中裾鶴背涼。", "吸盡流霞不知醉，直須乘月據胡牀。"]'),
('b6493467-b877-4153-956e-99b8ffc7cdbf','送程給事知越州  其一','沈紳','宋','宋诗','song-poetry','','[]','天街雨歇槐飛花，鎮東新府腰青緺。',240,'全唐诗/poet.song.20000.json','["天街雨歇槐飛花，鎮東新府腰青緺。", "曉排閶闔辭玉皇，肅齋先過文德衙。", "赤墀再拜升東塗，赭袍前對明朱霞。", "公行早爲上所器，恩言褒寵何光華。", "翰林紫微文章公，歡然惜去宴頭加。", "東堂西府爭落筆，詩艷萬丈靈星槎。", "行周四方心尚壯，勁氣晚節開胡沙。", "東南便鄉久思歸，翠巖白水得地嘉。", "秋風鱸魚正鮮肥，旗鼓滿城看過家。", "吾鄉禹功有餘烈，舊俗質厚民不譁。", "比年天時苦荒札，大資公已勤櫛爬。", "行當下車鎮清和，仁賢相繼自足夸。", "蓬萊到日望三山，海波浸眼窮天涯。", "酒濃詩豪真樂都，莫爲畫船留若耶。", "公才甚高宜大用，歸來禁鼓聽新撾。"]'),
('bb953c66-eabd-425b-8db7-2a2c8133e857','送程給事知越州  其二','沈紳','宋','宋诗','song-poetry','','[]','千兵督府占樓居，刻鎖君門一夕虛。',64,'全唐诗/poet.song.20000.json','["千兵督府占樓居，刻鎖君門一夕虛。", "爲厭承明新遞直，却探禹穴舊藏書。", "家頭鼓角聞初近，座上湖山畫不如。", "一道政清貔虎肅，四星密拱紫微車。"]'),
('19d5cfb3-5926-4b75-a873-8a35d7c498b2','題寒亭山壁','沈紳','宋','宋诗','song-poetry','','[]','元子此始來，大暑生凍骨。',60,'全唐诗/poet.song.20000.json','["元子此始來，大暑生凍骨。", "名亭陽崖角，高文猶仿佛。", "我行冰雪天，噤語揖風物。", "銀江走碧漲，九疑抱雲窟。", "它年名不磨，至者戒無忽。"]'),
('3ea818f0-6e87-4514-9d29-99663d3f64bc','送程給事知越州','褚珵','宋','宋诗','song-poetry','','[]','元稹唐朝輔相材，全家曾住小蓬萊。',96,'全唐诗/poet.song.20000.json','["元稹唐朝輔相材，全家曾住小蓬萊。", "公今得請爲藩去，事異當時謫宦來。", "雅意未應亡魏闕，歸心且喜過蘇臺。", "茂林修竹仁風動，紫蟹黄柑宴席開。", "聽訟初承召公後，遞詩須繼樂天才。", "政成不待三年報，入告謀猷豈晚哉。"]'),
('a5afd529-7394-482b-a152-e0037bd35beb','謝王介甫','薛利和','宋','宋诗','song-poetry','','[]','一路生靈陡頓貧，廟堂康濟豈無人。',32,'全唐诗/poet.song.20000.json','["一路生靈陡頓貧，廟堂康濟豈無人。", "君王若問茶租日，請把茶租乞與人。"]'),
('c36206f1-2f92-45b5-86c7-029cb0ff973b','文惠公獨遊亭','薛利和','宋','宋诗','song-poetry','','[]','軒檻前臨一水湄，此亭誰見獨遊時。',64,'全唐诗/poet.song.20000.json','["軒檻前臨一水湄，此亭誰見獨遊時。", "春風坐處無人伴，秋月行來有影隨。", "文酒等閑辜會友，溪山贏得自裁詩。", "城東老屋今仍舊，當日高蹤孰可追。"]'),
('5a59f75a-8c98-43d8-8e05-197bc9bd874f','韓亭','薛利和','宋','宋诗','song-poetry','','[]','嶺脊孤亭勢倚雲，前臨城邑後荒村。',64,'全唐诗/poet.song.20000.json','["嶺脊孤亭勢倚雲，前臨城邑後荒村。", "八千里外人歸久，四百年間木尚存。", "直北惡溪泉滾滾，落南瘴海霧昏昏。", "先生偉績傳青史，萬古民懷逐鰐恩。"]'),
('cab0dc64-9737-4ce5-9dc6-51789be1b4ca','西湖亭','薛利和','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f", "\u897f\u6e56"]','一泓泉色漲漪漣，竊號西湖幾百年。',64,'全唐诗/poet.song.20000.json','["一泓泉色漲漪漣，竊號西湖幾百年。", "泛出芰荷錢萬疊，洗開楊柳眼三眠。", "雪鷗卧聽禪僧磬，錦鯉行驚釣客船。", "若比錢塘江上景，欠他十里好風煙。"]'),
('a9c707ae-300d-422a-bdc9-a6360969ecbe','句','薛利和','宋','宋诗','song-poetry','','[]','傍人笑我無藍袖，今日朱衣嶺上歸。',16,'全唐诗/poet.song.20000.json','["傍人笑我無藍袖，今日朱衣嶺上歸。"]'),
('a72d967f-3684-4f8b-8128-fcbc2e5519ba','遊勝法寺兼簡深公','陸綰','宋','宋诗','song-poetry','','[]','道旁有古寺，巋然聳梅林。',144,'全唐诗/poet.song.20000.json','["道旁有古寺，巋然聳梅林。", "邇來衣褐徒，包禍歲月深。", "埋伏狡兔穴，嘯聚惡木陰。", "安得智慧劍，力斬奸邪心。", "吾師曹溪流，所在人依欽。", "郡邑兩交疏，來發雲雷音。", "初如碎瓦礫，乃見真球琳。", "瞽者破其瞽，瘖者破其瘖。", "有若鸞鳳巢，無復鴟鴞禽。", "嗟予困吏役，海岸宜投簪。", "扁舟扣禪戶，清風滿衣襟。", "高論松桂間，爲師揮玉琴。"]'),
('f4069ce5-a396-4ec1-9413-0e423976f049','題招提院靜照堂','聞人安道','宋','宋诗','song-poetry','','[]','清虛結宇卜新居，寂靜標名欲性純。',64,'全唐诗/poet.song.20000.json','["清虛結宇卜新居，寂靜標名欲性純。", "直向萬緣無斷處，應爲一念不生人。", "風幡震動殊非鬧，水月澄明未是真。", "宴坐經行惟此地，箇中消息與誰親。"]'),
('247274ab-f906-41d1-a51c-46c5b2ecb0a1','句','聞人安道','宋','宋诗','song-poetry','','[]','秋浦澄明郡境清，天然巖岫作南屏。',16,'全唐诗/poet.song.20000.json','["秋浦澄明郡境清，天然巖岫作南屏。"]'),
('24996c07-ba73-4cb9-845d-86447e5c79b9','游碧落洞','李京','宋','宋诗','song-poetry','','[]','賞景塵囂外，放懷岑寂中。',48,'全唐诗/poet.song.20000.json','["賞景塵囂外，放懷岑寂中。", "寒崖映流水，古檜生清風。", "坐有琴酒樂，路非車馬通。", "何當遂初志，來此期芝翁。"]'),
('6ccedbc0-03e5-4d6c-91c1-0bae6cdc2087','刻浯溪石上','柳應辰','宋','宋诗','song-poetry','','[]','浯溪石上大江邊，心記閑將此地鎸。',32,'全唐诗/poet.song.20000.json','["浯溪石上大江邊，心記閑將此地鎸。", "自有後來人屈指，四千六百甲寅年。"]'),
('71ef5be7-1f7c-486c-8b2f-e8da7324c09b','浯溪','柳應辰','宋','宋诗','song-poetry','','[]','不能歌，不能吟，瀟湘江頭千古心。',16,'全唐诗/poet.song.20000.json','["不能歌，不能吟，瀟湘江頭千古心。"]'),
('ced7297a-5d46-4d5b-aa62-aace5cc2638c','石角山','柳應辰','宋','宋诗','song-poetry','','[]','□□□□山幾重，與君吟望意無窮。',64,'全唐诗/poet.song.20000.json','["□□□□山幾重，與君吟望意無窮。", "當時共指白雲外，今日獨行青嶂中。", "案牘暫休聊自適，籃輿乘隙若爲同。", "九嶷秋約心先到，巖月斕斑桂子紅。"]'),
('3d049bcf-a61b-476f-8cf4-4aa01748e0a1','范陽同年示及零陵三題率然爲答甚愧妍唱 火星巖','俞希孟','宋','宋诗','song-poetry','','[]','信美真靈宅，呀然洞府通。',48,'全唐诗/poet.song.20000.json','["信美真靈宅，呀然洞府通。", "皇家尊盛德，南夏享陰功。", "廟貌鄰炎帝，峯名比祝融。", "遊人思所謂，無獨愛嵌空。"]'),
('50186c4b-e9be-45b8-94b6-335c38e36486','范陽同年示及零陵三題率然爲答甚愧妍唱 朝陽巖','俞希孟','宋','宋诗','song-poetry','','[]','旭日多橫照，幽巖得粹華。',48,'全唐诗/poet.song.20000.json','["旭日多橫照，幽巖得粹華。", "次山名此地，瀟水匯其涯。", "峭壁生雲葉，危根濺浪花。", "終携羨門侶，晨坐嚥東霞。"]'),
('c3e9f2be-9a9b-4aad-b975-58487ea72404','范陽同年示及零陵三題率然爲答甚愧妍唱 澹山巖','俞希孟','宋','宋诗','song-poetry','','[]','巖腹潛雲構，清涼十畝間。',48,'全唐诗/poet.song.20000.json','["巖腹潛雲構，清涼十畝間。", "天留盤古穴，人識寶陁山。", "壞像煙嵐濕，高僧歲月閑。", "聖時無遁客，佳境付禪關。"]'),
('04e26491-4807-4f6c-bfc8-5681e035c7c9','句','俞希孟','宋','宋诗','song-poetry','','[]','若把東閩比西洛，可將陳紫敵姚黄。',16,'全唐诗/poet.song.20000.json','["若把東閩比西洛，可將陳紫敵姚黄。"]'),
('135b7e25-63ed-4966-abd1-08deef7c8cd8','三巖詩 火星巖','盧臧','宋','宋诗','song-poetry','','[]','巖扃瞰羣阜，疇昔道宮隣。',48,'全唐诗/poet.song.20000.json','["巖扃瞰羣阜，疇昔道宮隣。", "熒惑標名舊，浮屠締構新。", "石寒長滴乳，池潤不生塵。", "吾到期深入，虬蛇勿噬人。"]'),
('7f465f8d-c158-4d02-8b29-3d5f9e5c9521','三巖詩 朝陽巖','盧臧','宋','宋诗','song-poetry','','[]','瀟湘峻岸傍，巖穴號朝陽。',48,'全唐诗/poet.song.20000.json','["瀟湘峻岸傍，巖穴號朝陽。", "全會江雲勢，先分海日光。", "高深驚險易，冬夏返溫涼。", "誰肯棄塵世，探窮仙者鄉。"]'),
('c40f5a0b-acee-4d03-8a79-2ac392c94867','三巖詩 澹山巖','盧臧','宋','宋诗','song-poetry','','[]','誰開仙窟宅，非與眾巖儔。',48,'全唐诗/poet.song.20000.json','["誰開仙窟宅，非與眾巖儔。", "樹響晴翻雨，嵐涼夏變秋。", "禽靈啼復斷，雲怪吐還收。", "深羨羣僧住，嗟予莫少留。"]'),
('f7dd6eaf-3fe6-4ed1-a35a-cfff73488b2b','和','沈遜','宋','宋诗','song-poetry','','[]','一自曾經別，於今歎索居。',72,'全唐诗/poet.song.20000.json','["一自曾經別，於今歎索居。", "善交思柳惠，多病是相如。", "官下頻無況，天涯每得書。", "舊懷長惋歎，此會合躊躇。", "曉露生蘭苑，秋風動鱠魚。", "蕭然林野性，與世轉爲疏。"]'),
('18d0fc99-0bff-4c5f-b524-b5ac4d156c00','和趙閱道遊海雲山','霍交','宋','宋诗','song-poetry','','[]','山深藏古寺，旁枕舊方池。',48,'全唐诗/poet.song.20000.json','["山深藏古寺，旁枕舊方池。", "鼓響揭雲外，石探從水涯。", "使旌遊不倦，瑞麥獻相隨。", "事簡民同樂，歸心莫競馳。"]'),
('0efab979-8533-4574-8f24-486b25af2f42','和趙抃賦新繁周表權如詔亭詩','白贄','宋','宋诗','song-poetry','','[]','亭名詔語密相沿，須信從來教義全。',64,'全唐诗/poet.song.20000.json','["亭名詔語密相沿，須信從來教義全。", "肯構嘗探詩禮業，出綸特表父師賢。", "早安素履知文富，晚服朱衣稱賞筵。", "不是韋家專講學，豈聞旛戟到門前。"]'),
('8b28e9b0-0e55-4f58-a676-cb3dfe1c4060','游琅邪寺','周圻','宋','宋诗','song-poetry','','[]','杉松夾道綠森森，古寺尤欣結客尋。',64,'全唐诗/poet.song.20000.json','["杉松夾道綠森森，古寺尤欣結客尋。", "殿閣長時異香滿，亭臺佳處白雲深。", "清泉迸石落寒谷，幽鳥避人穿茂林。", "緩步閑看舊題詠，盆池蓮葉幾浮沈。"]'),
('74c9d246-e328-49fa-a3bb-7a23d1ad66c1','香山寺','韓綜','宋','宋诗','song-poetry','','[]','信馬盤桓上碧穹，雲埋松翠梵王宮。',32,'全唐诗/poet.song.20000.json','["信馬盤桓上碧穹，雲埋松翠梵王宮。", "老僧細說禪機話，深會菩提色即空。"]'),
('18ff2aff-009b-45aa-93d2-55eb51880e9b','三賢詠','李覯','宋','宋诗','song-poetry','','[]','魯連誓蹈海，夷齊甘采薇。',48,'全唐诗/poet.song.20000.json','["魯連誓蹈海，夷齊甘采薇。", "秦王不得帝，周武終見非。", "輕死議萬乘，强哉三布衣。", "凡人期貧賤，貧賤豈易欺。"]'),
('8e380c1d-2126-4870-9a28-db2afd6b6712','和蘇著作麻姑十詠 魯公碑 其一','李覯','宋','宋诗','song-poetry','','[]','他人工字書，美好若婦女。',96,'全唐诗/poet.song.20000.json','["他人工字書，美好若婦女。", "猗嗟顔太師，赳赳丈夫武。", "麻姑有遺碑，歲月亦已古。", "硬筆可破石，鐫者疑虛語。", "驚龍索雷鬭，口唾天下雨。", "怒虎突圍出，不畏千强弩。", "有海珠易求，有山玉易取。", "唯恐此碑壞，此書難再靚。"]'),
('9673512b-c1ca-4b79-8a02-391aa7cbcbbe','和蘇著作麻姑十詠 魯公碑 其二','李覯','宋','宋诗','song-poetry','','[]','收藏在天府。',18,'全唐诗/poet.song.20000.json','["收藏在天府。", "自非大祭時，莫教凡眼覷。"]'),
('9d4c7128-ac77-4fea-ac92-bf8142811a8b','和蘇著作麻姑十詠 七星杉','李覯','宋','宋诗','song-poetry','','[]','五行興萬類，有象皆在天。',96,'全唐诗/poet.song.20000.json','["五行興萬類，有象皆在天。", "如何彼杉樹，反更侔星躔。", "予思古昔意，欲媚茲山巔。", "草木尚有斗，人物誰非仙。", "栽培自何代，衰老今多年。", "大旱不減翠，涉春無益鮮。", "生當好世界，過盡閑雲煙。", "房心欲布政，柱石安可捐。"]'),
('5b2de4d2-5eb3-47b5-a418-005c0d7375e0','和蘇著作麻姑十詠 煉丹井','李覯','宋','宋诗','song-poetry','','[]','丹竈久已毀，井泉空獨存。',96,'全唐诗/poet.song.20000.json','["丹竈久已毀，井泉空獨存。", "此地非常地，今人非昔人。", "我願刀圭藥，輕舉朝明宸。", "一言洗天日，萬物歸陽春。", "羣仙誰嫉妬，使我身漂淪。", "俯視廢井水，欲飲礙荆榛。", "徘徊片雲下，泣涕霑衣巾。", "少壯幾何時，且醉樽中醇。"]'),
('707c07e2-0d34-49b1-8b17-f160168a3666','和蘇著作麻姑十詠 玳瑁石','李覯','宋','宋诗','song-poetry','','[]','前有縣大夫，取此石爲器。',120,'全唐诗/poet.song.20000.json','["前有縣大夫，取此石爲器。", "囂然夸謂予，材與工俱美。", "如何爾鄉人，器用曾莫備。", "無乃居荒陬，俗鄙不喜事。", "答云此石堅，攻磨動時歲。", "官用錢出民，民用錢出己。", "出民官不知，喜事誠可貴。", "出己乃傷財，誰能不惜費。", "大夫聞此言，如有所忿戾。", "今君倡是詩，敢以報嘉惠。"]'),
('8402355f-3bae-41c3-8683-87c0d5ddd88e','和蘇著作麻姑十詠 秦人峰','李覯','宋','宋诗','song-poetry','','[]','秦法雖甚苛，秦吏若猶拙。',96,'全唐诗/poet.song.20000.json','["秦法雖甚苛，秦吏若猶拙。", "山林不數里，俾爾逃得脫。", "予觀後世事，政役火烈烈。", "苟非爲鬼神，何計避羈紲。", "師皇今在御，百事咸均節。", "常披詔書意，苦念生財竭。", "誰能將順者，所望在賢哲。", "無使峰中人，笑我民屠裂。"]'),
('cc1e5756-4b80-495f-9572-2872e71fe018','和蘇著作麻姑十詠 流杯池','李覯','宋','宋诗','song-poetry','','[]','幽居久不樂，心死如濕灰。',144,'全唐诗/poet.song.20000.json','["幽居久不樂，心死如濕灰。", "聞言山有池，仙客曾流杯。", "披衫向西坐，欲望無崇臺。", "何當命遊宴，盡聚不羈才。", "顧恐狹隘地，未足開吾懷。", "仰手斸河漢，决向天南來。", "移舟復轉嶽，壅遏成環迴。", "橫持北斗柄，量盡酒星醅。", "箕踞接下流，一歃空千罍。", "八風助吟倡，萬怪供嘲諧。", "醉來散髮卧，蠅聲視霆雷。", "冷笑勢利子，茫茫塵土堆。"]'),
('44c6fc0d-8f39-4bfe-a95f-aa9e6daf8938','和蘇著作麻姑十詠 碧蓮池','李覯','宋','宋诗','song-poetry','','[]','碧蓮何歲開，我時不得見。',48,'全唐诗/poet.song.20000.json','["碧蓮何歲開，我時不得見。", "于今到池上，只有紅蓮綻。", "紅蓮非醜惡，物以多爲賤。", "阿蠻雖解舞，不見真妃面。"]'),
('a5b4942b-d84b-4bac-9e7c-402ec7293613','和蘇著作麻姑十詠 虎跑泉','李覯','宋','宋诗','song-poetry','','[]','虎跑本何爲，彼將對以臆。',96,'全唐诗/poet.song.20000.json','["虎跑本何爲，彼將對以臆。", "有如大丈夫，卓爾抱剛直。", "盜泉既不飲，譖人亦不食。", "山中小禽獸，何足勞捉搦。", "勇氣無所泄，爪地成遺迹。", "地神嘉乃誠，水源如開闢。", "尋常竊六畜，夜傍人牆壁。", "是與豺狼同，聞此宜慙色。"]'),
('92b769de-9d57-45c4-b2cc-b5bda678047b','和蘇著作麻姑十詠 丹霞洞','李覯','宋','宋诗','song-poetry','','[]','山西十數里，乃是丹霞洞。',96,'全唐诗/poet.song.20000.json','["山西十數里，乃是丹霞洞。", "直上窮雲霓，中寬入罌甕。", "紅塵生不識，明月手可捧。", "人家千里庭，泉源六月凍。", "風雨氣勢惡，草木精神竦。", "靈物少形見，仙官何職貢。", "欲緣易厭倦，世事足愁痛。", "寄語松上鶴，他年期一控。"]'),
('78f687f1-4965-4bbe-832b-b1398a43f428','和蘇著作麻姑十詠 葛仙壇','李覯','宋','宋诗','song-poetry','','[]','仙翁猶在時，壇上何設施。',48,'全唐诗/poet.song.20000.json','["仙翁猶在時，壇上何設施。", "仙翁一去後，夢草空離離。", "下士固大笑，言者多不知。", "嗟嗟天壤內，共是枯魚池。"]'),
('eddf8f20-e7f7-48f6-ad9f-ff166caf3f08','穫稻','李覯','宋','宋诗','song-poetry','','[]','朝陽過山來，下田猶露濕。',48,'全唐诗/poet.song.20000.json','["朝陽過山來，下田猶露濕。", "餉婦念兒啼，逢人不敢立。", "表黄先後收，斷折傴僂拾。", "鳥鼠滿官倉，于今又租入。"]'),
('100fc8cc-4868-4a40-b698-060316193262','哀老婦','李覯','宋','宋诗','song-poetry','','[]','里中一老婦，行行啼路隅。',288,'全唐诗/poet.song.20000.json','["里中一老婦，行行啼路隅。", "自悼未亡人，暮年從二夫。", "寡時十八九，嫁時六十餘。", "昔日遺腹兌，今茲垂白鬢。", "子豈不欲養，母豈不懷居。", "繇役及下戶，財盡無所輸。", "異籍幸可免，嫁母乃良圖。", "牽車送出門，急若盜賊驅。", "兒孫孫有婦，小大攀且呼。", "回頭與永訣，欲死無刑誅。", "我時聞此言，爲之長嘆嗚。", "天民固有窮，鰥寡實其徒。", "仁政先四者，著在孟軻書。", "吾君務復古，旦旦師黄虞。", "赦書求節婦，許與旌門閭。", "繄爾愚婦人，豈曰禮所拘。", "蓬茨四十年，不知形影孤。", "州縣莫能察，詔旨成徒虛。", "而况賦役間，羣小所同趨。", "姦欺至骨髓，公利未錙銖。", "良田歲歲賣，存者唯萊汙。", "兄弟欲離散，母子因變渝。", "天地豈非大，曾不容爾軀。", "嗟嗟孝治王，早晚能聞諸。"]'),
('3d3236a9-162e-495e-90c4-e28079f21063','寄懷三首  其一','李覯','宋','宋诗','song-poetry','','[]','鳥獸死有用，羽角筋革齒。',72,'全唐诗/poet.song.20000.json','["鳥獸死有用，羽角筋革齒。", "輦輓入工師，飾作軍國器。", "玉食白如瓠，暝目已腐穢。", "生者不敢留，埋藏與螻蟻。", "百年富貴身，孰若鳥獸類。", "唯有令名人，終古如不死。"]'),
('fd2941f4-e605-455d-a711-e3ded0c9c054','寄懷三首  其二','李覯','宋','宋诗','song-poetry','','[]','根生但爲松，翼飛但爲鳳。',48,'全唐诗/poet.song.20000.json','["根生但爲松，翼飛但爲鳳。", "王侯尚可輕，道義本來重。", "癡兒似婢妾，寸步矜恩寵。", "傍人忍笑時，佯把衣袪弄。"]'),
('6739d7a8-adaa-4f54-8968-35e8ef91fbc9','寄懷三首  其三','李覯','宋','宋诗','song-poetry','','[]','齪齪復齪齪，淺謀同燕雀。',48,'全唐诗/poet.song.20000.json','["齪齪復齪齪，淺謀同燕雀。", "不思明日憂，但取今日樂。", "俗儒抱書卷，未去眼中膜。", "誰將古人淚，更爲今人落。"]'),
('81e7e813-d045-4fba-a2fd-c04c1288d24c','避暑','李覯','宋','宋诗','song-poetry','','[]','富貴責且重，慙耻心如何。',96,'全唐诗/poet.song.20000.json','["富貴責且重，慙耻心如何。", "貧賤事易了，飽煖幸已多。", "大熱火天下，虛堂枕山阿。", "拔俗嫌人影，考古分賢科。", "潄冷齒雙噤，飲香顔半酡。", "一跣或移日，遇狂還自歌。", "去就各有志，彼此無相訶。", "原憲豈嘗病，賜也徒來過。"]'),
('a8285619-17c7-40b7-b853-f382846de121','喜雨','李覯','宋','宋诗','song-poetry','','[]','人皆喜膏澤，我獨憂豐年。',96,'全唐诗/poet.song.20000.json','["人皆喜膏澤，我獨憂豐年。", "歲凶已賤糴，年豐安得錢。", "賦役忽驚駭，倉廩甘棄捐。", "銖銅苟可換，富賈寧我憐。", "歸來官事了，相弔柴門邊。", "農夫未盡死，穀價應常然。", "王心幸仁聖，分職當忠賢。", "謂穀賤爲美，咄咄無欺天。"]'),
('ab2ff0df-fb75-46c5-b7f0-8a2e7d32025d','送上官直','李覯','宋','宋诗','song-poetry','','[]','失意多怨尤，有誰能自知。',48,'全唐诗/poet.song.20000.json','["失意多怨尤，有誰能自知。", "遊人務乞丐，之子唯求師。", "成名在積善，干錄先闕疑。", "根本苟深固，春風諒無私。"]'),
('9451394d-be42-4e5f-ae1e-76057ee4bf41','題昱師房三笑圖','李覯','宋','宋诗','song-poetry','','[]','高僧不出院，屏畫三笑圖。',56,'全唐诗/poet.song.20000.json','["高僧不出院，屏畫三笑圖。", "客子倦遊者，欲去復踟躕。", "古人骨朽不可追，今人相見如古時。", "人間觸事入吾笑，何必門前有虎谿。"]'),
('5daaa98f-159f-4a77-91ed-888f717b22d9','寄祖祕丞','李覯','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u957f\u6c5f"]','我本山田人，好尚與衆異。',288,'全唐诗/poet.song.20000.json','["我本山田人，好尚與衆異。", "平生重交遊，所得國無幾。", "昨者應茂才，西行覷朝美。", "時當慶曆初，選舉實多士。", "茫茫帝王州，栖栖遠行子。", "携錢賃破屋，乞火蒸陳米。", "鞍馬到即賣，僮僕癡難使。", "有時造公卿，努力向廛市。", "數步則一歇，長吁乃能起。", "衣冠信質野，言語欠婉媚。", "閽人顧之笑，將命見而避。", "往往得所請，蹌蹌向前跪。", "何能剖懷抱，浪自慕尊貴。", "貴人如天神，喘息生雲氣。", "野夫等麋鹿，芻豢非所冀。", "歸來坐空窗，惆悵夕不睡。", "塵埃滿鬚鬢，臭惡入口鼻。", "業已辭吾親，中道豈可廢。", "僶俛待報聞，愁憂遂經歲。", "二年正月晦，閑房適假寐。", "有奴來啄門，手披擇之刺。", "承命驚下牀，赤脚誤穿履。", "從來未識面，只是聞高第。", "名顯宦且達，見我當何爲。"]'),
('6d934b88-6d61-4349-8a93-0c819d784178','名男曰參魯以詩喻之','李覯','宋','宋诗','song-poetry','','[]','孔門有高弟，曾子以孝著。',216,'全唐诗/poet.song.20000.json','["孔門有高弟，曾子以孝著。", "求諸聖人言，尚曰參也魯。", "才敏誰不願，顧恐難荷負。", "苟無德將之，何益於父母。", "昔如吳起者，善兵惡孫武。", "齧臂游諸侯，親喪哀不舉。", "楊彪有子脩，器能頗可取。", "一旦以罪誅，舐犢徒虛語。", "吾生本薄祜，略無兄弟助。", "及汝又一身，不絕如線縷。", "祖母唯汝愛，無異所生乳。", "寧止託祭祀，亦欲興門戶。", "伎倆勿求名，適時乃有補。", "計盧勿尚巧，合義乃可處。", "持重尚寡過，摧剛庶無懼。", "內以保家族，外以揚名譽。", "高山在所仰，今人豈殊古。", "參魯爲汝名，其字曰孝孺。"]'),
('b2907ddf-584e-4908-bff8-8d23b8599fe5','女色無定美贈卿材','李覯','宋','宋诗','song-poetry','','[]','女色無定美，寵至美則多。',288,'全唐诗/poet.song.20000.json','["女色無定美，寵至美則多。", "士才無定稱，用顯稱已過。", "長安小家子，粲粲秋池荷。", "性慧不覺耻，母憐不如訶。", "出戶一囊麝，見人雙眼波。", "情動笑難止，語嬌音屢訛。", "都人口如沸，觀者踵相摩。", "因緣幸充選，恩澤成偏頗。", "少費萬金珠，一呼千綺羅。", "佯愁慘白日，猛唾傾天河。", "東鄰有賢女，春綠涵脩蛾。", "花艷不栽翦，玉光無切磋。", "自小固聞禮，藏頭豈知他。", "親戚尚未見，媒官當奈何。", "過時誰訪問，生世就蹉跎。", "豈不有配偶，市里或山阿。", "豈不有奉養，舂饎與機梭。", "列女不得傳，樂府無人歌。", "容華日衰落，涕泣坐滂沱。", "富貴易脩飾，貧賤多笑呵。", "柳下無仲尼，小官終滅磨。", "進退在勇决，遲疑兩皆蹉。", "退當事奇偉，夙駕追雄軻。", "進當取勢位，健筆爲干戈。"]'),
('cfd3faa8-5d28-44a3-8c93-c3d217ee9706','江亭醉後','李覯','宋','宋诗','song-poetry','','[]','平生尚倜儻，壯大苦摧折。',192,'全唐诗/poet.song.20000.json','["平生尚倜儻，壯大苦摧折。", "主人能結納，佳境爲鋪設。", "渺㵿東江來，谽谺暮雲裂。", "倡女稍多藝，市酒且供啜。", "俠氣復何聊，心朋幸相悅。", "解冠從放蕩，大呼誰輓掣。", "咄哉千里足，嗟呼三寸舌。", "海物喚龍取，天葩令鬼折。", "艷唱聲非雅，戲談理當譎。", "帷房笑私昵，閭巷嘲瑣屑。", "更鼓莫催睡，夜風讒去熱。", "俗士鮮大志，于今重小節。", "內行豕在泥，外貌犬伏紲。", "吾儕古豪傑，方寸浴日月。", "被謗肯自疑，爲歡顧猶拙。", "放飯彼不慙，使我無齒决。"]'),
('3d165cdd-211f-410a-932e-5cdfadff8f82','寄章友直','李覯','宋','宋诗','song-poetry','','[]','人生何足貴，貴在天資秀。',240,'全唐诗/poet.song.20000.json','["人生何足貴，貴在天資秀。", "譬如沙石間，金玉豈常有。", "有才不善用，多爲淫邪誘。", "嗟哉棟梁材，往往厄樵手。", "章子吾不識，美在衆人口。", "如何材藝多，四十無所守。", "所守者何爲，非貴亦非富。", "古今聖與賢，歷歷垂星斗。", "景行苟有成，進退無一繆。", "不能功天下，尚可名身後。", "百年隨飄風，白髪勇未鬭。", "良時且不反，飲恨唯尸柩。", "無謂學已足，大海難掬漱。", "無謂過可文，希珍尚磨垢。", "智者當自知，既往誠何咎。", "西子蒙不潔，見者掩鼻走。", "惡人幸齋戒，上帝必孚祐。", "相如竊妻逃，犢鼻從沽酒。", "一朝賦上林，在漢爲稱首。", "努力念前哲，吾言非子詬。"]'),
('4a13a730-93e3-42c2-82d7-07b25a040704','中春苦雨書懷','李覯','宋','宋诗','song-poetry','','[]','春秋書大雨，三日已爲霖。',240,'全唐诗/poet.song.20000.json','["春秋書大雨，三日已爲霖。", "如何方春時，終月常積陰。", "淙空若泉瀉，盪地成淵深。", "曾無晝夜別，顧恐山嶽沈。", "疑是天上河，底漏不可禁。", "傍無女媧石，欲補難爲針。", "又疑坎宮水，陽曜所不臨。", "何等大鬼物，戲把北斗斟。", "誰籠三足烏，冷卧空桑林。", "勾芒失權柄，羞耻啼盈襟。", "枉殺幾樹花，恣許泥土浸。", "或云天有意，欲使誅荒淫。", "田穀彼何罪，芽穎當森森。", "一粒且漂溺，不啻千黄金。", "路絕吊客行，餒我憂巢禽。", "風聲怒打屋，寒氣獰穿衾。", "況我出山遠，久次茲江潯。", "嗟嗟歲月晚，悠悠金玉音。", "無聊但詼笑，有得還歌吟。", "莫怪旅愁甚，旅人千萬心。"]'),
('e4027da1-6e2a-4f28-b091-562a271a37a9','弋陽縣學北堂見夾竹桃花有感而書','李覯','宋','宋诗','song-poetry','','[]','暖碧覆睛殷，依依近朱欄。',72,'全唐诗/poet.song.20000.json','["暖碧覆睛殷，依依近朱欄。", "異類偶相合，勁節何能安。", "同時盡妖艷，無地容檀欒。", "移根既不可，潔心誠爲難。", "外貌任春色，中心期歲寒。", "正聲尚可聽，誰是伶倫官。"]'),
('c1d2c437-095a-4561-9a59-8c95b2f13a02','孤懷','李覯','宋','宋诗','song-poetry','','[]','智者在不惑，君子貴知幾。',48,'全唐诗/poet.song.20000.json','["智者在不惑，君子貴知幾。", "彼昏有耳目，無能辨是非。", "蜀犬盡鳴吠，羲輪自光輝。", "古人不可作，垂涕沾吾衣。"]'),
('bdb2e5ff-7bc7-4964-80f0-321649a154d0','讀韓文公駑驥篇因廣其說','李覯','宋','宋诗','song-poetry','','[]','主人渴良馬，僕夫念駑駘。',48,'全唐诗/poet.song.20000.json','["主人渴良馬，僕夫念駑駘。", "行遲追易及，力少牽易來。", "時聞千里足，百箭攢其懷。", "主人雖欲買，衆口大悠哉。"]'),
('3183762d-bbbb-4668-8f05-61ecf0688f0b','送陳次公茂材','李覯','宋','宋诗','song-poetry','','[]','俗人無心胸，貴僞不貴誠。',96,'全唐诗/poet.song.20000.json','["俗人無心胸，貴僞不貴誠。", "口吻當文學，犇走成名聲。", "之子出蒿萊，行潔業且精。", "中美未外發，樸質亡華英。", "持此嚮廣衆，詎免笑與憎。", "况復覓薦舉，路險豈易行。", "所願天命泰，因之主者明。", "牙絃一鼓時，鍾子耳必傾。"]'),
('a8533c0d-5188-4bef-99e7-44b7e1bd12e7','蝦蟆','李覯','宋','宋诗','song-poetry','','[]','蝦蟆爾奚爲，閤閤攪人耳。',72,'全唐诗/poet.song.20000.json','["蝦蟆爾奚爲，閤閤攪人耳。", "在官不爲官，在私無私事。", "徒將一寸口，日夜相鳴吠。", "豈能劖語言，且欲譟夢寐。", "何者孔稚珪，愛之如鼓吹。", "誰論正與淫，各自有知己。"]'),
('cd7f7155-7b76-48f1-9af9-140647d75536','惜鷄詩','李覯','宋','宋诗','song-poetry','','[]','吾家有鷄母，乘春數子生。',288,'全唐诗/poet.song.20000.json','["吾家有鷄母，乘春數子生。", "生來踰六旬，互覺羽翼成。", "其母且再卵，逐之使離散。", "衆雛既不來，一子獨戀戀。", "戀戀不肯離，逐之終不移。", "母行無險易，唧唧相追隨。", "卵生亦云足，母伏窠中宿。", "厥子苦無依，攀背如悲哭。", "窠中母所安，忍渴復忘餐。", "子於背上卧，不捨須臾間。", "我時見之喜，異類能如此。", "因欲觀其終，其終諒何似。", "一朝大長成，乃知牝牡情。", "膨脝娠在腹，漸見東西行。", "行行求飲食，欲以助生息。", "卵出子還多，養子何勞役。", "朝啄荆草林，暮爪汙泥深。", "昔時隨母意，今作愛雛心。", "雛生誠可愛，母老寧忍背。", "物性乃不常，使人心歡慨。", "物類本無知，無知孰責之。", "斯鷄與衆異，酷似有天資。", "天資以仁孝，變更何太早。", "况彼本無知，血毛安足道。"]'),
('9cedf5b4-caca-4cb6-8825-36ab1c08015b','日出吟','李覯','宋','宋诗','song-poetry','','[]','日出百鳥喜，覊人懶舉眸。',48,'全唐诗/poet.song.20000.json','["日出百鳥喜，覊人懶舉眸。", "長恨年光緩，祿養未可求。", "若至年光過，高堂又白頭。", "羲和君有知，奈我心悠悠。"]'),
('971c011b-eb56-423d-bbb2-467ea464808f','聞女子虐疾偶書二十四韻寄示','李覯','宋','宋诗','song-poetry','','[]','昨日家人來，言汝苦寒熱。',288,'全唐诗/poet.song.20000.json','["昨日家人來，言汝苦寒熱。", "想由卑濕地，頗失飲食節。", "脾官驕不治，氣馬癡如絏。", "乃致四體煩，故當雙日發。", "江南此疾多，理不憂顛越。", "顧汝僅毀齒，何力禁喘噎。", "寄書詰醫師，有藥且嚼啜。", "方經固靈應，病根終翦滅。", "但恐祟所爲，嘗聞里中說。", "茲地有罔兩，乘時相罥結。", "嗟哉鬼無知，何於我爲孽。", "我本重脩飾，胸中掬冰雪。", "禍淫雖甚苛，無所可挑抉。", "疑是饕餮魂，私求盤碗設。", "盡室唯琴書，何路致葷血。", "無錢顧越巫，刀劍百斬决。", "徒恣彼昏邪，公然敢抄撮。", "吾聞上帝靈，網目匪疎缺。", "行當悉追捕，汝苦旦夕歇。", "慈愛早有加，憶念今逾切。", "塵勞差可畏，歸計又云輟。", "所生能劬勞，祖母矧聰哲。", "羸卧縱未蘇，撫視諒非拙。", "勉勉多自安，風來信勿絕。"]'),
('f93fbd1e-9311-4a20-8fab-929bbf838435','讀史','李覯','宋','宋诗','song-poetry','','[]','子長漢良史，筆鋒頗雄剛。',120,'全唐诗/poet.song.20000.json','["子長漢良史，筆鋒頗雄剛。", "惜哉聞道寡，氣志苦不常。", "心如蟲絲輕，隨風東西揚。", "一事若可喜，不顧道所長。", "公言絀原憲，俠賊乃爲良。", "仁義謂足羞，貨殖比君王。", "黄老先六經，斯言固猖狂。", "吁嗟夫子沒，兩觀無刑章。", "予懷班孟堅，駁議何洋洋。", "傳與後世人，慎思其否臧。"]'),
('37320ebb-ba0d-49a4-a23e-d6f0fbaad988','和育王十二題 金沙池','李覯','宋','宋诗','song-poetry','','[]','遥聞金在沙，知是虛名號。',24,'全唐诗/poet.song.20000.json','["遥聞金在沙，知是虛名號。", "世人方競奢，何茲有遺寶。"]'),
('a8120457-e8bf-4d3f-86c2-c25d7087e447','和育王十二題 佛迹峯','李覯','宋','宋诗','song-poetry','','[]','佛迹空在茲，佛心無處所。',24,'全唐诗/poet.song.20000.json','["佛迹空在茲，佛心無處所。", "尋迹以求之，似學邯鄲步。"]'),
('efe63a42-a57b-475f-9733-72eaa3c11cc4','和育王十二題 七佛石','李覯','宋','宋诗','song-poetry','','[]','萬物雖散殊，孰非道之體。',24,'全唐诗/poet.song.20000.json','["萬物雖散殊，孰非道之體。", "何必石岩岩，方疑金色臂。"]'),
('2a6462f1-8136-43f0-ad8a-abb1b5ed88be','和育王十二題 袈裟石','李覯','宋','宋诗','song-poetry','','[]','梵教一來東，羣心日歸向。',24,'全唐诗/poet.song.20000.json','["梵教一來東，羣心日歸向。", "土石至無情，也作披緇狀。"]'),
('85e6bc0e-4e2c-49dc-b32e-4214e437a046','和育王十二題 明月臺','李覯','宋','宋诗','song-poetry','','[]','月色固無改，臺基亦不壞。',24,'全唐诗/poet.song.20000.json','["月色固無改，臺基亦不壞。", "嗟哉翫月人，古來誰更在。"]'),
('323dbeb2-c3aa-4ef1-bf11-be0c134d30e5','和育王十二題 石屏風','李覯','宋','宋诗','song-poetry','','[]','形模皆自然，樹立豈人力。',24,'全唐诗/poet.song.20000.json','["形模皆自然，樹立豈人力。", "松影與秋光，掃成真水墨。"]'),
('379ff421-e03a-47c7-a8a4-356e75622dab','和育王十二題 靈鰻井','李覯','宋','宋诗','song-poetry','','[]','田苗自枯槁，井鰻人所禱。',24,'全唐诗/poet.song.20000.json','["田苗自枯槁，井鰻人所禱。", "若教龍有靈，此魚何足道。"]'),
('b728b3c2-b296-4380-8a08-41e5ff8cf2b4','和育王十二題 供奉泉','李覯','宋','宋诗','song-poetry','','[]','璘師鑿此泉，晨夕奉親老。',24,'全唐诗/poet.song.20000.json','["璘師鑿此泉，晨夕奉親老。", "因知達者心，豈嘗離孝道。"]'),
('8f6c952c-66ef-4fbf-96fb-df30e59cdd14','和育王十二題 育王塔','李覯','宋','宋诗','song-poetry','','[]','嘗聞有爲法，佛說如夢幻。',24,'全唐诗/poet.song.20000.json','["嘗聞有爲法，佛說如夢幻。", "胡然窣堵波，香花耀凡眼。"]'),
('3647a663-b31b-4b6f-bea0-e9b038eadfd6','和育王十二題 八角殿','李覯','宋','宋诗','song-poetry','','[]','晉後千百年，茲殿儼如昔。',24,'全唐诗/poet.song.20000.json','["晉後千百年，茲殿儼如昔。", "梵宇若皆然，應須省民力。"]'),
('053ec5fa-10f0-4808-b748-dfe0d6c66f32','和育王十二題 晉年松','李覯','宋','宋诗','song-poetry','','[]','典午既陵夷，羣材共淪謝。',24,'全唐诗/poet.song.20000.json','["典午既陵夷，羣材共淪謝。", "唯有青青松，于今被王化。"]'),
('83ddc4a1-1a2f-4750-a43d-1b7f93b73c06','和育王十二題 重臺蓮','李覯','宋','宋诗','song-poetry','','[]','長疑佛界中，天女來行樂。',24,'全唐诗/poet.song.20000.json','["長疑佛界中，天女來行樂。", "爲怕山風寒，仙衣盡重著。"]'),
('6b3d6aac-05c1-4953-8b00-f36fbe0d8fa2','美女篇','李覯','宋','宋诗','song-poetry','','[]','繁霜毒春木，花開苦不早。',72,'全唐诗/poet.song.20000.json','["繁霜毒春木，花開苦不早。", "愚夫擇利婚，美女貧中老。", "曷不冶顔色，門前車馬道。", "閨房有禮文，自衒誰言好。", "俗態競朱粉，古心慕蘋藻。", "所期君子恩，卒以慰枯槁。"]'),
('ffbe68b9-8271-4f40-8fd6-e45f678eb46c','苦熱夜','李覯','宋','宋诗','song-poetry','','[]','熒熒背明燈，黯黯垂疎帷。',48,'全唐诗/poet.song.20000.json','["熒熒背明燈，黯黯垂疎帷。", "階庭豈不好，蚊蟲苦相期。", "壞扇無清風，暗樹多斜枝。", "屈指出泉侶，寂寥空所思。"]'),
('9576ce1b-ae54-4a0c-9890-709474f3f3b7','丐僧','李覯','宋','宋诗','song-poetry','','[]','靡靡步康衢，喋喋問流俗。',36,'全唐诗/poet.song.20000.json','["靡靡步康衢，喋喋問流俗。", "誰將今日財，願易來世福。", "休論身善惡，佛眼重金玉。"]'),
('a216aa3c-ae02-412e-8f23-92ee73a7dee2','閔俗','李覯','宋','宋诗','song-poetry','','[]','君門若無祿，陳編孰能讀。',48,'全唐诗/poet.song.20000.json','["君門若無祿，陳編孰能讀。", "公庭若無法，穢德誰不足。", "煦煦儒者言，沈沈小人腹。", "傷心勿復道，拂絃寄清曲。"]'),
('d81a4f6a-b4da-46b3-9228-a4e3cc2ec9d1','感歎二首  其一','李覯','宋','宋诗','song-poetry','','[]','世常羞貧賤，貧賤非我羞。',72,'全唐诗/poet.song.20000.json','["世常羞貧賤，貧賤非我羞。", "道成不見取，貧賤誰之由。", "陛楯擁堯舜，廊廟居伊周。", "面對豈無說，咫尺路阻脩。", "浮雲關太虛，白日光逆流。", "嗟爾臨人者，蔽賢天所仇。"]'),
('f4c507de-5734-4788-94da-07ee064f6993','感歎二首  其二','李覯','宋','宋诗','song-poetry','','[]','得志萬罪消，失志百醜生。',60,'全唐诗/poet.song.20000.json','["得志萬罪消，失志百醜生。", "誰云王路寬，枯槁不敢行。", "出言到口角，縮舌悔恨并。", "自省由若此，況乃蚩蚩氓。", "故知當今賢，未有非簪纓。"]'),
('c9e23891-4f9a-4e45-b811-242358e889b3','寄鄰父','李覯','宋','宋诗','song-poetry','','[]','離山闕歸期，滯蹤如在獄。',48,'全唐诗/poet.song.20000.json','["離山闕歸期，滯蹤如在獄。", "他門一臠炙，賤子萬端辱。", "吟憶圃花盡，夢知原麥熟。", "公言富貴遲，何似耕穫速。"]'),
('d03777fd-8077-4051-85b5-5227654fe304','竹齋題事','李覯','宋','宋诗','song-poetry','','[]','低齋結空野，小竹移孤林。',120,'全唐诗/poet.song.20000.json','["低齋結空野，小竹移孤林。", "齋閑竹浄好，日媚幽人心。", "南方夏厭暑，獨此留殘陰。", "戛雨挫促夢，穿風搜凉襟。", "長茵展麗蘚，亂歌奏歡禽。", "侍奴裹村服，語客拋塵簪。", "志高成利讐，思爽生詩淫。", "值聖喜盈卷，感古悲入琴。", "山迎穩履遠，月勸澄杯深。", "榮名雖未染，幸亦非堙沈。"]'),
('6901f32a-3809-4b54-9290-96cf00557f21','贈黄秀才別','李覯','宋','宋诗','song-poetry','','[]','朝閨入有籍，疏遠難見君。',48,'全唐诗/poet.song.20000.json','["朝閨入有籍，疏遠難見君。", "世眼不識道，貧賤無高文。", "蘭蕙生同草，鴻鵠心在雲。", "贈子喜別離，兒女安得聞。"]'),
('509cb24a-de06-4b4a-bc42-0024fde566fa','雨中作','李覯','宋','宋诗','song-poetry','','[]','羣陰侮陽德，雨陣春嘈嘈。',96,'全唐诗/poet.song.20000.json','["羣陰侮陽德，雨陣春嘈嘈。", "白曉慘成夜，瓦口生飛濤。", "凝雲列山韒，冷氣攢衣刀。", "徑鬧有松竹，庭卧唯蓬蒿。", "花淫得罪隕，鶑辯知時逃。", "隰苗出水短，木菌隨日高。", "微吟雅於樂，快飲甘如膏。", "朱曦待未見，天蓋空牢牢。"]'),
('aca4f022-5c27-48cc-8191-aaee12dae029','獨居','李覯','宋','宋诗','song-poetry','','[]','苔根跨階發，白雨滿四簷。',48,'全唐诗/poet.song.20000.json','["苔根跨階發，白雨滿四簷。", "春眠嬾下枕，日午誰開簾。", "浮塵裹酒榼，餒蟲鏤書籤。", "榮樂豈不欲，非義固所嫌。"]'),
('6a0b5758-e680-4651-9250-6610abb96fff','閔雨詩','李覯','宋','宋诗','song-poetry','','[]','吳江之南，是曰豐國。',354,'全唐诗/poet.song.20000.json','["吳江之南，是曰豐國。", "五種之生天下食，一歲不登，吾民菜色。", "如何天不仁，縱彼旱孽稱其神。", "矯矯赤龍推火軒，來自東南山。", "咸池愞水不敢沃，陽侯失色愁烹煎。", "況茲畎畝流涓涓，何足吸之唇齒間。", "但見禾與黍，蓬勃紅塵起。", "土伯敕其屬，掃路迎饑鬼。", "哀哉氓蚩蚩，託身釜鬲惟蒸炊。", "小人怨咨君子知，天生天殺今其時。", "我聞皇穹大德在生育，愛養萬物同嬰兒。", "産民之身賦民食，中道絕之何所爲。", "當時冥冥間，委作非其宜。", "山川之神各守土，羣龍受位司天池。", "上帝當軒親戒敕，十日一雨無愆期。", "帝心仁且信，臨下固不疑。", "謂言庶事有分職，屏去視聽思無爲。", "安知愚下鬼，負德孤恩難制指。", "弄天之權侮人命，貪嗜牛羊邀祭祀。", "忽焉一物不稱情，因教此旱災生靈。", "雷霆之官畏罪莫敢諫，頭枕天鼓眠不醒。", "帝在紫微垣，下隔千里雲。", "徒勞銜血向空哭，帝心雖聖安得聞。", "北斗侍帝側，斡運氣母均四時。"]'),
('00565f76-b300-467b-825b-ca19cd2752b8','訪周道士','李覯','宋','宋诗','song-poetry','','[]','豈無飲食奉歡樂，亦有賓客相追遊。',96,'全唐诗/poet.song.20000.json','["豈無飲食奉歡樂，亦有賓客相追遊。", "宿酲在枕或時起，俗話入耳令人羞。", "偶隨賢友訪仙子，一臨花檻斟瓷甌。", "塵埃何處是浮世，松竹此地長清秋。", "古來擾擾富且貴，天下茫茫公與侯。", "蓋棺事了何足數，乘興嘯傲真良籌。"]'),
('972b317a-1dd4-466c-a7bf-2b714cffe832','甘露亭詩','李覯','宋','宋诗','song-poetry','','[]','乾坤父母莫匪慈，胚胎億兆成角覊。',384,'全唐诗/poet.song.20000.json','["乾坤父母莫匪慈，胚胎億兆成角覊。", "其間哺乳不及處，有時泣殺呱呱兒。", "南川上游號沃野，景祐丙子嘗凶饑。", "新田始苗舊穀罄，十室八九無晨炊。", "伏陰何者不仁甚，釀作水災來助之。", "煙煤刷天雨汁黑，嘔山泄谷爭奔馳。", "橫流一夜打城郭，萬弩竊發穿毛皮。", "東隅有洲尸揖揖，如蟻欲走遭水圍。", "屋根無力樹腰折，蛟蜃食人猶擇肥。", "濤波一望萬山阻，六親不得相扶持。", "國子劉公好仁者，惟時假守茲軍麾。", "民生在我不在命，告舟往救無敢違。", "童兒赤立婦女困，載之刳木何纍纍。", "泥沙外冷內饑渴，口噤不語如狂癡。", "牽攣坐卧滿府舍，賦以酒飲加饘糜。", "隨流往往亦不死，遠在百里無人知。", "捐金購得問氏姓，召使親族携之歸。", "司農倉廩盡發出，不待奏報先施爲。", "有餘況可補不足，大賈蓄家如響隨。", "來瞻去察夜繼晝，赤熱不忍蔭華榱。", "由斯一郡十萬戶，餓膚日月生膏脂。", "存者相保沒者葬，唐虞仁壽重敺躋。", "聖主養賢賢養物，氣和郁郁通高卑。", "城西老宮古松徑，一朝墜露甘如飴。"]'),
('125bab77-33a3-4600-8740-bd9abea8616e','送丘寺丞','李覯','宋','宋诗','song-poetry','','[]','嗟予兀兀何施爲，學無異意唯傳師。',256,'全唐诗/poet.song.20000.json','["嗟予兀兀何施爲，學無異意唯傳師。", "嘗言先聖所述作，人事而已亡他岐。", "安知步步有天道，繄我丘師能識之。", "春秋下應三千歲，雅頌周流十二支。", "闡幽大傳與隠旨，圖寫轉匝成圓規。", "勞兄示我復教我，一字不曉如癡兒。", "文侯聽樂唯恐卧，今我幸免指目皮。", "丘明子夏言不及，我兄所得何神奇。", "直疑前身是顔子，獨受師說無人知。", "又疑夢寐感靈怪，常與周孔相追隨。", "不然悠悠千載後，何傳何習遽如斯。", "窮愁著書古有例，昨官閩中今海涯。", "海涯路遠學者少，斯道未有施行時。", "聖皇誅賞甚明白，歸來奏牘無遲遲。", "江南臘雪片如掌，酒花上面寒力衰。", "是非得失從此止，馬頭一別東西馳。"]'),
('f046ed50-22cb-46c5-acc1-bf5f8a113fe7','答緣概師見示草書千字文并名公所贈詩序','李覯','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','佛繇西域漸中土，欲使羣心皆鼓舞。',288,'全唐诗/poet.song.20000.json','["佛繇西域漸中土，欲使羣心皆鼓舞。", "若顓梵語及胡書，昧者雖從明孰與。", "其徒往往多材能，暗結時賢爲外助。", "遠公自昔來廬山，誇逞蓮花邀社侶。", "吁嗟君子遭亂邦，舍此未知何處去。", "邇來一行善記覽，齧破乾坤尋曆數。", "或攻文苑掠芬香，辭則貫休筆懷素。", "其餘曲藝與小詩，布在人間難悉數。", "賢豪大抵多憐才，引致門牆無齟齬。", "其人既重法亦尊，羽翼大成根本固。", "我緣山谷見不遠，緇褐憧憧盡愚魯。", "坐量此去朋黨衰，纖縞焉能拒强弩。", "去年有使自番陽，手藉一函來我所。", "發函乃是緣概書，千字滿前雲縷縷。", "衆人飽食己用心，欲噍伯英肥美處。", "當時名士嘉其能，長序短篇聊繡組。", "因思幅員千萬里，如師之能更幾許。", "以儒輔釋日益多，何恤區區一韓愈。"]'),
('1d91342a-690a-4832-968d-7ba7925f2296','春社詞','李覯','宋','宋诗','song-poetry','','[]','吳臺翫春鎖春色，雨刷花光入龍國。',64,'全唐诗/poet.song.20000.json','["吳臺翫春鎖春色，雨刷花光入龍國。", "田邊大樹啼老鴉，野雲癡醉寒查牙。", "年華欲住風雷惡，蘭臉知秋淚先落。", "時榮時謝無了時，扶起混沌須神醫。"]'),
('7fb66e7f-e8b3-4a41-9e98-a4cd22360f83','聞訓狐','李覯','宋','宋诗','song-poetry','','[]','昔年因讀昌黎文，知有訓狐猶未真。',160,'全唐诗/poet.song.20000.json','["昔年因讀昌黎文，知有訓狐猶未真。", "客堂昨夜滅燭後，一聲竊發誠驚人。", "慈母入席匪虛語，據此麄暴誰敢聞。", "殺人之子養爾子，天地不管胡爲仁。", "豈無鷹隼善搏擊，去路昏黑難相親。", "亦有弓矢可彈射，却恐誤中東西鄰。", "我今獨處雖無懼，聒不得睡寧不嗔。", "嘗聞鳳凰百鳥君，丹穴萬里誰龍言。", "行當整頓九韶樂，奉迎綷羽掀重雲。", "直前再拜列爾罪，爾軀何足爲灰塵。"]'),
('c8bfee4c-6671-4bff-8150-2180a8c092ca','聞喜鵲','李覯','宋','宋诗','song-poetry','','[]','翩翩者鵲何品流，羽毛白黑林之幽。',176,'全唐诗/poet.song.20000.json','["翩翩者鵲何品流，羽毛白黑林之幽。", "生平智力可料度，有巢往往輸鳴鳩。", "天然却會報人喜，愚兒幼婦唯爾求。", "萬聲千噪幾曾驗，聞者終是軒眉頭。", "從來烏鳥愛反哺，孝慈情性誰可儔。", "其間於事最先見，告人凶禍令人憂。", "憂時不肯自脩飾，禱請神鬼爭啾啾。", "告之愈驗愈見惡，共去災患鴉之由。", "彈丸瓦石相驅逐，名園佳樹難依投。", "忠言逆耳世罕用，屬鏤曾割伍員喉。", "莫笑後來司馬公，事事稱好真良謀。"]'),
('fa4f7a9a-4997-44c6-8803-ee830165f9f4','解湯延祖字','李覯','宋','宋诗','song-poetry','','[]','仲尼作經授曾子，明稽至孝之終始。',160,'全唐诗/poet.song.20000.json','["仲尼作經授曾子，明稽至孝之終始。", "始於事親終立身，以是揚我於後世。", "大雅有言念爾祖，述脩其德乃爲美。", "聖訓昭昭十八章，寫之琬琰千餘歲。", "湯生本由義方教，石磨沙盪求成器。", "其名延祖有意哉，吾以子立爲之字。", "立身之道將何如，非曰凡人富與貴。", "不賢而位何能爲，蠅蟲豈不披紅紫。", "周公亦人舜亦人，口銜日月坐天際。", "勗哉見善勿遲疑，往往後生誠可畏。"]'),
('93dc2f52-3742-455e-a94f-5e986a053dc7','詠竹','李覯','宋','宋诗','song-poetry','','[]','外邊雖節目，內裹却空虛。',24,'全唐诗/poet.song.20000.json','["外邊雖節目，內裹却空虛。", "從來汗流浹，只爲寫經書。"]'),
('5c99d9ae-ec23-47b1-9f16-72160f2edf87','霜','李覯','宋','宋诗','song-poetry','','[]','夜落無人見，朝看到處新。',24,'全唐诗/poet.song.20000.json','["夜落無人見，朝看到處新。", "非君有分別，力不奈松筠。"]'),
('2a419f07-f02a-4c3e-9ba2-43256457dbc7','冰','李覯','宋','宋诗','song-poetry','','[]','水性本來弱，漸寒成此堅。',24,'全唐诗/poet.song.20000.json','["水性本來弱，漸寒成此堅。", "東風有時到，幾日是殘年。"]'),
('7babaa35-7734-4fb4-b018-d1444d4b3b35','鵝','李覯','宋','宋诗','song-poetry','','[]','逸少曾留翫，人因喚右軍。',24,'全唐诗/poet.song.20000.json','["逸少曾留翫，人因喚右軍。", "鳥名加爵號，不離羽毛羣。"]'),
('1d3fb8af-6fd4-4dcf-826d-c0560ae4e60e','鴨','李覯','宋','宋诗','song-poetry','','[]','庶人常用贄，貴在不飛遷。',24,'全唐诗/poet.song.20000.json','["庶人常用贄，貴在不飛遷。", "飽食待庖宰，虛教兩翅全。"]'),
('9ad057e2-bebc-4d90-bd98-bc68a35ec50f','惜才','李覯','宋','宋诗','song-poetry','','[]','醜婦易爲潔，愚兒多守純。',24,'全唐诗/poet.song.20000.json','["醜婦易爲潔，愚兒多守純。", "天將惡文采，萬物恐無春。"]'),
('161dd41a-3040-43a1-b143-ee95f06be8c3','山舍寓止','李覯','宋','宋诗','song-poetry','','[]','無計奈踈拙，走逃雲水隈。',48,'全唐诗/poet.song.20000.json','["無計奈踈拙，走逃雲水隈。", "鶴饑雖厭夜，龍睡却嫌雷。", "師友關千古，窮通付一杯。", "商巖版築者，底處有梯媒。"]'),
('48767053-4710-456e-bdf7-74102b1cb605','東巖精舍','李覯','宋','宋诗','song-poetry','','[]','像設彼何時，高僧白衲衣。',48,'全唐诗/poet.song.20000.json','["像設彼何時，高僧白衲衣。", "水寒吞日氣，樹老慣霜威。", "幡影捎天近，鐘聲落谷微。", "可憐成道易，無事即無機。"]'),
('f0f4ec2a-8be0-4635-bee0-41b9bb625d59','閑夜','李覯','宋','宋诗','song-poetry','','[]','披衣坐小亭，夜氣拂人清。',48,'全唐诗/poet.song.20000.json','["披衣坐小亭，夜氣拂人清。", "月暗先成暈，蟲吟不識名。", "舉杯期混沌，開卷賞莖英。", "此興知誰會，松風鶴睡驚。"]'),
('383078c6-2e6a-48a0-b8f4-3060615d23f3','霧','李覯','宋','宋诗','song-poetry','','[]','光明人所好，幽暗此何爲。',48,'全唐诗/poet.song.20000.json','["光明人所好，幽暗此何爲。", "樹在谿無影，禽來鶻未知。", "愛花留潤與，避日卷陰移。", "底事偏相惱，天涯欲望時。"]'),
('109765e0-375b-4e80-bedc-285f5f9b54c3','自詠','李覯','宋','宋诗','song-poetry','','[]','俗態共紛紛，吾心誰與論。',48,'全唐诗/poet.song.20000.json','["俗態共紛紛，吾心誰與論。", "幾因清夜夢，還見古人魂。", "師域寧無樂，文家別有尊。", "此身聊自足，獨恐累兒孫。"]'),
('e9e04054-cbb2-4c27-b8da-587e07a0247f','睡思','李覯','宋','宋诗','song-poetry','','[]','俗語不入耳，旅愁還到心。',48,'全唐诗/poet.song.20000.json','["俗語不入耳，旅愁還到心。", "坐多渾易厭，夢好欲重尋。", "暴雨撩蓬響，殘陽過嶺陰。", "迴看犇競苦，此興貴南金。"]'),
('1a91722a-5c44-4d63-a586-edda217c8d29','秋熱','李覯','宋','宋诗','song-poetry','','[]','江湖限南鄙，秋令到還稀。',48,'全唐诗/poet.song.20000.json','["江湖限南鄙，秋令到還稀。", "節換空看曆，人閑未趁衣。", "齊紈方得意，厦燕莫言歸。", "祗有松筠徑，風高暑氣微。"]'),
('2e163016-0892-4e47-9185-78c52d917be3','鑑湖夜泛','李覯','宋','宋诗','song-poetry','','[]','明月到樽前，拏舟古岩邊。',48,'全唐诗/poet.song.20000.json','["明月到樽前，拏舟古岩邊。", "亂山斜入霧，遠水倒垂天。", "酒氣薰龍戲，歌聲弄鶴眠。", "迴頭嗤李郭，此外更無仙。"]'),
('febc33ac-665a-4a2e-bb75-f421b9b53bf9','池亭小酌','李覯','宋','宋诗','song-poetry','','[]','客思都無著，臨池一醉歌。',48,'全唐诗/poet.song.20000.json','["客思都無著，臨池一醉歌。", "喚春呈物象，移性入天和。", "月影碎荆玉，波紋緯蜀羅。", "相看盡仙骨，俗態已無多。"]'),
('e08cffe8-a886-469d-9f11-dae75de46edb','迴胡舜元賦稿','李覯','宋','宋诗','song-poetry','','[]','一把長篇讀，驚嗟即過旬。',48,'全唐诗/poet.song.20000.json','["一把長篇讀，驚嗟即過旬。", "誰知後來者，還似老成人。", "古訓但時習，英辭當日新。", "慙無稱薦力，空此見天麟。"]'),
('8906922a-db7a-40fe-a7d0-00b84262a564','迴黄通詩篇','李覯','宋','宋诗','song-poetry','','[]','老杜沒已久，嗟哉吾子心。',48,'全唐诗/poet.song.20000.json','["老杜沒已久，嗟哉吾子心。", "時人任詬病，獨自革浮淫。", "美玉寧須琢，朱絃豈在音。", "鐘期如未見，慎勿等閑吟。"]'),
('f9b4139d-4c0f-458d-860c-d0ed8bb5d78f','送路拯北遊','李覯','宋','宋诗','song-poetry','','[]','六月地欲赤，驅車河朔行。',48,'全唐诗/poet.song.20000.json','["六月地欲赤，驅車河朔行。", "王師備戎羯，游子念功名。", "盡識山川險，深窮彼我情。", "歸來具封奏，直上請長纓。"]'),
('cc39cedd-3cec-411e-9bd2-bfac2254c2a0','感事','李覯','宋','宋诗','song-poetry','','[]','太平無武備，一動未能安。',48,'全唐诗/poet.song.20000.json','["太平無武備，一動未能安。", "廟算何時勝，人生到處難。", "役頻農力耗，賦重女工寒。", "祗有旴江守，憐民不愛官。"]'),
('7103656a-3cec-44e1-8e45-3cb8d397c04e','閑居','李覯','宋','宋诗','song-poetry','','[]','無物可勞情，空郊日閉扃。',48,'全唐诗/poet.song.20000.json','["無物可勞情，空郊日閉扃。", "雨吟春破碎，貧飲客凋零。", "世事重江險，才名一夢醒。", "同心祗松栢，見我尚青青。"]'),
('507a33c0-301d-4b71-9b7d-fa818e07afa7','萍','李覯','宋','宋诗','song-poetry','','[]','盡日看流萍，誰原造化情。',48,'全唐诗/poet.song.20000.json','["盡日看流萍，誰原造化情。", "可憐無用物，偏解及時生。", "泥滓根萌淺，風波性質輕。", "晚來堆岸曲，猶得護蛙鳴。"]'),
('809c6835-2de1-4aa5-a7d1-2caf78f41e17','送張鬷嘏','李覯','宋','宋诗','song-poetry','','[]','人意皆懷土，嗟君無故園。',48,'全唐诗/poet.song.20000.json','["人意皆懷土，嗟君無故園。", "欲行須盡室，此去又他門。", "靜裏文章好，貧來節行存。", "振淹知有日，倚伏豈虛言。"]'),
('8e501dc7-7449-469b-bb77-4018606bc435','村行','李覯','宋','宋诗','song-poetry','','[]','産業家家壞，誅求歲歲新。',48,'全唐诗/poet.song.20000.json','["産業家家壞，誅求歲歲新。", "平時不爲備，執事彼何人。", "朱戶仍奢侈，柴門轉窶貧。", "若非衢室畔，無用說悲辛。"]'),
('59901867-12ec-4888-a17c-2159a2df9105','感懷寄擇之','李覯','宋','宋诗','song-poetry','','[]','衆人皆銳進，唯我復幽居。',48,'全唐诗/poet.song.20000.json','["衆人皆銳進，唯我復幽居。", "慮遠夢多亂，身閑氣不舒。", "干求非祿位，好尚豈詩書。", "日夜又日夜，霜寒鬢髮疎。"]'),
('1f4cf6d8-1cac-4f4c-aa57-9b29315d91c0','鷄','李覯','宋','宋诗','song-poetry','','[]','嗟爾羽蟲類，昂然冠距麄。',48,'全唐诗/poet.song.20000.json','["嗟爾羽蟲類，昂然冠距麄。", "徒爲識昏曉，猶未免庖厨。", "年少苦令鬭，主人頻見呼。", "寧思避弋者，天外去鴻孤。"]'),
('3ff85a9a-d0b2-4b9d-8093-ed54213aa016','堂西夜坐','李覯','宋','宋诗','song-poetry','','[]','炎蒸得避處，鋪席對西牆。',48,'全唐诗/poet.song.20000.json','["炎蒸得避處，鋪席對西牆。", "有月樹陰黑，無風山氣凉。", "聚蚊妨袒裼，飲井當壺觴。", "妻子詎知我，笑言皆在傍。"]'),
('7c2ab7fb-d4fd-48e0-9aa8-23b2d9ee9b16','寄題陳適追養亭','李覯','宋','宋诗','song-poetry','','[]','築室先塋下，哀心有所歸。',48,'全唐诗/poet.song.20000.json','["築室先塋下，哀心有所歸。", "每來開戶牖，渾似戀庭闈。", "丘木成風樹，衰裳換綵衣。", "吾生與君類，東望涕交揮。"]'),
('064909cd-82bf-4348-ab71-1d3bbe68dd57','送宜黄柳尉','李覯','宋','宋诗','song-poetry','','[]','荒郊人事絕，歡喜見時髦。',48,'全唐诗/poet.song.20000.json','["荒郊人事絕，歡喜見時髦。", "舊業椽爲筆，新官草染袍。", "幽明終考績，州縣豈徒勞。", "况有松筠性，凌寒節更高。"]'),
('0b7304e0-eaf6-42b2-a77a-3d7a979558e0','送君俞','李覯','宋','宋诗','song-poetry','','[]','之子來相問，吾言豈不誠。',48,'全唐诗/poet.song.20000.json','["之子來相問，吾言豈不誠。", "文章難得理，聲律易求名。", "貧甚須清節，親安莫遠行。", "異時如有立，宗族亦知榮。"]'),
('8f8fa77c-0d3a-4d9e-92c1-adbcc485b483','送黄祕丞','李覯','宋','宋诗','song-poetry','','[]','天下爲人子，何人似慶門。',48,'全唐诗/poet.song.20000.json','["天下爲人子，何人似慶門。", "二親皆白首，同日拜皇恩。", "就養蘭生畹，娛賓酒滿樽。", "自嗟偏侍早，相送只銷魂。"]'),
('50d64bfb-5bfa-490e-b06c-67d525b07de6','寄題廖說蒙亭','李覯','宋','宋诗','song-poetry','','[]','聖人雖在上，君子有窮時。',48,'全唐诗/poet.song.20000.json','["聖人雖在上，君子有窮時。", "自得山居樂，何須世俗知。", "夜多松月分，凉與水風期。", "只恐亨通去，清閑却付誰。"]'),
('30732164-45bd-4bad-a23d-deb007ccc6a0','晏起','李覯','宋','宋诗','song-poetry','','[]','貧士無所務，閑眠常起遲。',48,'全唐诗/poet.song.20000.json','["貧士無所務，閑眠常起遲。", "謾勞鷄口喚，不奈睡魔欺。", "宿酒猶薰腦，朝饑未到脾。", "誰能空汲汲，肉食自謀惟。"]'),
('e20aaa12-6239-4872-a39b-9f33afd79c16','養疾','李覯','宋','宋诗','song-poetry','','[]','少小唯貪酒，病來纔信醫。',48,'全唐诗/poet.song.20000.json','["少小唯貪酒，病來纔信醫。", "問方逋客許，尋藥野人疑。", "夜擣全聽慣，寒煎覺沸遲。", "古賢曾愛死，此意亦誰知。"]'),
('4d1d8cf5-76e5-4b53-be1f-baf6e801c4d7','遠山','李覯','宋','宋诗','song-poetry','','[]','最能牽病眼，天際一山橫。',48,'全唐诗/poet.song.20000.json','["最能牽病眼，天際一山橫。", "盡日是秋色，無人知地名。", "暗時雲自合，缺處路應平。", "才子霑衣淚，千秋共此情。"]'),
('05c03b03-7b40-455d-b842-a15e70d2df95','送吳伯華','李覯','宋','宋诗','song-poetry','','[]','典學淡無味，畏塗來幾程。',48,'全唐诗/poet.song.20000.json','["典學淡無味，畏塗來幾程。", "舉家應好事，努力爲求名。", "馨膳南陔遠，運環昨夢驚。", "壽觴何以薦，經術抵金籝。"]'),
('025e281b-2c2d-46a9-9fd1-0891c5dcb074','次韻陳殿丞除夜感懷','李覯','宋','宋诗','song-poetry','','[]','浮世因循過，流年次第新。',48,'全唐诗/poet.song.20000.json','["浮世因循過，流年次第新。", "迴思舊來事，都似夢中人。", "不飲偏嫌雪，多愁却怕春。", "星魁欲寅位，五鼓莫頻頻。"]'),
('3af43e41-31cf-4d10-8996-3fedd904b9da','早歸','李覯','宋','宋诗','song-poetry','','[]','病馬不妨騎，出門常便歸。',48,'全唐诗/poet.song.20000.json','["病馬不妨騎，出門常便歸。", "見人無事說，是物與心違。", "通塞元關命，驅馳轉覺非。", "莫教塵裏汗，壞却篋中衣。"]'),
('77af3350-b2a7-4111-9248-61a79d2e3c6c','晚聞角','李覯','宋','宋诗','song-poetry','','[]','傾耳斜陽裏，無聊拭淚頻。',48,'全唐诗/poet.song.20000.json','["傾耳斜陽裏，無聊拭淚頻。", "平生慣聞處，今日自愁人。", "夜近歇不久，風來聽得真。", "胡笳更何物，只此已傷神。"]'),
('53af5ccd-88ed-45e9-841f-83f1b51e37f3','庭樹','李覯','宋','宋诗','song-poetry','','[]','不是栽培力，誰容此處生。',48,'全唐诗/poet.song.20000.json','["不是栽培力，誰容此處生。", "細聲饒客睡，斜影與鄰清。", "地窄根猶迸，秋遲葉未驚。", "虞人雖欲伐，却怕損簷楹。"]'),
('b7f67ccb-6ffb-425b-9b16-9616def8a5cb','哭女二首  其一','李覯','宋','宋诗','song-poetry','','[]','妻死女已病，踰年成二喪。',48,'全唐诗/poet.song.20000.json','["妻死女已病，踰年成二喪。", "此生誰骨肉，未識好衣裳。", "看面雖猶小，聞言盡可傷。", "最知憐祖母，句句刮人腸。"]'),
('688d698b-c1c0-4411-a9cf-beba0fb49110','哭女二首  其二','李覯','宋','宋诗','song-poetry','','[]','老樹枝葉薄，先秋風雨過。',48,'全唐诗/poet.song.20000.json','["老樹枝葉薄，先秋風雨過。", "人間不善事，身外想無多。", "理遣誠如幻，悲來豈奈何。", "從前短鬢髪，爲爾漸雙皤。"]'),
('dc4c3b53-c2e6-44f8-a479-efcd41139d43','贈端師','李覯','宋','宋诗','song-poetry','','[]','十載寓都城，人傳善相名。',48,'全唐诗/poet.song.20000.json','["十載寓都城，人傳善相名。", "一言知禍福，相識盡公卿。", "洪井舊鄉路，紫衣歸計榮。", "塵緣應漸了，何日悟無生。"]'),
('cd1624e6-9ce0-45ee-9898-6d13bef6e29e','寄題鄒氏延壽亭','李覯','宋','宋诗','song-poetry','','[]','一世躋仁壽，君今更欲延。',48,'全唐诗/poet.song.20000.json','["一世躋仁壽，君今更欲延。", "山中想無事，分外得長年。", "松老多經雪，雲閑不到天。", "區區殉名者，迴首倍凄然。"]'),
('f9697543-ee09-4b9b-abfa-f6d45952f2d4','感秋','李覯','宋','宋诗','song-poetry','','[]','徙倚重咨嗟，非緣惜歲華。',48,'全唐诗/poet.song.20000.json','["徙倚重咨嗟，非緣惜歲華。", "關山異鄉客，砧杵別人家。", "天冷雲含日，谿清水獻沙。", "屈魂終不返，悲思更無涯。"]'),
('c152149c-e6a1-4753-b935-c39c301fd61d','次韻答陳殿丞','李覯','宋','宋诗','song-poetry','','[]','不能隨薄俗，非是向深山。',48,'全唐诗/poet.song.20000.json','["不能隨薄俗，非是向深山。", "自喜道無屈，所嗟心未閑。", "酒鄉貧更入，詩債病猶還。", "一字成虛美，通宵只厚顔。"]'),
('e2e868b1-9a6c-4afe-b44f-652176e1a512','讀趙氏淳化詩集','李覯','宋','宋诗','song-poetry','','[]','少年曾誦習，誤認古人詩。',48,'全唐诗/poet.song.20000.json','["少年曾誦習，誤認古人詩。", "風雅世不重，姓名誰得知。", "高情如隠者，薄宦過明時。", "地下尋才鬼，應逢陸與皮。"]'),
('137a1b91-d67f-46b7-92b9-f88b81d194a1','小女','李覯','宋','宋诗','song-poetry','','[]','惜汝今何恃，言來淚滿襟。',48,'全唐诗/poet.song.20000.json','["惜汝今何恃，言來淚滿襟。", "死生雖分定，襁褓累人心。", "饑買鄰家乳，寒勞祖母針。", "豈知泉路隔，時撥繐帷尋。"]'),
('188b912a-2c09-4041-805c-11e9e71e2e4c','送吳著','李覯','宋','宋诗','song-poetry','','[]','好學誠雖篤，事親心不忘。',48,'全唐诗/poet.song.20000.json','["好學誠雖篤，事親心不忘。", "秋風滿黄葉，歸路正重陽。", "力行宜無改，脩辭况有方。", "起家知可望，蘭秀自聞香。"]'),
('bdc83356-5a6f-468f-9d0d-094a4ef1425b','題靈陽宮','李覯','宋','宋诗','song-poetry','','[]','費君投杖處，行客過彷徨。',48,'全唐诗/poet.song.20000.json','["費君投杖處，行客過彷徨。", "水面風雷散，沙頭草木荒。", "一壺誰世界，千古共凄凉。", "大塊偏勞我，燒丹未有方。"]'),
('af56296a-4bde-4099-aa0a-506c02878120','龜峰精舍','李覯','宋','宋诗','song-poetry','','[]','去縣二十里，路平時正春。',48,'全唐诗/poet.song.20000.json','["去縣二十里，路平時正春。", "四山唯有石，一寺更無塵。", "融結疑天意，經營憶古人。", "但知安樂處，何必是金身。"]'),
('86dc8fbc-f500-4f97-9014-379651b827e2','鳴蜩','李覯','宋','宋诗','song-poetry','','[]','雨餘雲漏日，蟲思已喧喧。',48,'全唐诗/poet.song.20000.json','["雨餘雲漏日，蟲思已喧喧。", "時節驚初夏，聲音似故園。", "爲誰吟綠野，相共送黄昏。", "便是秋來信，霜髯更幾根。"]'),
('44d6f742-472a-4982-bcb2-5c13cde91b31','送張評事','李覯','宋','宋诗','song-poetry','','[]','江上楚花鮮，君行一黯然。',48,'全唐诗/poet.song.20000.json','["江上楚花鮮，君行一黯然。", "居官無藉手，選部豈知賢。", "廉善雖由己，亨通亦在天。", "都人如問我，疎嬾甚當年。"]'),
('722b6675-e85b-4d8b-99b7-62ef6aa17278','送春','李覯','宋','宋诗','song-poetry','','[]','送爾歸天去，天應解禍淫。',48,'全唐诗/poet.song.20000.json','["送爾歸天去，天應解禍淫。", "物生誰得所，我見獨傷心。", "好景吟來徧，芳樽醉不禁。", "東風別無用，百草已成林。"]'),
('54751e3e-f830-42a6-baa5-df00e00bed26','君錫以新詩相示因成四十字答之','李覯','宋','宋诗','song-poetry','','[]','君詩三十首，一一敵琅玕。',48,'全唐诗/poet.song.20000.json','["君詩三十首，一一敵琅玕。", "語近終非俗，情閑不似官。", "姑山蟠郡碧，旴水蘸天寒。", "景物將才思，相期李杜壇。"]'),
('9c98bf7c-9e7c-4092-8000-546ea5066c1a','送李侍禁','李覯','宋','宋诗','song-poetry','','[]','三載旴江上，軍和盜亦殲。',48,'全唐诗/poet.song.20000.json','["三載旴江上，軍和盜亦殲。", "事煩終不惓，貧極始知廉。", "別袖揮寒日，歸舟載夜蟾。", "懋功宜有賞，天意在官占。"]'),
('1c56a27e-788d-4a04-a1a1-d1a95c086fc5','寄周寺丞','李覯','宋','宋诗','song-poetry','','[]','我愛南豐宰，天資舉措奇。',48,'全唐诗/poet.song.20000.json','["我愛南豐宰，天資舉措奇。", "上官如不怒，善政有誰知。", "賦役貧中減，鞭笞惡處施。", "邑人多未悟，去後始應思。"]'),
('34aad6e2-a042-46d2-8b67-9f0e605f0574','次韻閻判官除夜','李覯','宋','宋诗','song-poetry','','[]','密雪穿窗入，孤燈向壁光。',48,'全唐诗/poet.song.20000.json','["密雪穿窗入，孤燈向壁光。", "老來人不覺，夢繼酒猶香。", "世事休思慮，年華任短長。", "朽株難長育，空此見春陽。"]'),
('c74fd7fa-f18a-42dd-bc6c-b5610a7800a8','送閻判官','李覯','宋','宋诗','song-poetry','','[]','鄉樹江淮接，軍籌歲月深。',48,'全唐诗/poet.song.20000.json','["鄉樹江淮接，軍籌歲月深。", "從公雖盡力，當路少知音。", "賦命休重問，離觴且滿斟。", "君言鵬與鷃，何者是飛沈。"]'),
('575ae688-3fe7-47ea-9c72-a2136bedfe29','送彭昱應舉','李覯','宋','宋诗','song-poetry','','[]','計偕千百數，太半是虛名。',48,'全唐诗/poet.song.20000.json','["計偕千百數，太半是虛名。", "近日逢吾子，中心歎筆精。", "衆人皆祿位，所貴在誠明。", "努力唐虞際，期於大有成。"]'),
('415eca78-2163-4cab-8025-9787feb04213','送黄銑應舉','李覯','宋','宋诗','song-poetry','','[]','先世宦不達，少年才已雄。',48,'全唐诗/poet.song.20000.json','["先世宦不達，少年才已雄。", "何人爲父執，獨自振家風。", "物色營求廣，賓興禮數隆。", "孤寒今有望，太守漢吳公。"]'),
('9f9f175d-1982-4749-9b73-6ec73d7654ce','夏日郊園','李覯','宋','宋诗','song-poetry','','[]','三徑是生涯，朋游日已賒。',48,'全唐诗/poet.song.20000.json','["三徑是生涯，朋游日已賒。", "野情饒皓鶴，寒氣入甘瓜。", "移竹調風韻，疏泉浴月華。", "塵埃應附勢，不肯到貧家。"]'),
('5aa8ac5b-4342-4c10-9645-7a12179b4e79','寄黄晞','李覯','宋','宋诗','song-poetry','','[]','長憶黄夫子，才高行亦淳。',48,'全唐诗/poet.song.20000.json','["長憶黄夫子，才高行亦淳。", "世情輕近事，見貫即常人。", "何力康時務，將身役路塵。", "七閩山水國，是處好安貧。"]'),
('c2fc71ab-261e-4623-826b-6bc3ffe6d6d1','送黄介夫','李覯','宋','宋诗','song-poetry','','[]','短亭車馬地，送子一盤桓。',48,'全唐诗/poet.song.20000.json','["短亭車馬地，送子一盤桓。", "不畏離羣久，所嗟行路難。", "曬衣雲日薄，撲面水風酸。", "聖有中庸訓，時時著意看。"]'),
('def86d7e-6f6a-4203-b4ac-2a8549961a2f','送山甫','李覯','宋','宋诗','song-poetry','','[]','喜爾年將壯，爲儒志可嘉。',48,'全唐诗/poet.song.20000.json','["喜爾年將壯，爲儒志可嘉。", "鄉閭知行實，場屋見辭華。", "公道方無壅，君門況不遐。", "直應千里足，世世出吾家。"]'),
('5759625a-9b3c-4e1b-b69e-26563b782a50','送沈郎中','李覯','宋','宋诗','song-poetry','','[]','僞飾久終變，具誠老益純。',48,'全唐诗/poet.song.20000.json','["僞飾久終變，具誠老益純。", "官爲郎位貴，家似舊時貧。", "去作吾民福，歸尋楚水濱。", "他年名粗立，林下願相親。"]'),
('856a72a1-838d-45cf-b88f-09edc1bcc7ea','送江茂才','李覯','宋','宋诗','song-poetry','','[]','少小尚英奇，高談與衆違。',48,'全唐诗/poet.song.20000.json','["少小尚英奇，高談與衆違。", "久窮纔信命，遠客合思歸。", "簞食非無樂，京塵誤入衣。", "雲山仍舊好，況是覲庭闈。"]'),
('dd612571-8cb3-445a-a0f7-eec8c374cd51','贈端上人','李覯','宋','宋诗','song-poetry','','[]','佛法本無二，誰論律與禪。',48,'全唐诗/poet.song.20000.json','["佛法本無二，誰論律與禪。", "水行到處入，月出有時圓。", "事去何嘗念，忙中不廢眠。", "松堂白日永，幡影自飄然。"]'),
('c2bd49ca-1231-4520-973d-9090df68dc88','千福寺昧軒','李覯','宋','宋诗','song-poetry','','[]','何人指蒙昧，題作此軒名。',48,'全唐诗/poet.song.20000.json','["何人指蒙昧，題作此軒名。", "天理自晝夜，道心無晦明。", "用當羣物化，舍去一毛輕。", "磊磊山前寺，時聞鐘磬聲。"]'),
('d1b8c36d-613d-4755-b03d-7e687e29da3e','怡山長慶寺','李覯','宋','宋诗','song-poetry','','[]','行行金碧裏，氣象怳如春。',48,'全唐诗/poet.song.20000.json','["行行金碧裏，氣象怳如春。", "不記來時路，自嫌衣上塵。", "院香知有佛，僧靜似無人。", "十載京華夢，相逢一欠申。"]'),
('fbf7e56b-eed1-4720-af07-ce7b294f471e','傅翼甘圃','李覯','宋','宋诗','song-poetry','','[]','老圃君何學，中心切養親。',48,'全唐诗/poet.song.20000.json','["老圃君何學，中心切養親。", "從來啜菽處，便作采蘭人。", "百行當無愧，三牲未足珍。", "孝廉方察舉，勉勉詎長貧。"]'),
('1df7780c-f61f-4f27-a4b3-75e31793d967','林屯田思軒','李覯','宋','宋诗','song-poetry','','[]','慮遠無如靜，茲軒得地幽。',48,'全唐诗/poet.song.20000.json','["慮遠無如靜，茲軒得地幽。", "一官雖智效，萬仞更心游。", "風月趨吟筆，乾坤入坐籌。", "延英期上對，豈是爲身謀。"]'),
('db81cd01-99ff-48b1-82d3-34adef617018','迴明上人詩卷','李覯','宋','宋诗','song-poetry','','[]','學佛有餘力，吟詩過一生。',48,'全唐诗/poet.song.20000.json','["學佛有餘力，吟詩過一生。", "情閑氣燄少，句好琢磨成。", "栢竹門庭古，冰霜筆硯清。", "輸他飽食者，終日自無營。"]'),
('36feff4c-ecdb-49a7-bd6c-e7729f53469e','聽周大師琴','李覯','宋','宋诗','song-poetry','','[]','已解琴中意，更加絃上聲。',48,'全唐诗/poet.song.20000.json','["已解琴中意，更加絃上聲。", "他人鄭衛雜，此手鬼神驚。", "深夜衆籟息，寒天孤月明。", "四鄰應得睡，濁酒且同傾。"]'),
('029137e1-c337-4765-93e8-8f5b27185da5','送覺師西遊乞御書','李覯','宋','宋诗','song-poetry','','[]','累聖多材藝，留神翰墨間。',48,'全唐诗/poet.song.20000.json','["累聖多材藝，留神翰墨間。", "皇墳非小道，玉版徧藏山。", "上士持三學，西行謁九關。", "奎華如可捧，歸伴白雲閒。"]'),
('8103a3f5-438f-4c17-a2f6-df166be468b8','送分司吳太博還鄉','李覯','宋','宋诗','song-poetry','','[]','休官衆未許，分政且歸閩。',48,'全唐诗/poet.song.20000.json','["休官衆未許，分政且歸閩。", "名係金閨彥，身爲蕙帳人。", "林泉新得主，冠履漸無塵。", "知足應常足，安能更問津。"]'),
('7cff3c67-c92b-4f41-8169-9cec53c4bcf7','送任大中','李覯','宋','宋诗','song-poetry','','[]','真僞少分別，吁嗟此世情。',48,'全唐诗/poet.song.20000.json','["真僞少分別，吁嗟此世情。", "西施作老婢，南郭逞新聲。", "命合生來困，詩應沒後名。", "旅游何所得，赤日又徒行。"]'),
('0ac9058d-246c-405c-93ed-d76c06b770c5','送杜奉職','李覯','宋','宋诗','song-poetry','','[]','青紫皆同道，稀曾到薜蘿。',48,'全唐诗/poet.song.20000.json','["青紫皆同道，稀曾到薜蘿。", "感君非我輩，無事每來過。", "此別當貧病，何年共醉歌。", "人生有後會，爭奈鬢雙皤。"]'),
('31e4429e-26fb-4f8d-9565-36187f89150f','送陽曲蔡尉','李覯','宋','宋诗','song-poetry','','[]','鳳皇貴在德，孔翠豈無文。',48,'全唐诗/poet.song.20000.json','["鳳皇貴在德，孔翠豈無文。", "詩禮多承訓，賢能逈出羣。", "談清蛻塵滓，志大躡煙雲。", "更喜并州牧，豪英天下聞。"]'),
('ae5d7790-1fc7-492a-809b-d61f3aa91303','送武陵令','李覯','宋','宋诗','song-poetry','','[]','之子當爲邑，吾朝信擇人。',48,'全唐诗/poet.song.20000.json','["之子當爲邑，吾朝信擇人。", "位卑難立事，任重合憂民。", "榘瓠多遺種，桃源即近隣。", "登臨如有見，才思日應新。"]'),
('a016206c-be7f-41da-8a8a-5bb78f969757','送酸棗鄧主簿','李覯','宋','宋诗','song-poetry','','[]','畿縣官雖小，京華日可親。',48,'全唐诗/poet.song.20000.json','["畿縣官雖小，京華日可親。", "文章成薄俗，交結最難人。", "典學應無廢，存誠況已純。", "邦工尋尺用，杞梓詎沉淪。"]'),
('7434aeda-d525-4cd2-96b3-5dca9c75f66c','送仙遊知縣許延評','李覯','宋','宋诗','song-poetry','','[]','策名曾未幾，奮迅出埃塵。',48,'全唐诗/poet.song.20000.json','["策名曾未幾，奮迅出埃塵。", "陋巷潛心久，亨衢得意新。", "君恩方責報，民業近多貧。", "莫學悠悠者，謀身不爲人。"]'),
('4e4d680a-6784-4c73-a99c-99e5cab6da14','送杜寺丞知永城','李覯','宋','宋诗','song-poetry','','[]','薦表同時入，天衢自此通。',48,'全唐诗/poet.song.20000.json','["薦表同時入，天衢自此通。", "弦歌新邑宰，清白舊家風。", "官舍隋河北，離觴華谷東。", "勖哉松栢操，咫尺是堯聰。"]'),
('5de99dbc-6518-4c0d-a861-3aefe1c80b3f','迴廖解元所業','李覯','宋','宋诗','song-poetry','','[]','昔者聞鄉舉，良田恐甚蕪。',48,'全唐诗/poet.song.20000.json','["昔者聞鄉舉，良田恐甚蕪。", "于今觀日益，珍樹已垂珠。", "衆惡吾雖察，謙卑孰敢踰。", "師賢明訓在，只此是亨衢。"]'),
('2bb871ca-ca64-4e02-8078-b61bd879672b','送張寺丞','李覯','宋','宋诗','song-poetry','','[]','三載居鄰縣，得聞金玉音。',48,'全唐诗/poet.song.20000.json','["三載居鄰縣，得聞金玉音。", "路遥相見少，道合受知深。", "已矣瓜時戍，悠哉魏闕心。", "歸舟望不及，白日隠寒林。"]'),
('49393ed9-1ff6-48a5-9a38-b39dca067651','送何祕丞','李覯','宋','宋诗','song-poetry','','[]','吳人作蜀官，萬里泝驚湍。',48,'全唐诗/poet.song.20000.json','["吳人作蜀官，萬里泝驚湍。", "地俗雖雲異，民情想一般。", "智明終戒察，政惠不須寬。", "前史多循吏，乘閑更熟看。"]'),
('16f335f2-e452-47cd-a9b5-340bf782bd04','送劍州張掾','李覯','宋','宋诗','song-poetry','','[]','名在鄉書久，恩由父任優。',48,'全唐诗/poet.song.20000.json','["名在鄉書久，恩由父任優。", "從今紹清白，即此是箕裘。", "交結多良士，經過半舊游。", "舉知應有望，鴻翼佇橫秋。"]'),
('69718dca-8e48-472f-8af6-c19fe39b1ce3','送演教大師東遊','李覯','宋','宋诗','song-poetry','','[]','野客相知久，年來髪漸華。',48,'全唐诗/poet.song.20000.json','["野客相知久，年來髪漸華。", "衣冠從異教，言行似儒家。", "通塞隨天命，遨遊徧海涯。", "武夷應有會，好去醉流霞。"]'),
('8c793974-e8d7-4811-9281-1a463ef3d486','寄贈福山長老','李覯','宋','宋诗','song-poetry','','[]','時世重因循，師何獨苦辛。',48,'全唐诗/poet.song.20000.json','["時世重因循，師何獨苦辛。", "潔齋徒衆散，剛直里閭嗔。", "游藝能濟物，舊交多雅人。", "雲山雖好住，住久轉勞神。"]'),
('b32bc6a4-6d8e-4626-b337-b62251d3d90f','書樓夏晚','李覯','宋','宋诗','song-poetry','','[]','地僻無他管，樓危有剩凉。',72,'全唐诗/poet.song.20000.json','["地僻無他管，樓危有剩凉。", "遠流通越派，殘日共秦光。", "鳥道頑雲黑，人家病葉黄。", "高情夢箕潁，閑景畫瀟湘。", "山藥香多桂，漁歌濁少商。", "太平知可喜，何者是簪裳。"]'),
('8f38c5f2-ce12-4663-aba4-f83600a7c4d1','小杉','李覯','宋','宋诗','song-poetry','','[]','小杉高丈餘，體直立還孤。',72,'全唐诗/poet.song.20000.json','["小杉高丈餘，體直立還孤。", "任過千年雪，應無一節枯。", "鬼狂從髮解，龍長怕鱗麄。", "怪狀春寧笑，清聲月所娛。", "地終存古氣，景合在仙圖。", "不作明堂用，良工莫厚誣。"]'),
('8b0dfdae-dfe1-4c26-9c80-8c118d32f4fa','乾元節羣臣祝壽小人無位以詩繼之','李覯','宋','宋诗','song-poetry','','[]','帝命當敷佑，民生有厥初。',72,'全唐诗/poet.song.20000.json','["帝命當敷佑，民生有厥初。", "千秋唐節日，萬國禹朝車。", "韶美笙鏞外，需亨飲食餘。", "神仙似姑射，夢想即華胥。", "嘉會誠難得，愚忠敢自疎。", "古人誰最壽，無逸在周書。"]'),
('c46e5057-1cf4-4232-95b8-0dcf1d6d6516','悶書','李覯','宋','宋诗','song-poetry','','[]','行行四月晦，絺綌未能裁。',72,'全唐诗/poet.song.20000.json','["行行四月晦，絺綌未能裁。", "天氣疑無定，春寒恐再來。", "襲衣從汗浹，交扇取風回。", "野秀深成黑，鑪薰冷作媒。", "年高情已淡，俗薄意多猜。", "李杜今何在，芳樽誰與開。"]'),
('5d034f32-b6c7-443b-8aba-49752ab19075','同徐殿丞遊麻姑山陳屯田聞之以詩見寄次韻第一首','李覯','宋','宋诗','song-poetry','','[]','良友嗟塵網，相期物外遊。',72,'全唐诗/poet.song.20000.json','["良友嗟塵網，相期物外遊。", "求珠非赤水，不死是丹丘。", "几上麟交擗，樽中蟻亂浮。", "仙家一度醉，人世幾千秋。", "藥氣多留鼎，茶香細出甌。", "堯人方曠蕩，容易學巢由。"]'),
('317c0730-4a25-4346-ba5b-b18d2b573e5e','送李著作知柳州','李覯','宋','宋诗','song-poetry','','[]','到官十五月，太半在他邦。',96,'全唐诗/poet.song.20000.json','["到官十五月，太半在他邦。", "惠術未施一，公心無與雙。", "剖符新使粵，盡室始浮江。", "地理將分嶺，行程即下瀧。", "旅愁侵酒座，秋色漏船窗。", "屬吏誰非懾，羣蠻不易降。", "人稀財豈厚，俗異性多惷。", "自此觀賢業，洪鐘且試撞。"]'),
('8dccbaea-5aa6-44d7-97d6-1123a734089c','送知縣蘇祕丞移英州','李覯','宋','宋诗','song-poetry','','[]','大邑曰南城，唯君治道行。',120,'全唐诗/poet.song.20000.json','["大邑曰南城，唯君治道行。", "何曾設鉤距，到底是聰明。", "鼎在神姦伏，鷹來鳥雀驚。", "詐窮多自笑，刑重亦知平。", "府史如廉士，農桑學頌聲。", "在官嗟不久，丕績已垂成。", "嶺路當過庾，州圖喜得英。", "遠人天與幸，弊俗日將清。", "遊刃非無地，摶風別有程。", "上心應寤寐，彝器待書名。"]'),
('84564d61-a432-428d-a09d-a96be12e7a9e','夏日雨中','李覯','宋','宋诗','song-poetry','','[]','一雨遂不止，我行當此窮。',120,'全唐诗/poet.song.20000.json','["一雨遂不止，我行當此窮。", "蜀東天亦漏，堯後水猶洪。", "大點有片重，密濛無寸空。", "曉唯壺箭覺，暖似炭爐通。", "書筆提梅洗，征衣擘潤烘。", "簾間稀去燕，枕下即鳴蟲。", "竹粉千腰白，桃皮半頰紅。", "物華嬌自衒，天意猛相攻。", "酒退愁城外，吟興憤涌中。", "遣誰咨畢宿，留作旱時功。"]'),
('324b7f0c-ce5f-4a03-9208-ed34ae04b865','鄉思','李覯','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u601d\u4e61", "\u5b8b\u8bd7"]','人言落日是天涯，望極天涯不見家。',32,'全唐诗/poet.song.20000.json','["人言落日是天涯，望極天涯不見家。", "已恨碧山相阻隔，碧山還被暮雲遮。"]'),
('325b56e1-8101-4e3b-98b0-45fcfc6e60e1','少年','李覯','宋','宋诗','song-poetry','','[]','新翻曲調恐人傳，不許高聲唱玳筵。',32,'全唐诗/poet.song.20000.json','["新翻曲調恐人傳，不許高聲唱玳筵。", "金獸也嫌春態淺，向風噴作綠楊烟。"]'),
('372948d9-1122-4257-8c38-29c3bd17b588','自勉','李覯','宋','宋诗','song-poetry','','[]','月欲東生日又西，莫隨兒女醉明時。',32,'全唐诗/poet.song.20000.json','["月欲東生日又西，莫隨兒女醉明時。", "黄泉一向埋愚鬼，不與人間史筆知。"]'),
('46b4e84b-77e5-4c4d-8d03-88c7cea6bb81','戲題玉臺集','李覯','宋','宋诗','song-poetry','','[]','江右君臣筆力雄，一言宮體便移風。',32,'全唐诗/poet.song.20000.json','["江右君臣筆力雄，一言宮體便移風。", "始知姬旦無才思，祗把豳詩詠女功。"]'),
