('d1bafb61-65c8-41b0-b65c-61780d11c649','麻源題壁','李覯','宋','宋诗','song-poetry','','[]','一到麻源日又曛，幾迴欲起却逡巡。',32,'全唐诗/poet.song.20000.json','["一到麻源日又曛，幾迴欲起却逡巡。", "世間豈是無山水，不奈閑人好聒人。"]'),
('f98098fd-d7b7-4022-80bc-b2c2f0139c95','馬嵬驛','李覯','宋','宋诗','song-poetry','','[]','六軍剛要罪楊妃，空使君王血淚垂。',32,'全唐诗/poet.song.20000.json','["六軍剛要罪楊妃，空使君王血淚垂。", "何事國忠誅死後，不將林甫更鞭尸。"]'),
('19fe9a52-0ac6-480c-b3db-7d4a6c69ceab','齊世家','李覯','宋','宋诗','song-poetry','','[]','莫以荒淫便責君，大都危亂爲無臣。',32,'全唐诗/poet.song.20000.json','["莫以荒淫便責君，大都危亂爲無臣。", "若教管仲身長在，何患夫人更六人。"]'),
('abb4a53a-f996-49b8-8f34-dad08ba6ca62','漢宮','李覯','宋','宋诗','song-poetry','','[]','哀平外立國權分，只爲當時乏嗣君。',32,'全唐诗/poet.song.20000.json','["哀平外立國權分，只爲當時乏嗣君。", "試問莽新誰佐命，最應飛燕是元勳。"]'),
('ba8cb21a-82e1-4eee-9bf0-91ba34f6055b','景陽宮井','李覯','宋','宋诗','song-poetry','','[]','以色從人自古然，幸逢聖主得稱賢。',32,'全唐诗/poet.song.20000.json','["以色從人自古然，幸逢聖主得稱賢。", "太王姜女來岐下，應不相將墮井泉。"]'),
('08b3273d-90a0-4e48-a6f4-e0e2bdea80e1','燕雀  其一','李覯','宋','宋诗','song-poetry','','[]','燕子從來巧語聲，主人相愛是常情。',32,'全唐诗/poet.song.20000.json','["燕子從來巧語聲，主人相愛是常情。", "黄頭老雀何能解，飽食官倉過一生。"]'),
('7d863566-35a6-4300-9735-4a353254eb20','燕雀  其二','李覯','宋','宋诗','song-poetry','','[]','繡戶珠簾見最頻，暖來寒去但安身。',32,'全唐诗/poet.song.20000.json','["繡戶珠簾見最頻，暖來寒去但安身。", "翟公門下是飛入，全勝交情斗頓人。"]'),
('9c02a9fc-13a7-4a66-817b-13923a1301ee','張禹','李覯','宋','宋诗','song-poetry','','[]','漢室尊儒未得真，只求學藝不知人。',32,'全唐诗/poet.song.20000.json','["漢室尊儒未得真，只求學藝不知人。", "君王幸已疑王氏，苦把春秋助賊臣。"]'),
('69fb2353-1688-474d-a3b8-beddf1c6ac12','孔光','李覯','宋','宋诗','song-poetry','','[]','王莽欲爲先與草，董賢將過自迎門。',32,'全唐诗/poet.song.20000.json','["王莽欲爲先與草，董賢將過自迎門。", "省中樹木何閑事，却對妻孥不肯言。"]'),
('ecf95818-18fc-4a56-a902-44130eb8481f','元紀  其一','李覯','宋','宋诗','song-poetry','','[]','孝宣應是不知書，便謂先王似豎儒。',32,'全唐诗/poet.song.20000.json','["孝宣應是不知書，便謂先王似豎儒。", "若使周家純任德，親如管蔡忍行誅。"]'),
('074b8074-c191-46ae-94d6-8bd891c7ae5b','元紀  其二','李覯','宋','宋诗','song-poetry','','[]','君道乾剛豈易柔，謬牽文義致優游。',32,'全唐诗/poet.song.20000.json','["君道乾剛豈易柔，謬牽文義致優游。", "高皇馬上辛勤得，總被儒生斷送休。"]'),
('1ce15364-a8ca-4c76-8132-81a8d968390a','聞鶑','李覯','宋','宋诗','song-poetry','','[]','纔轉歌喉碧樹枝，驚飛還避巧丸兒。',32,'全唐诗/poet.song.20000.json','["纔轉歌喉碧樹枝，驚飛還避巧丸兒。", "可憐蜂蝶無言語，入徧花房人未知。"]'),
('6e44e3d3-9509-4f3a-9eca-2947b06b0918','學北堂有海棠一株顔色至佳凋落稍速憶而爲詩','李覯','宋','宋诗','song-poetry','','[]','來時初見滿枝紅，璧碎珠沉幾日中。',32,'全唐诗/poet.song.20000.json','["來時初見滿枝紅，璧碎珠沉幾日中。", "宋玉有鄰誠耐事，三年猶在短牆東。"]'),
('f7645bd3-6f92-4046-8e2f-c587893b4e68','玉胡蝶花','李覯','宋','宋诗','song-poetry','','[]','胡蝶生來只愛花，春工描樣作奇葩。',32,'全唐诗/poet.song.20000.json','["胡蝶生來只愛花，春工描樣作奇葩。", "莊周有夢何曾覺，冰雪肌膚落幾家。"]'),
('d7da8fa7-4ce5-4c4e-aad0-80ee73fb45dd','次韻答陳殿丞南塘觀魚見寄','李覯','宋','宋诗','song-poetry','','[]','鱗鬣摧殘幾許年，水平風靜得潛淵。',32,'全唐诗/poet.song.20000.json','["鱗鬣摧殘幾許年，水平風靜得潛淵。", "喜無美味登君俎，且學驪龍盡日眠。"]'),
('3828e0ec-2b9e-4ba4-a1ac-5f773b6065d4','送傅野','李覯','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','國學先生石與孫，金鈴木舌士林間。',32,'全唐诗/poet.song.20000.json','["國學先生石與孫，金鈴木舌士林間。", "欲將天下觀諸掌，之子從今上泰山。"]'),
('a2a2d13e-6a84-48b1-81d2-507f6693d05b','送杜萬','李覯','宋','宋诗','song-poetry','','[]','谷口生涯已是貧，素衣還擬冒京塵。',32,'全唐诗/poet.song.20000.json','["谷口生涯已是貧，素衣還擬冒京塵。", "因風早寄登科信，裝點江南幾日春。"]'),
('5e84b6c9-550b-449e-92d3-e4110906fb91','儒行','李覯','宋','宋诗','song-poetry','','[]','一死相從患難時，何人能與古人齊。',32,'全唐诗/poet.song.20000.json','["一死相從患難時，何人能與古人齊。", "酈生泉下還知否，賣友而今價轉低。"]'),
('658fca3e-a0ff-49cc-93ba-9a8d197fe261','感義','李覯','宋','宋诗','song-poetry','','[]','懊惱常人只好儒，古來忠義出屠沽。',32,'全唐诗/poet.song.20000.json','["懊惱常人只好儒，古來忠義出屠沽。", "試將朱亥相倫擬，幾箇衣冠是丈夫。"]'),
('d666de27-e59f-4f5e-9ad8-f4b9b8446098','屈原','李覯','宋','宋诗','song-poetry','','[]','秋來張翰偶思鱸，滿筯鮮紅食有餘。',32,'全唐诗/poet.song.20000.json','["秋來張翰偶思鱸，滿筯鮮紅食有餘。", "何事靈均不知退，却將閑肉付江魚。"]'),
('009d0e84-773d-4925-8c15-d4b0a69ba253','宋玉','李覯','宋','宋诗','song-poetry','','[]','世間佳麗每專房，一顧多應萬事荒。',32,'全唐诗/poet.song.20000.json','["世間佳麗每專房，一顧多應萬事荒。", "夢裏若無真實處，不妨頻爲賦高唐。"]'),
('1ae92316-7a18-4c8f-accb-9d6d28321914','贈日者鄒生','李覯','宋','宋诗','song-poetry','','[]','賢不必通愚不窮，悠悠無處問蒼穹。',32,'全唐诗/poet.song.20000.json','["賢不必通愚不窮，悠悠無處問蒼穹。", "可憐富貴君之柄，斷在山人指掌中。"]'),
('91e4b3ea-b503-4ea0-b606-7dc655b25720','送夏旦赴舉','李覯','宋','宋诗','song-poetry','','[]','嶺梅初盡草初生，馬上春風酒易醒。',32,'全唐诗/poet.song.20000.json','["嶺梅初盡草初生，馬上春風酒易醒。", "好共大鵬雙奮擊，此行有路到南溟。"]'),
('aec56691-18fa-4ff0-8cd7-1866bed76309','送春','李覯','宋','宋诗','song-poetry','','[]','宜春臺上送春歸，淚滴金杯不自知。',32,'全唐诗/poet.song.20000.json','["宜春臺上送春歸，淚滴金杯不自知。", "懊惱黄鶑解言語，飛來唯見落花枝。"]'),
('71f49ee4-0055-4681-b822-20641cbf000c','曉角','李覯','宋','宋诗','song-poetry','','[]','腸斷城頭畫角聲，燈青月黑酒微醒。',32,'全唐诗/poet.song.20000.json','["腸斷城頭畫角聲，燈青月黑酒微醒。", "濃香夢裏誰曾管，只有離人夜夜聽。"]'),
('f5fe8fdc-ef1b-4878-addc-ea7703fccdde','送丁正臣','李覯','宋','宋诗','song-poetry','','[]','鉛槧辛勤四十年，摶風不上鬢霜寒。',32,'全唐诗/poet.song.20000.json','["鉛槧辛勤四十年，摶風不上鬢霜寒。", "朱門何處是知己，短褐空瓢行路難。"]'),
('25227495-4d68-4b45-b205-4d777004fb7d','惜才','李覯','宋','宋诗','song-poetry','','[]','子雲辭賦似相如，自說雕蟲異壯夫。',32,'全唐诗/poet.song.20000.json','["子雲辭賦似相如，自說雕蟲異壯夫。", "何事犬羊誇質素，患他人愛著貂狐。"]'),
('0c320f6f-3cd8-4c4e-aa59-dea901ebb3ae','登越山','李覯','宋','宋诗','song-poetry','','[]','臘後梅花破碎香，望中情地轉凄凉。',32,'全唐诗/poet.song.20000.json','["臘後梅花破碎香，望中情地轉凄凉。", "遊山只道尋高處，高處何曾見故鄉。"]'),
('817e3a75-b223-4902-882a-17ad705fd35d','送古山人','李覯','宋','宋诗','song-poetry','','[]','喜聞吉事怕聞凶，天下人心處處同。',32,'全唐诗/poet.song.20000.json','["喜聞吉事怕聞凶，天下人心處處同。", "乍出山來言語拙，莫將刺字謁王公。"]'),
('198b98e3-8276-4965-af4e-bafcb4d0d5aa','送毗師西遊','李覯','宋','宋诗','song-poetry','','[]','望望王城十二門，青山行盡入紅塵。',32,'全唐诗/poet.song.20000.json','["望望王城十二門，青山行盡入紅塵。", "近來富貴皆天與，到處應多問命人。"]'),
('03063e57-e709-4dab-8ec5-fb4ecab93357','送春寄呈祖袁州  其一','李覯','宋','宋诗','song-poetry','','[]','去年春盡在宜春，醉送東風淚滿巾。',32,'全唐诗/poet.song.20000.json','["去年春盡在宜春，醉送東風淚滿巾。", "今日春歸倍惆悵，相逢不是去年人。"]'),
('fe6c8403-08c4-4d99-a399-e0b06c6145c8','送春寄呈祖袁州  其二','李覯','宋','宋诗','song-poetry','','[]','東君此去幾時來，雪裏梅根待暖迴。',32,'全唐诗/poet.song.20000.json','["東君此去幾時來，雪裏梅根待暖迴。", "莫似仙家寥落甚，蟠桃千歲始重開。"]'),
('989d020a-32cc-44f4-87f5-03c52456b736','次韻陳屯田途中所寄','李覯','宋','宋诗','song-poetry','','[]','封豕長蛇戰嶺南，何人肉食不懷慙。',32,'全唐诗/poet.song.20000.json','["封豕長蛇戰嶺南，何人肉食不懷慙。", "只今唯有高眠好，風弄松聲水濺庵。"]'),
('b6c44333-56d6-4a53-9fa8-4d7bb375ec63','正月二十日俗號天穿日以煎餠置屋上謂之補天感而爲詩','李覯','宋','宋诗','song-poetry','','[]','媧皇沒後幾多年，夏伏冬愆任自然。',32,'全唐诗/poet.song.20000.json','["媧皇沒後幾多年，夏伏冬愆任自然。", "只有人間閑婦女，一枚煎餠補天穿。"]'),
('f0554d2f-ab5c-47d2-a76d-5403f1c9dd86','送薛經','李覯','宋','宋诗','song-poetry','','[]','多能未必有相知，況是東南義士稀。',32,'全唐诗/poet.song.20000.json','["多能未必有相知，況是東南義士稀。", "京洛路長何日到，風塵依舊化人衣。"]'),
('0e6a11e9-aae1-4841-91f7-59095f454cd4','僧志月碧雲軒改爲景雲軒因書  其一','李覯','宋','宋诗','song-poetry','','[]','長見江淹雜體詩，碧雲非是惠休詞。',32,'全唐诗/poet.song.20000.json','["長見江淹雜體詩，碧雲非是惠休詞。", "試言日暮佳人怨，何事高僧却得知。"]'),
('62ae494d-4b70-4336-b48e-069d7d2964cb','僧志月碧雲軒改爲景雲軒因書  其二','李覯','宋','宋诗','song-poetry','','[]','景雲持律冠當年，遺迹雖沉古寺存。',32,'全唐诗/poet.song.20000.json','["景雲持律冠當年，遺迹雖沉古寺存。", "釋子若能精進去，便應題作景雲軒。"]'),
('a6bb3106-5b10-41ed-b027-2ed5d3572094','書景雲軒壁','李覯','宋','宋诗','song-poetry','','[]','二江斜入似娥眉，盡日凭高把酒巵。',32,'全唐诗/poet.song.20000.json','["二江斜入似娥眉，盡日凭高把酒巵。", "貧賤別應無好處，猛忙中是我閑時。"]'),
('a1a7bbbb-a382-4ca2-84fb-8cd0f819ca4d','因遊華子崗題麻源壁','李覯','宋','宋诗','song-poetry','','[]','平生猶未識紅泉，今日纔遊石磴邊。',32,'全唐诗/poet.song.20000.json','["平生猶未識紅泉，今日纔遊石磴邊。", "宿雨半晴秋草濕，困來無處可閑眠。"]'),
('14efef34-daa4-45a7-8373-89dc55dbdc4e','苦雨初霽','李覯','宋','宋诗','song-poetry','','[]','積陰爲患恐沈綿，革去方驚造化權。',64,'全唐诗/poet.song.20000.json','["積陰爲患恐沈綿，革去方驚造化權。", "天放舊光還日月，地將濃秀與山川。", "泥途漸少車聲活，林薄初乾果味全。", "寄語殘雲好知足，莫依河漢更油然。"]'),
('33a6d58a-9bb0-47c5-bb46-7f0d3c04fe17','野人','李覯','宋','宋诗','song-poetry','','[]','村落蒼茫半草茅，路無車轍水無橋。',64,'全唐诗/poet.song.20000.json','["村落蒼茫半草茅，路無車轍水無橋。", "婚姻取足唯春繭，鹽酪歸來待晚樵。", "一樣寬衣疑效古，幾人華髮未經徭。", "相逢不會寒溫語，借問官家合是堯。"]'),
('9c2e9765-7d50-4152-b82d-bc2d6b929e6a','書麻姑廟','李覯','宋','宋诗','song-poetry','','[]','流欲好仙方學道，至人樂道自成仙。',64,'全唐诗/poet.song.20000.json','["流欲好仙方學道，至人樂道自成仙。", "飛昇若也由貪欲，紫府還應用詐權。", "塵裏笙歌千古夢，洞中星斗幾家天。", "無心便是歸真日，姹女河車總謾傳。"]'),
('01ee43bd-109a-4404-b89f-d09661c2187d','客有話故丁祕監京師舊宅因而傷之','李覯','宋','宋诗','song-poetry','','[]','等閑榮謝已悉聞，況話三公極寵身。',64,'全唐诗/poet.song.20000.json','["等閑榮謝已悉聞，況話三公極寵身。", "青史尚爲今世事，朱門不是舊時人。", "文章散入諸蕃口，花藥留添上國春。", "生死交情渾易見，有誰過此爲霑巾。"]'),
('7d91df36-fd7f-437e-99e6-04f716839b5c','五龍塘','李覯','宋','宋诗','song-poetry','','[]','世傳鱗物有蟠時，分得寒泉住翠微。',64,'全唐诗/poet.song.20000.json','["世傳鱗物有蟠時，分得寒泉住翠微。", "天命雖教爲潤澤，神心終是索虔祈。", "一圍石岸刓無迹，幾族陰雲禁不飛。", "風脚斗回波面黑，向人渾似逞巖威。"]'),
('6a39e7c3-a3b5-47a5-8a1e-2ba9401f24e4','寄小兒','李覯','宋','宋诗','song-poetry','','[]','兩世煢煢各一人，生來且喜富精神。',64,'全唐诗/poet.song.20000.json','["兩世煢煢各一人，生來且喜富精神。", "欲教齠齔從師學，祗恐文章誤爾身。", "但有犁鋤終得飽，莫看紈綺便嫌貧。", "不知別後啼多少，苦問家僮說未真。"]'),
('76c38410-e8cd-49b7-9b0a-5ad3281cd7a9','季夏雨中宛有秋色四望之際百感生焉因題於紙','李覯','宋','宋诗','song-poetry','','[]','粟花時節雨脩脩，莫道如秋即是秋。',64,'全唐诗/poet.song.20000.json','["粟花時節雨脩脩，莫道如秋即是秋。", "客路幾千成大夢，年華一半落東流。", "眼存將聖生前筆，心得騷人格外愁。", "微物若教無所失，塵埃猶願補嵩丘。"]'),
('3781b848-bbd0-4f4a-8538-f04032ee826f','秋懷','李覯','宋','宋诗','song-poetry','','[]','褚冠斜頂對清秋，病骨支撐懶上樓。',64,'全唐诗/poet.song.20000.json','["褚冠斜頂對清秋，病骨支撐懶上樓。", "輔世功夫何日是，少年滋味此生休。", "山含紅樹隨時老，天带黄昏一例愁。", "自笑酒腸空半在，前村無處典鷞裘。"]'),
('a06c1534-88c7-4ec3-9b25-614e8951e6fe','書松陵唱和','李覯','宋','宋诗','song-poetry','','[]','天命相逢陸與皮，當年才調兩權奇。',64,'全唐诗/poet.song.20000.json','["天命相逢陸與皮，當年才調兩權奇。", "朝端未有輸忠處，詩外應無用力時。", "意古直摩軒昊頂，言微都洩鬼神私。", "近來此道中興也，泉下英魂知不知。"]'),
('701c7c9d-afbb-404b-9997-d949db7b5880','七夕','李覯','宋','宋诗','song-poetry','','[]','天孫何許是來時，月意愔愔露氣微。',64,'全唐诗/poet.song.20000.json','["天孫何許是來時，月意愔愔露氣微。", "可道星河難得過，自緣烏鵲合高飛。", "秋宵已勝春宵短，今會還如古會稀。", "早晚望夫能化石，盡分人世作支機。"]'),
('291c4d31-614a-4d20-bd53-7612bc5f5aea','早起有懷','李覯','宋','宋诗','song-poetry','','[]','草草西風動葛衣，呼僮前啟竹間扉。',64,'全唐诗/poet.song.20000.json','["草草西風動葛衣，呼僮前啟竹間扉。", "山僧好睡鐘聲晏，社戶多貧酒氣微。", "豈是客愁渾較可，祗因書卷解忘歸。", "旴江百里清無滓，枉屬閑人坐釣磯。"]'),
('b4f5ac4e-2f75-4b58-aad4-1f1f3ac59252','留題歸安尉凝碧堂','李覯','宋','宋诗','song-poetry','','[]','騷人得助是江山，千里幽懷一凭欄。',64,'全唐诗/poet.song.20000.json','["騷人得助是江山，千里幽懷一凭欄。", "野色豈唯春晚秀，天風長似月邊寒。", "身閑暫覺塵埃遠，境勝纔知宇宙寬。", "祗恐仙壺提挈去，不教凡眼醉中看。"]'),
('b9aa1e87-5196-435a-98cf-62580abdcdbf','答張鬷嘏','李覯','宋','宋诗','song-poetry','','[]','幾年江外恣荒唐，偶脫荷衣覘國光。',64,'全唐诗/poet.song.20000.json','["幾年江外恣荒唐，偶脫荷衣覘國光。", "自是狂言無可擇，敢嗟賢路有相妨。", "謾將文史爲生業，已約漁樵共醉鄉。", "多謝故人貽絕唱，爰居寧解聽鏗鏘。"]'),
('64b22a51-2c89-46a3-9132-c98d2ce7bdde','清明日作','李覯','宋','宋诗','song-poetry','','[]','遲遲日景坐成曛，聞說清明在此晨。',64,'全唐诗/poet.song.20000.json','["遲遲日景坐成曛，聞說清明在此晨。", "花卉不宜愁眼看，勾芒能爲幾人春。", "銷磨志氣多因老，點檢交游半作塵。", "欲向醉鄉聊自適，病來還厭舉杯頻。"]'),
('4ced0300-deda-41ab-ba9f-e2e2fc152318','晚思','李覯','宋','宋诗','song-poetry','','[]','一檻東風小箔開，亂山明暗水縈迴。',64,'全唐诗/poet.song.20000.json','["一檻東風小箔開，亂山明暗水縈迴。", "流年漸共春華去，暴熱還隨霽色來。", "天氣濁多人欲睡，地形卑甚物先梅。", "因知楚客迷魂處，不是江東不足哀。"]'),
('72d43d76-a892-41cc-ba30-c87c65cb395e','暮春始遊城西','李覯','宋','宋诗','song-poetry','','[]','病多無力逐紛華，三月衡門未見花。',64,'全唐诗/poet.song.20000.json','["病多無力逐紛華，三月衡門未見花。", "長恐後期成索寞，果逢殘景獨咨嗟。", "欄干倚望山空在，杯酒遲留日易斜。", "謾說明年更春色，不知園囿屬誰家。"]'),
('3cb87c4e-6263-4fdf-9f6c-d6e1490ce2b0','寄傅代言','李覯','宋','宋诗','song-poetry','','[]','交游散盡客來稀，門掩城隅晝漏遲。',64,'全唐诗/poet.song.20000.json','["交游散盡客來稀，門掩城隅晝漏遲。", "春地更無嫌草處，雨天還有詐晴時。", "輕量世事世不罪，冷笑人言人豈知。", "猶喜道途收拾早，將閑對病最相宜。"]'),
('6109a274-89f7-4be4-ae46-f2748a064c2c','丙子冬至夜酒醒','李覯','宋','宋诗','song-poetry','','[]','盡道一陽初復時，不期風雨更凄凄。',64,'全唐诗/poet.song.20000.json','["盡道一陽初復時，不期風雨更凄凄。", "凌晨出去逢人飲，沉醉歸來滿馬泥。", "多恨恐成干斗氣，欲言那得上天梯。", "燈青火冷睡半醒，殘葉打窗烏夜啼。"]'),
('768ae232-a230-4a49-84f5-b47cce6f8eda','南齋詠風','李覯','宋','宋诗','song-poetry','','[]','懊惱南窗一道風，只應天配與貧窮。',64,'全唐诗/poet.song.20000.json','["懊惱南窗一道風，只應天配與貧窮。", "不歸羅綺飄颻處，故入松篁冷淡中。", "久座披襟塵榻穩，半醒吹面月帷空。", "城邊菡萏今多少，偷得清香是爾功。"]'),
('8aa3af28-1acd-4a90-b15f-4a1afa3ee09f','小雨','李覯','宋','宋诗','song-poetry','','[]','已是蛟龍未肯忙，誰教螮蝀更相妨。',64,'全唐诗/poet.song.20000.json','["已是蛟龍未肯忙，誰教螮蝀更相妨。", "來時槁葉疎疎響，過後浮雲片片光。", "徑草微滋垂粉汗，砌沙圓滴簇蜂房。", "嗟予不及高飛鳥，先得天邊幾點凉。"]'),
('29aaa146-b488-4c1a-864c-d11f827707b1','題凈居院','李覯','宋','宋诗','song-poetry','','[]','寺門幽獨傍江城，江水清含地氣清。',64,'全唐诗/poet.song.20000.json','["寺門幽獨傍江城，江水清含地氣清。", "隔岸樓臺人醉死，遶堦松竹夏寒生。", "路經橋遠塵難過，僧占閑多俗不爭。", "唯有行吟憔悴客，這廻須去濯長纓。"]'),
('c54cac31-cef8-42dc-b58d-a7e694353def','清暉亭','李覯','宋','宋诗','song-poetry','','[]','池亭何處占清暉，只在暉江更向西。',64,'全唐诗/poet.song.20000.json','["池亭何處占清暉，只在暉江更向西。", "山上白雲如有雪，水中明月似無泥。", "郊原不改春來秀，徑路終憂客到迷。", "沈約東陽曾入詠，使君才調好留題。"]'),
('99964c16-857f-4d9b-b687-695ab147d104','往山舍道中作','李覯','宋','宋诗','song-poetry','','[]','截竹成輿不用輪，東行盡日穩宜身。',64,'全唐诗/poet.song.20000.json','["截竹成輿不用輪，東行盡日穩宜身。", "前看疊嶂如無路，每到平田始見人。", "下戶半曾差作役，朽株多已祀爲神。", "生涯一撮誠何有，且免庸兒共拜塵。"]'),
('deb4e047-0c3a-4df5-8f9c-47ba1ba0fb0e','秋晚悲懷','李覯','宋','宋诗','song-poetry','','["\u5c81\u6708", "\u79cb\u5929", "\u60b2\u79cb", "\u611f\u53f9"]','漸老多憂百事忙，天寒日短更心傷。',64,'全唐诗/poet.song.20000.json','["漸老多憂百事忙，天寒日短更心傷。", "數分紅色上黄葉，一瞬曙光成夕陽。", "春水別來應到海，小松生命合禁霜。", "壺中若逐仙翁去，待看年華幾許長。"]'),
('4c014457-3836-4b9a-a029-23d048299c6e','殘葉','李覯','宋','宋诗','song-poetry','','["\u548f\u7269", "\u6292\u60c5", "\u79cb\u5929", "\u548f\u7269\u8bd7"]','一樹摧殘幾片存，欄邊爲汝最傷神。',64,'全唐诗/poet.song.20000.json','["一樹摧殘幾片存，欄邊爲汝最傷神。", "休翻雨滴寒鳴夜，曾抱花枝暖過春。", "與影有情唯日月，遇紅無禮是泥塵。", "上陽宮女多詩思，莫寄人間取次人。"]'),
('a728cbe6-c918-4b16-8b68-8923e63f6f75','哭十姪','李覯','宋','宋诗','song-poetry','','[]','到官六月寄書迴，未病封題死後開。',64,'全唐诗/poet.song.20000.json','["到官六月寄書迴，未病封題死後開。", "一命至卑人盡得，九泉何事獨相催。", "唯憂旅櫬還鄉遠，況是親喪繼踵來。", "數世學文終若此，可憐門戶轉隳頹。"]'),
('dca71aa9-31f2-4242-bf58-f63089c63331','秋陰','李覯','宋','宋诗','song-poetry','','[]','一夜風聲曉更狂，起來庭戶頓凄凉。',64,'全唐诗/poet.song.20000.json','["一夜風聲曉更狂，起來庭戶頓凄凉。", "不知紅日在何處，時見黑雲微有光。", "天落水中兼鴈影，露啼林罅带楓香。", "愁人莫苦登高閣，說著江山已斷腸。"]'),
('51e3db77-6171-47f3-a8ca-054833362b64','寄介夫','李覯','宋','宋诗','song-poetry','','[]','天恨吾儕各一方，夕陽千度到西窗。',64,'全唐诗/poet.song.20000.json','["天恨吾儕各一方，夕陽千度到西窗。", "因循流俗今皆是，磊落如君信少雙。", "書未隔年難得報，心從薄宦始應降。", "可憐漢水無拘係，長與旴江會九江。"]'),
('bb692927-10e3-4887-a279-401357146a21','書懷寄介夫','李覯','宋','宋诗','song-poetry','','[]','棄材幸免雜輿薪，收拾緇衣出洛塵。',64,'全唐诗/poet.song.20000.json','["棄材幸免雜輿薪，收拾緇衣出洛塵。", "漸老得閑纔是性，謾言成謔且隨人。", "能傳身後須文字，要識胸中只鬼神。", "俗子不勞輕毀譽，問天長乞醉鄉春。"]'),
('f2cbf8c3-2e3e-403a-87c9-378a473b4e40','關徐','李覯','宋','宋诗','song-poetry','','[]','雲長不絕舊君情，元直終隨老母行。',64,'全唐诗/poet.song.20000.json','["雲長不絕舊君情，元直終隨老母行。", "立效報公何感慨，指心辭主更分明。", "三方本以兵攻戰，一士能爲國重輕。", "多謝曹劉存大度，任教忠孝得成名。"]'),
('8068a1b2-7d15-4ece-b425-7693e4d85c01','送張宏下第南歸','李覯','宋','宋诗','song-poetry','','[]','世家元是武夷孫，四上觀光預國賓。',64,'全唐诗/poet.song.20000.json','["世家元是武夷孫，四上觀光預國賓。", "地底豈無干斗氣，天邊爭奈飲牛人。", "田宜秫稻應多酒，路入溪山漸少塵。", "身計未諧歸計好，一樽猶可醉鄉鄰。"]'),
('cdff94d3-7944-46ab-a196-9c9e8dab28b4','葛陂逢何道士','李覯','宋','宋诗','song-poetry','','[]','十數年前別我行，相逢猶是舊顔形。',64,'全唐诗/poet.song.20000.json','["十數年前別我行，相逢猶是舊顔形。", "琴聲漸古聽來淡，藥味雖凡試最靈。", "出有酒錢天下富，住無家地浪頭萍。", "神仙可學應須學，萬里蓬萊一點青。"]'),
('fd5c3ac6-34ba-4799-8822-0d9330ccc8c3','俞秀才山風亭小飲','李覯','宋','宋诗','song-poetry','','[]','炎炎千室熱如烘，亭壓山頭獨有風。',64,'全唐诗/poet.song.20000.json','["炎炎千室熱如烘，亭壓山頭獨有風。", "雨意生獰雲彩黑，秋容細碎樹枝紅。", "半天斜日歸心動，一面平川醉眼空。", "却是夢魂無所得，人間豈少翠微宮。"]'),
('fc30bbe0-7b44-417a-bc5a-b32ce9c1f2f9','謝宋屯田見示永平錄海南編','李覯','宋','宋诗','song-poetry','','[]','多少儒衣只假塗，貴來誰肯更觀書。',64,'全唐诗/poet.song.20000.json','["多少儒衣只假塗，貴來誰肯更觀書。", "其間或以文爭勝，未見如君識有餘。", "長把六經爲準的，最應三代是權輿。", "可憐後世名空在，直釣而今豈得魚。"]'),
('eafe6d88-53fe-4880-9fef-1e825dc4e398','閩中歲暮','李覯','宋','宋诗','song-poetry','','[]','休道南人暖過冬，苦寒今與北方同。',64,'全唐诗/poet.song.20000.json','["休道南人暖過冬，苦寒今與北方同。", "霜嚴欲裂地到底，日短不行天正中。", "誰使智愚相伴老，便將榮辱斷還空。", "鄉愁莫更欺閑客，薄酒從來亦有功。"]'),
('2b59a458-4674-41ea-85f6-262e7b028b60','送侯殿直之官吉州','李覯','宋','宋诗','song-poetry','','[]','待詔何年別玉堂，筆端渾欲繼鐘王。',64,'全唐诗/poet.song.20000.json','["待詔何年別玉堂，筆端渾欲繼鐘王。", "官資未出風塵外，蹤迹曾親日月光。", "扶老只今非遠道，薦能從此有封章。", "廬陵若要高文寫，爭得滁州在故鄉。"]'),
('fa8507b4-f161-4310-9987-f9f0aa6bdfa6','偶題饒秀才谿光亭','李覯','宋','宋诗','song-poetry','','[]','北出城來駐馬蹄，君家別館幸臨谿。',64,'全唐诗/poet.song.20000.json','["北出城來駐馬蹄，君家別館幸臨谿。", "雄虹見雨遏不斷，潦水到秋痕漸低。", "萬事熱心成浩歎，一樽撩眼怕長迷。", "俗人誰會儒生意，是處醉吟還日西。"]'),
('4561ab30-f277-48f5-adfb-8e7f3ad77814','宗人宅仁知閣','李覯','宋','宋诗','song-poetry','','[]','江南盡是山水地，君子固求仁知名。',64,'全唐诗/poet.song.20000.json','["江南盡是山水地，君子固求仁知名。", "可憐塵土不到眼，只有雲泉相伴清。", "人間擾擾知何在，日暮悠悠空鬭行。", "明月一欄風一枕，醉鄉猶可過浮生。"]'),
('c3070d91-fdbf-4fb1-9391-d89ddb3c70ca','早夏偶作','李覯','宋','宋诗','song-poetry','','[]','閑愁不覺過年光，强半精神似醉鄉。',64,'全唐诗/poet.song.20000.json','["閑愁不覺過年光，强半精神似醉鄉。", "幾度雨來成惡熱，有時雲斷見斜陽。", "古人事業塵空滿，故國園林草自長。", "頼得南華憐我病，一篇齊物勝醫方。"]'),
('aa00250f-32c7-43a1-9210-7bc2e8750821','匈奴傳','李覯','宋','宋诗','song-poetry','','[]','漢家經武意如何，也信狼心欲偃戈。',64,'全唐诗/poet.song.20000.json','["漢家經武意如何，也信狼心欲偃戈。", "豈是虜庭佳麗少，自緣婚禮貨財多。", "女從宗室方掄擇，賦出齊民更刮摩。", "若向大臣求姪媵，當是誰肯議通和。"]'),
('ca650277-01a6-4818-a516-3a2a085f7436','忠武侯','李覯','宋','宋诗','song-poetry','','[]','齊霸燕强舊有基，當年管樂易爲奇。',64,'全唐诗/poet.song.20000.json','["齊霸燕强舊有基，當年管樂易爲奇。", "何如新野覊栖後，正值曹公挾帝時。", "指畫二州收漢燼，安排八陣與天期。", "才高命短雖無奈，猶勝隆中世不知。"]'),
('88b25a34-4d29-4e8d-89af-886745bea83a','次韻答陳殿丞見寄','李覯','宋','宋诗','song-poetry','','[]','顛倒江湖二十春，干時的是妄庸人。',64,'全唐诗/poet.song.20000.json','["顛倒江湖二十春，干時的是妄庸人。", "先容不肯收蟠木，高足無從得要津。", "衆與善名酬苦志，莫將吟味養閑身。", "食田飲井知誰力，下有驕兒上有親。"]'),
('050ad31e-6e87-43ae-825a-09e45d3fa0d5','贈韓侍禁','李覯','宋','宋诗','song-poetry','','[]','閥閱山西舊將家，一官淪落向天涯。',64,'全唐诗/poet.song.20000.json','["閥閱山西舊將家，一官淪落向天涯。", "目皮相處應難識，髀肉生來只自嗟。", "野囿幾年饑虎豹，旱雷何日起龍蛇。", "吳歌楚舞時相慰，劍鋏梅乾鐵有花。"]'),
('edbaf1eb-990c-4e70-94bc-46dbae5bcaa1','送沈祕校','李覯','宋','宋诗','song-poetry','','[]','君家龍虎弟兄賢，斗酒相逢楚水邊。',64,'全唐诗/poet.song.20000.json','["君家龍虎弟兄賢，斗酒相逢楚水邊。", "雨露自今榮一命，塵埃未免困三年。", "高談欲出稠人右，敏政當居俗吏前。", "異日能來見逋客，麻姑碧洞古時天。"]'),
('a58dbe21-ac83-4b33-9acf-5549d076bd39','寄題錢塘毛氏西湖園','李覯','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昔年曾泛西湖流，君今更住西湖頭。',64,'全唐诗/poet.song.20000.json','["昔年曾泛西湖流，君今更住西湖頭。", "人生多是未得往，地上有天何處求。", "朱樓照影鐘磬曉，畫船落手芙蓉秋。", "鯉魚赤鱗應不少，待與水仙相伴遊。"]'),
('17bb2091-4cd4-43b1-8a1c-58f701cf1c25','自解','李覯','宋','宋诗','song-poetry','','[]','人生何苦要多才，百慮攢心摘不開。',64,'全唐诗/poet.song.20000.json','["人生何苦要多才，百慮攢心摘不開。", "夜月幾曾無夢處，春風只管送愁來。", "禿毫强會悠悠事，浮世無過滿滿盃。", "看取秦坑烟焰裏，是非同作一抔灰。"]'),
('9b70e724-82a0-447b-9d9d-417e1eff605b','不寐','李覯','宋','宋诗','song-poetry','','[]','四壁空空絕語聲，困來終是睡難成。',64,'全唐诗/poet.song.20000.json','["四壁空空絕語聲，困來終是睡難成。", "孤燈要與人相背，寒漏苦教天不明。", "累月故園無信息，幾般閑事惱心情。", "別愁若解生華髮，一夕應添一萬莖。"]'),
('cb5daf3b-ec3a-4b4e-a957-ba74a47136ec','韓偓集有自撫州往南城縣舟行見拂水薔薇之詩南城吾鄉也因題八句','李覯','宋','宋诗','song-poetry','','[]','韓偓當年赴七閩，舟行過此倍凝神。',64,'全唐诗/poet.song.20000.json','["韓偓當年赴七閩，舟行過此倍凝神。", "江邊石上知誰處，綠戰紅酣別是春。", "往事幾多書不記，仙源依舊地無塵。", "花光柳色今何限，更有才人勝古人。"]'),
('7c6f7c41-e8d2-4a6b-aa15-27970b8a8ae5','代書答陳次公','李覯','宋','宋诗','song-poetry','','[]','咄咄休休一世閑，百年都是浪悲歡。',64,'全唐诗/poet.song.20000.json','["咄咄休休一世閑，百年都是浪悲歡。", "高談不待傍人笑，立事須知自古難。", "時見老顔來鑑裏，已將生計託雲端。", "六鼇未可揮刀斫，肯便臨谿把釣竿。"]'),
('6664c8c0-fa94-41a8-9b5a-583635377d24','和君錫題堯輔齋壁','李覯','宋','宋诗','song-poetry','','[]','書林老仙頭欲斑，近日卜居吳楚間。',64,'全唐诗/poet.song.20000.json','["書林老仙頭欲斑，近日卜居吳楚間。", "麻姑世界盡贏得，羲皇興味先追還。", "川流切對夏無暑，山月出來門未關。", "笑殺區區躁求者，不因貧病不曾閑。"]'),
('0541d15b-068d-4ff9-922a-a85ea00b236f','送王都曹','李覯','宋','宋诗','song-poetry','','[]','古木亭邊夜嚮晨，餞壺重疊擁雙輪。',64,'全唐诗/poet.song.20000.json','["古木亭邊夜嚮晨，餞壺重疊擁雙輪。", "高文健筆科場手，白髮青衫宦路人。", "十月霜風還劈面，六街塵土會欺貧。", "麻源碧澗神仙地，早晚歸來伴隠淪。"]'),
('d87c6e0b-13d7-4280-abd4-b4808b15addc','送危太博','李覯','宋','宋诗','song-poetry','','[]','一片靈臺衆共知，宦途寧肯避危機。',64,'全唐诗/poet.song.20000.json','["一片靈臺衆共知，宦途寧肯避危機。", "至誠似有神明助，盡室初從瘴海歸。", "烈火豈能傷美寶，覆盆終是見炎暉。", "人生未出功名外，多少京塵待染衣。"]'),
('d6914421-5ea8-4eda-8484-25a4a142ea61','題虞侍禁山停','李覯','宋','宋诗','song-poetry','','[]','嶺上簷楹締構新，我來登望倍凝神。',64,'全唐诗/poet.song.20000.json','["嶺上簷楹締構新，我來登望倍凝神。", "可憐韜略真名將，猶與谿山作主人。", "會把松心欺過雪，更憑花萼占留春。", "江南風物雖佳麗，爭奈燕然有虜塵。"]'),
('dce29cb5-d632-4ef3-b5aa-8b0bcdf8b18c','君錫宰壽春','李覯','宋','宋诗','song-poetry','','[]','淪落多愁笑不成，水邊還是送君行。',64,'全唐诗/poet.song.20000.json','["淪落多愁笑不成，水邊還是送君行。", "官爲令長前程好，地近鄉關喜氣生。", "百里有人觀惠術，三年唯我見交情。", "山中後夜思賢處，風月猶應似舊清。"]'),
('843a7db0-0995-449b-9038-0355b3607307','錢寺丞知白州','李覯','宋','宋诗','song-poetry','','[]','大邑歌謠日尚新，忽驚千騎擁行塵。',64,'全唐诗/poet.song.20000.json','["大邑歌謠日尚新，忽驚千騎擁行塵。", "宦游莫歎登長道，天意先教福遠人。", "城在海隅門少客，地鐘陽氣景常春。", "政成不患無知己，按察當今正直臣。"]'),
('2865dafa-2134-49b0-87cf-7f6b55d3ccff','次韻答史太博','李覯','宋','宋诗','song-poetry','','[]','驛使將詩訪遠山，發函寧暇正衣冠。',64,'全唐诗/poet.song.20000.json','["驛使將詩訪遠山，發函寧暇正衣冠。", "秦城未割難論價，燕谷纔吹已不寒。", "佔畢有心忘老至，惰農無罰賀恩寬。", "一枝數粒唯知分，豈是明時學考槃。"]'),
('69cbbb05-f24e-4d69-b97d-a3ed8b36dbba','蟬','李覯','宋','宋诗','song-poetry','','[]','一蛻囂塵向此生，柳枯槐老正傷情。',64,'全唐诗/poet.song.20000.json','["一蛻囂塵向此生，柳枯槐老正傷情。", "高吟盡日知誰聽，零露充腸且獨清。", "螳斧不勞陰致害，貂冠猶可共傳名。", "騷人若有遺魂在，應放冤聲伴爾鳴。"]'),
('9ae9c7c5-7e28-482f-880a-c96b64da5971','寄史屯田','李覯','宋','宋诗','song-poetry','','[]','秀汝清旴數舍中，繫匏名謁竟難通。',64,'全唐诗/poet.song.20000.json','["秀汝清旴數舍中，繫匏名謁竟難通。", "只知俗吏隆官業，不意高文有古風。", "朝請待趨天屏北，家園歸省浙江東。", "遠民利害聞應熟，早晚嘉謀沃舜聰。"]'),
('3c92bad8-f6be-47eb-b9bd-834b3bd83c38','答丘寺丞示月蝕詩','李覯','宋','宋诗','song-poetry','','[]','一夜吟公月蝕詩，睡魔驚走醉魂飛。',64,'全唐诗/poet.song.20000.json','["一夜吟公月蝕詩，睡魔驚走醉魂飛。", "如將混沌重區別，要使君臣有等威。", "天道至高全指掌，古人雖死合知非。", "相思無計能相見，何日軒車向北歸。"]'),
('f3a83090-c9c4-4601-a944-8c4d62cddeb1','蓬屋','李覯','宋','宋诗','song-poetry','','[]','長簷數尺庇堂東，疎漏從來只有蓬。',64,'全唐诗/poet.song.20000.json','["長簷數尺庇堂東，疎漏從來只有蓬。", "日影碎如秋樹下，雨聲初似夜船中。", "竹經蠹了多垂地，箬到乾時半捲空。", "此處想非人所競，衆言千萬莫相攻。"]'),
('db3da6c1-3a8b-41bd-8062-0fbf0e5421dd','階基','李覯','宋','宋诗','song-poetry','','[]','堂前一級似階墀，無石無甎只舊基。',64,'全唐诗/poet.song.20000.json','["堂前一級似階墀，無石無甎只舊基。", "泥飾頃因年節近，蹋崩唯是客行時。", "誰曾羅襪雙來上，多謝蒼苔久不離。", "從此便成貧景致，竹簾垂處最相宜。"]'),
('8d620a17-9fa5-497f-b670-eacd060ecdbc','宜春臺','李覯','宋','宋诗','song-poetry','','[]','謫官誰住小蓬萊，唯有宜春有古臺。',64,'全唐诗/poet.song.20000.json','["謫官誰住小蓬萊，唯有宜春有古臺。", "千里待看毫末去，萬家攢作畫圖來。", "雲中羅綺香風落，月底笙歌醉夢迴。", "莫怪江山苦相助，騷人沒後得真才。"]'),
('8b93ff52-1e30-4dd7-ae3b-969fda0ed735','東湖','李覯','宋','宋诗','song-poetry','','[]','古郡城池已瞰江，重湖更在郡東方。',64,'全唐诗/poet.song.20000.json','["古郡城池已瞰江，重湖更在郡東方。", "水仙坐下魚鱗赤，龍女門前橘樹香。", "路絕塵埃非灑掃，地無風雨亦清凉。", "使君待客多娛樂，只有醒時覺異鄉。"]'),
('3e42949f-014b-4aa5-b778-f7cf35a77db2','送趙拊','李覯','宋','宋诗','song-poetry','','[]','先朝名士有遺孫，狼藉麻衣化洛塵。',64,'全唐诗/poet.song.20000.json','["先朝名士有遺孫，狼藉麻衣化洛塵。", "筆下每求千古意，醉中曾過幾迴春。", "勞生只見年年老，客路相逢事事新。", "滿座狂歌時莫笑，眼看燕市若無人。"]'),
('5edd11bc-fc0d-4624-928d-be4c97ed922e','太平州十詠亭','李覯','宋','宋诗','song-poetry','','[]','客遊無日暫開顔，姑孰谿邊偶得閑。',64,'全唐诗/poet.song.20000.json','["客遊無日暫開顔，姑孰谿邊偶得閑。", "風景直疑圖畫出，古今都似夢魂間。", "桓溫罪逆休重問，謝傅英靈已不還。", "深美謫仙遺世務，酒船椎鼓浪如山。"]'),
('ee686d0a-08d8-47fb-b06a-6ea4595297f5','送王尉','李覯','宋','宋诗','song-poetry','','[]','義激中心不再思，宦途從此抱瑕疵。',64,'全唐诗/poet.song.20000.json','["義激中心不再思，宦途從此抱瑕疵。", "誰憐君子篤親意，況是明王孝治時。", "靖節田園應久廢，尚平婚嫁豈宜遲。", "一官塵土休迴顧，海上羣鷗舊有期。"]'),
('7f782160-b3e5-4f92-9771-a5d5b2458cf4','野意亭','李覯','宋','宋诗','song-poetry','','[]','福唐城郭掌中窺，旭日登臨到落暉。',64,'全唐诗/poet.song.20000.json','["福唐城郭掌中窺，旭日登臨到落暉。", "誰在畫簾沽酒處，幾多鳴櫓趁潮歸。", "晴來海色依稀辨，醉後鄉愁積漸微。", "山鳥不知紅粉好，纔聞歌板便驚飛。"]'),
('02dcd5c5-4870-4a17-8d93-334596448dc5','靈源洞','李覯','宋','宋诗','song-poetry','','[]','纔出塵來尚未知，漸攀藤竹漸臨危。',64,'全唐诗/poet.song.20000.json','["纔出塵來尚未知，漸攀藤竹漸臨危。", "伏流似是龍藏處，古樹應無春到時。", "誰把石崖齊剗削，直教雲氣當簾帷。", "良工畫得猶宜秘，莫與凡夫肉眼窺。"]'),
('f6e24fd9-9920-4d3b-b6fb-e5a2d9912b0b','送陳司理','李覯','宋','宋诗','song-poetry','','[]','平生直道耻求人，下位沈英久未伸。',64,'全唐诗/poet.song.20000.json','["平生直道耻求人，下位沈英久未伸。", "齊吹古來偏有濫，葉龍今更不宜真。", "天邊奕世三台貴，江上先廬一畝貧。", "大抵窮通相倚伏，這迴寒谷解逢春。"]'),
('13db0158-29b4-4263-b7ec-2e6c5cb8c5c2','送黄承伯','李覯','宋','宋诗','song-poetry','','[]','君來別我向番陽，時節初春曉尚霜。',64,'全唐诗/poet.song.20000.json','["君來別我向番陽，時節初春曉尚霜。", "茶褐園林新柳色，鹿胎田地落梅香。", "此行硯席多知己，是處樓臺可舉觴。", "只恐詔書非久下，槐花又在眼前黄。"]'),
('3c4a05bf-f9f1-4ce5-a359-200d2a1dccc6','謝蔡十八丈相示詩卷','李覯','宋','宋诗','song-poetry','','[]','昔年多幸枉高軒，示我新詩累百篇。',64,'全唐诗/poet.song.20000.json','["昔年多幸枉高軒，示我新詩累百篇。", "使君即時還趙璧，夢魂今尚憶鈞天。", "據鞍馬援誰云老，陋巷顔回始是賢。", "桂樹寒山風景好，近來應更有長編。"]'),
('29b75414-9f31-44fd-99e0-aea85054ca9e','清話堂詩','李覯','宋','宋诗','song-poetry','','[]','釋子相延暫解冠，一宵清話到更蘭。',64,'全唐诗/poet.song.20000.json','["釋子相延暫解冠，一宵清話到更蘭。", "漆盤香燼死蚯蚓，紙瓦雨聲鳴彈丸。", "往事莫將閑口笑，勞生誰在定中看。", "明朝頮面還歸去，依舊塗泥濺馬鞍。"]'),
('445cb04e-4315-42be-b683-999f3ec3c121','送郴縣吳主簿','李覯','宋','宋诗','song-poetry','','[]','數十年來預薦書，當時文行聳羣儒。',64,'全唐诗/poet.song.20000.json','["數十年來預薦書，當時文行聳羣儒。", "青衫近始霑王澤，白首從新入宦途。", "四壁生涯雖寂莫，一官趨進轉崎嶇。", "楚南若是江山好，閑日猶應味道腴。"]'),
('ef30ec19-4a2e-4080-8d10-c30d8ed21728','覽余堯輔詩因成七言四韻','李覯','宋','宋诗','song-poetry','','[]','少年心苦向毛錐，老大生涯只有詩。',64,'全唐诗/poet.song.20000.json','["少年心苦向毛錐，老大生涯只有詩。", "哀樂萬端成畫繪，江山大半入鑪鎚。", "格如平易人多愛，意到幽深鬼未知。", "白髮尚新才不盡，幾時吟興是衰時。"]'),
('cd8149c4-290c-41b8-9121-779aa1720bed','次韻酬屯田陳丈見寄','李覯','宋','宋诗','song-poetry','','[]','老年纔到病還催，老病成叢撥不開。',64,'全唐诗/poet.song.20000.json','["老年纔到病還催，老病成叢撥不開。", "腹冷有時如咽雪，耳虛終日獨聞雷。", "半生辛苦歸三徑，萬恨銷磨向一桮。", "頼得竹窗無事處，清風頻共故人來。"]'),
('dcf01db7-20b9-4dee-8377-71c091161ec4','同徐殿丞遊麻姑山陳屯田聞之以詩見寄次韻第二首','李覯','宋','宋诗','song-poetry','','[]','塵寰漸遠漸凄清，似向崑崙采玉英。',64,'全唐诗/poet.song.20000.json','["塵寰漸遠漸凄清，似向崑崙采玉英。", "此地已知鄰華子，幾人猶道識方平。", "步高那復肌膚重，心逸都疑羽翼生。", "苦恨俗緣無了處，歸來依舊馬蹄聲。"]'),
('b1692181-01ef-4a8e-a3f0-6665c52c98c7','和陳屯田送知縣徐殿丞次韻','李覯','宋','宋诗','song-poetry','','[]','近年雙闕暫鳴珂，出宰南城戶數多。',64,'全唐诗/poet.song.20000.json','["近年雙闕暫鳴珂，出宰南城戶數多。", "古道存心公道顯，惡人鉗口善人歌。", "登高賦處英辭在，垂橐歸時舊物鈋。", "當比瑞金囂訟後，要移風俗擬如何。"]'),
('402ae049-f79f-408b-a252-0733799ea8d8','和屯田陳丈寄唐休次韻','李覯','宋','宋诗','song-poetry','','[]','白屋從來未有官，一名須作佛名看。',64,'全唐诗/poet.song.20000.json','["白屋從來未有官，一名須作佛名看。", "彥倫北谷重歸去，安石東山足舊歡。", "常調幾時趨鳳闕，湛恩唯待立雞竿。", "胸中況是多奇藴，自比陽春退苦寒。"]'),
('ead93d23-7c49-4a85-8e69-2f2b7ec4df22','和王刑部遊仙都觀','李覯','宋','宋诗','song-poetry','','[]','尋幽西去路非賒，回首紅塵可可嗟。',64,'全唐诗/poet.song.20000.json','["尋幽西去路非賒，回首紅塵可可嗟。", "不待鸞驂并鶴駕，便分人世與仙家。", "幾函道藏金壺墨，一片秋容玉井花。", "還似武夷高會日，骨凡猶幸醉流霞。"]'),
('03f1d499-a1bd-4862-8b63-9bd7a1c9fef2','和遊丹霞有懷歸之意','李覯','宋','宋诗','song-poetry','','[]','暫時來訪道家流，肯伴煙蘿滯一丘。',64,'全唐诗/poet.song.20000.json','["暫時來訪道家流，肯伴煙蘿滯一丘。", "爲憶長安瞻日下，欲尋蓬島向鼇頭。", "陶潛醉後雖眠石，王粲憂多更上樓。", "宣室歲餘虛席在，青山何路更重遊。"]'),
('659b11f5-13dc-4bef-a7e9-aa686642d573','送知軍曹比部移虔州','李覯','宋','宋诗','song-poetry','','[]','要知賢者善居官，法自嚴明性自寬。',128,'全唐诗/poet.song.20000.json','["要知賢者善居官，法自嚴明性自寬。", "黠吏欲欺難作計，愚民初懼久方安。", "獄辭大小情皆見，市物公私價一般。", "農力不聞供土木，窮閻猶得免饑寒。", "星爲二使來巡撫，考未三年悉可觀。", "劇郡便當煩鎮守，君恩寧許更盤桓。", "雨轓贛水行非遠，五袴旴江日漸單。", "從此天衢龍躍去，野人懷德謾悲酸。"]'),
('65228e22-c620-4cb5-9d4a-171ae40fb38b','芍藥','李覯','宋','宋诗','song-poetry','','[]','斜月正當樓，香霧壓城重。',24,'全唐诗/poet.song.20000.json','["斜月正當樓，香霧壓城重。", "起傍小蘭行，花亦方在夢。"]'),
('ad2eab94-41c7-4ea8-9727-55291322a6ed','海棠','李覯','宋','宋诗','song-poetry','','[]','戢戢雖聚頭，脉脉俱俯地。',48,'全唐诗/poet.song.20000.json','["戢戢雖聚頭，脉脉俱俯地。", "既言是姊妹，又却相妬忌。", "面痕赤未沒，盡是傷爪指。", "不然睡未醒，被人沃井水。"]'),
('c4b889e0-a4da-4507-a07b-60c4bee0a36b','訶孟子','李覯','宋','宋诗','song-poetry','','[]','完廩捐階未可知，孟軻深信亦還疑。',32,'全唐诗/poet.song.20000.json','["完廩捐階未可知，孟軻深信亦還疑。", "岳翁方且爲天子，女婿如何弟殺之。"]'),
('ae91fd7f-a75e-48db-bb5b-ff0638c13555','震山巖','李覯','宋','宋诗','song-poetry','','[]','鮮日媚睛靄，泉石閩融融。',72,'全唐诗/poet.song.20000.json','["鮮日媚睛靄，泉石閩融融。", "酒味醴於春，揖翠迎春風。", "坐映珪璧秀，六合開情悰。", "昔人袖全璞，傲睨追冥鴻。", "里閭味前塵，慨慕滋無窮。", "蓄藴非一身，出處固異同。"]'),
('9e2494da-463c-466c-a271-2be7693024f0','又寄龍學','李覯','宋','宋诗','song-poetry','','[]','三十年交舊，相逢各白頭。',48,'全唐诗/poet.song.20000.json','["三十年交舊，相逢各白頭。", "海壖曾共飯，洛社又同遊。", "脫屣風波地，開懷松桂秋。", "兩眉從此後，應不著閑愁。"]'),
('a5a72bf9-e0ee-492e-ac36-3994951bca29','雲興于山','蘇洵','宋','宋诗','song-poetry','','[]','雲興于山，霜霜爲霧。',70,'全唐诗/poet.song.20000.json','["雲興于山，霜霜爲霧。", "匪山不仁，天實不顧。", "山川我享，爲我百訴。", "豈不畏天，哀此下土。", "班班鳲鳩，穀穀晨號。", "天乎未雨，余不告勞。", "誰爲山川，不如羽毛。"]'),
('0685f994-e173-48c5-84e0-7c5b0ef34930','有驥在野','蘇洵','宋','宋诗','song-poetry','','[]','有驥在野，百過不呻。',66,'全唐诗/poet.song.20000.json','["有驥在野，百過不呻。", "子不我良，豈無他人。", "縶我于廐，乃不我駕。", "遇我不終，不如在野。", "禿毛于霜，寄肉于狼，寧彼我傷。", "寧人不我顧，無子我忘。"]'),
('2183cb7e-e77e-4748-9ea7-c023da0d57a6','有觸者犢','蘇洵','宋','宋诗','song-poetry','','[]','有觸者犢，再箠不却。',50,'全唐诗/poet.song.20000.json','["有觸者犢，再箠不却。", "爲子已觸，安所置角。", "天實畀我，子欲已我。", "惡我所爲，盍奪我有。", "子欲不觸，盍索之苙。"]'),
('d661c29b-fa00-4c2f-80e3-1a61af1df4cb','朝日載昇','蘇洵','宋','宋诗','song-poetry','','[]','朝日載昇，薨薨伊氓。',70,'全唐诗/poet.song.20000.json','["朝日載昇，薨薨伊氓。", "于室有績，于野有耕。", "于塗有商，于邊有征。", "天生斯民，相養以寧。", "嗟我何爲，踽踽無營。", "初孰與我，今孰主我。", "我將往問，安所處我。"]'),
('aeea5259-8b97-4580-924e-298b855ca9dc','我客至止','蘇洵','宋','宋诗','song-poetry','','[]','我客至止，我逆于門。',65,'全唐诗/poet.song.20000.json','["我客至止，我逆于門。", "來升我堂，來飲我罇。", "羞鼈不時，詈我不勤。", "求我何多，請辭不能。", "客謂主人，唯子我然。", "求子之多，責子之深，期子于賢。"]'),
('7fd4d4a3-9757-4a9c-be93-f32bd6e9f611','顔書','蘇洵','宋','宋诗','song-poetry','','[]','任君北方來，手出邠州碑。',288,'全唐诗/poet.song.20000.json','["任君北方來，手出邠州碑。", "爲是魯公寫，遺我我不辭。", "魯公實豪傑，慷慨忠義姿。", "憶在天寶末，變起漁陽師。", "猛士不敢當，儒生橫義旗。", "感激數十郡，連衡鬭羌夷。", "新造勢尚弱，胡爲力未衰。", "用兵竟不勝，歎息真數奇。", "杲兄死常山，烈士淚滿頤。", "魯公不死敵，天下皆熙熙。", "奈何不愛死，再使踏鯨鰭。", "公固不畏死，吾實悲當時。", "緬邈念高誼，惜哉我生遲。", "近日見異說，不知作者誰。", "云公本不死，此事亦已奇。", "大抵天下心，人人屬公思。", "加以不死狀，慰此苦歎悲。", "我欲哭公墓，莽莽不可知。", "愛其平生迹，往往或孑遺。", "此字出公手，一見減歎咨。", "使公不善書，筆墨紛訛癡。", "思其平生事，豈忍棄路歧。", "況此字頗怪，堂堂偉形儀。", "駿極有深穩，骨老成支離。"]'),
('da23c7d6-9b3d-495b-be46-2e46302e42cd','歐陽永叔白兔','蘇洵','宋','宋诗','song-poetry','','[]','飛鷹搏平原，禽獸亂衰草。',120,'全唐诗/poet.song.20000.json','["飛鷹搏平原，禽獸亂衰草。", "蒼茫就擒執，顛倒莫能保。", "白兔不忍殺，歎息愛其老。", "獨生遂長拘，野性始驚矯。", "貴人織筠籠，馴擾漸可抱。", "誰知山林寬，穴處頗自好。", "高飈動槁葉，羣竄迹如掃。", "異質不自藏，照野明暠暠。", "獵夫指之笑，自匿苦不早。", "何當騎蟾蜍，靈杵手自搗。"]'),
('18be2326-90a6-48a7-b2da-f2e2b3c48dbf','答二任','蘇洵','宋','宋诗','song-poetry','','[]','魯人賤夫子，嗚丘指東家。',240,'全唐诗/poet.song.20000.json','["魯人賤夫子，嗚丘指東家。", "當時雖未遇，弟子已如麻。", "奈何鄉閭人，曾不爲歎嗟。", "區區吳越間，問骨不憚遐。", "習見反不怪，海人等龍暇。", "嗟我何足道，窮居出無車。", "昨者入京落，文章彼人誇。", "故舊未肯信，聞之笑呀呀。", "獨有兩任子，知我有足嘉。", "遠遊苦相念，長篇寄芬葩。", "我道亦未爾，子得無增加。", "貧窮已衰老，短髮垂髿髿。", "重祿無意取，思治山中畬。", "往歲栽苦竹，細密如蒹葭。", "庭前三小山，本爲山中楂。", "當前鑿方池，寒泉照谽谺。", "翫此可竟日，胡爲踏朝衙。", "何當子來會，酒食相邀遮。", "願爲久相敬，終始無疵瑕。", "閑居各無事，數來飲流霞。"]'),
('94bda8dc-65f5-4deb-8a16-033fe0a7cdde','丙申歲余在京師鄉人陳景回自南來棄其官得太子中允景回舊有地在蔡今將治園囿於其間以自老余嘗有意於嵩山之下洛水之上買地築室以爲休息之館而未果今景回欲余詩遂道此意景回志余言異日可以知余之非戲云爾','蘇洵','宋','宋诗','song-poetry','','[]','岷山之陽土如腴，江水清滑多鯉魚。',176,'全唐诗/poet.song.20000.json','["岷山之陽土如腴，江水清滑多鯉魚。", "古人居之富者衆，我獨厭倦思移居。", "平川如手山水蹙，恐我後世鄙且愚。", "經行天下愛嵩嶽，遂欲買地居妻孥。", "晴原漫漫望不盡，山色照野光如濡。", "民生舒緩無夭扎，衣冠堂堂偉丈夫。", "吾今隠居未有所，更後十載不可無。", "聞君厭蜀樂上蔡，占地百頃無邊隅。", "草深野闊足狐兔，水種陸取身不劬。", "誰知李期顧秦寵，不獲牽犬追黄狐。", "今君南去已足老，行看嵩少當吾廬。"]'),
('4daa5093-759e-4a2d-bc23-2410a4bd1972','憶山送人','蘇洵','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u957f\u6c5f"]','少年喜奇迹，落拓鞍馬間。',288,'全唐诗/poet.song.20000.json','["少年喜奇迹，落拓鞍馬間。", "縱目視天下，愛此宇宙寬。", "山川看不厭，浩然遂忘還。", "岷峨最先見，睛光厭西川。", "遠望未及上，但愛青若鬟。", "大雪冬沒脛，夏秋多虵蚖。", "乘春乃敢去，匍匐攀孱顔。", "有路不容足，左右號鹿猿。", "陰崖雪如石，迫暖成高瀾。", "經日到絕頂，目眩手足顛。", "自恐不得下，撫膺忽長嘆。", "坐定聊四顧，風色非人寰。", "仰面囁雲霞，垂手撫百山。", "臨風弄襟袖，飄若風中仙。", "朅來游荆渚，談笑登峽船。", "峽山無平岡，峽水多悍湍。", "長風送輕帆，瞥過難詳觀。", "其間最可愛，巫廟十數巔。", "聳聳青玉幹，折首不見端。", "其餘亦詭怪，土老崖石頑。", "長江渾渾流，觸齧不可攔。", "苟非峽山壯，浩浩無隅邊。", "恐是造物意，特使險且堅。", "江山兩相值，後世無水患。"]'),
('028d4a8d-91c3-4ec0-9f99-5a979a7f1d52','上田待制詩','蘇洵','宋','宋诗','song-poetry','','[]','日落長安道，大野渺荒荒。',228,'全唐诗/poet.song.20000.json','["日落長安道，大野渺荒荒。", "吁嗟秦皇帝，安得不富强。", "山大地胍厚，小民十尺長。", "耕田破萬頃，一稔粟柱樑。", "少年事游俠，皆可荷弩槍。", "勇力不自驕，頗能啗乾糧。", "天意此有謂，故使連西羌。", "古人遭邊患，累累鬭兩剛。", "方今正似此，猛士强如狼。", "跨馬負弓矢，走不擇澗岡。", "脫甲森不顧，袒裼搏敵場。", "嗟彼誰治此，踧踧不敢當。", "當之負重責，無成不朝王。", "田侯本儒生，越略今洸洸。", "右手握麈尾，指麾據胡牀。", "郡國遠浩浩，邊鄙有積倉。", "秦境古何在，秦人多戰傷。", "此事久不報，此時將何償。", "得此報天子，爲侯歌之章。"]'),
('87121570-1d27-4b1a-818f-d1d8dd37c92b','途次長安上都漕傅諫議','蘇洵','宋','宋诗','song-poetry','','[]','丈夫正多念，老大自不安。',288,'全唐诗/poet.song.20000.json','["丈夫正多念，老大自不安。", "居家不能樂，忽忽思中原。", "慨然棄鄉廬，劫劫道路間。", "窮山多虎狼，行路非不難。", "昔者倦奔走，閑門事耕田。", "蠶穀聊自給，如此已十年。", "緬懷當今人，草草無復閑。", "堅卧固不起，芒刺實在肩。", "布衣與食肉，幸可交口言。", "默默不以告，未可遽罪愆。", "驅車入京洛，藩鎮皆達官。", "長安逢傅侯，願得說肺肝。", "貧賤吾老矣，不復苦自嘆。", "富貴不足愛，浮雲過長天。", "中懷邈有念，惝怳難自論。", "世俗不見信，排斥僅得存。", "昨者東入秦，大麥黄滿田。", "秦民可無饑，爲君喜不眠。", "禁軍幾千萬，仰此填其咽。", "西蕃久不反，老賊非常然。", "士飽可以戰，吾寧爲之先。", "傅侯君在西，天子憂東藩。", "烽火尚未滅，何策安西邊。", "傅侯君謂何，明日將東轅。"]'),
('006e8309-aa91-4735-97cf-1ef1cfac24ff','答陳公美','蘇洵','宋','宋诗','song-poetry','','[]','少壯事已遠，舊交良可懷。',288,'全唐诗/poet.song.20000.json','["少壯事已遠，舊交良可懷。", "百年能幾何，十載不得偕。", "念昔居鄉里，游處了無猜。", "飲食不相捨，談笑久所陪。", "拜君以爲兄，分蜜誰能開。", "齒髮俱未老，未至衰與頹。", "我子在襁褓，君猶無嬰孩。", "君後獨捨去，爲吏天一涯。", "我又厭奔走，遠引不復來。", "歲月杳難恃，區區老吾儕。", "況從與君別，多事歲若排。", "心力不能救，衰病侵骨骸。", "二子皆已冠，如吾苦無才。", "君亦已有嗣，骨目秀且佳。", "人事知幾變，會合終不諧。", "昨者本不出，豪傑苦自咍。", "欝欝自不樂，誰爲子悲哀。", "翻然感其說，東走陵巔崖。", "不意君在此，得春笑與詼。", "君顔蔚如故，大噱飛塵灰。", "我老應可怪，白髭生兩顋。", "新句辱先贈，古詩許見推。", "賢俊非獨步，故舊每所乖。", "作詩報嘉貺，亦聊以相催。"]'),
('cd4205c5-8f65-475d-a09d-b2ea193a6942','又答陳公美三首  其一','蘇洵','宋','宋诗','song-poetry','','[]','仲尼魯司寇，官職亦已優。',60,'全唐诗/poet.song.20000.json','["仲尼魯司寇，官職亦已優。", "從祭肉不及，戴冕奔諸侯。", "當時不之知，爲肉誠可羞。", "君子意有在，衆人但愆尤。", "置之待後世，皎皎無足憂。"]'),
('85df14eb-4c6a-4dfe-aa3a-01bd06a1fc96','又答陳公美三首  其二','蘇洵','宋','宋诗','song-poetry','','[]','仲尼爲羣婢，一走十四年。',60,'全唐诗/poet.song.20000.json','["仲尼爲羣婢，一走十四年。", "荀卿老不出，五十干諸田。", "顧彼二夫子，豈其陷狂顛。", "出處固無定，不失稱聖賢。", "彼亦誠自信，誰能卹多言。"]'),
('c2714096-bac4-415d-8032-1b15bbdc9f24','又答陳公美三首  其三','蘇洵','宋','宋诗','song-poetry','','[]','公孫昔放逐，牧羊滄海濱。',48,'全唐诗/poet.song.20000.json','["公孫昔放逐，牧羊滄海濱。", "勉强聽鄉里，垂老西游秦。", "自顧未爲壯，徒爲久辛勤。", "君子豈必隠，孔孟皆旅人。"]'),
('090c12d6-38e5-4e37-b837-50cc340263a9','送李才元學士知邛州','蘇洵','宋','宋诗','song-poetry','','[]','貧賤羞妻子，富貴樂鄉關。',72,'全唐诗/poet.song.20000.json','["貧賤羞妻子，富貴樂鄉關。", "不見李夫子，得意今西還。", "白馬渡滻水，紅旌照蜀山。", "歸來未解带，故舊已滿門。", "平生浪游處，何者哀王孫。", "壯士勿齷齪，千金報一飱。"]'),
('c7d8762e-666a-426c-a809-accc7442591c','送陸權叔提舉茶稅','蘇洵','宋','宋诗','song-poetry','','[]','君家本江湖，南行即鄰里。',132,'全唐诗/poet.song.20000.json','["君家本江湖，南行即鄰里。", "稅茶雖冗繁，漸喜官資美。", "嗟君本篤學，寤寐好文字。", "往年在巴蜀，憶見春秋始。", "名家亂如髮，棼錯費尋理。", "今來未五歲，新傳滿盈几。", "又言欲治易，雜說書萬紙。", "君心不可測，日夜湧如水。", "何年重相逢，祗益使余畏。", "但恐茶事多，亂子易中意。", "茶易兩無妨，知君足才思。"]'),
('efcdff4c-1be7-4fe5-a5f7-985043ade1ea','送王吏部知徐州','蘇洵','宋','宋诗','song-poetry','','[]','東徐三齊之南鄰，夫子豈是三齊人。',112,'全唐诗/poet.song.20000.json','["東徐三齊之南鄰，夫子豈是三齊人。", "辭囂乞靜得此守，走兔入藪魚投津。", "徐州絕勝不須問，請問項籍何去秦。", "江山雄豪不相下，衣錦遊戲欲及辰。", "霸王事業今已矣，但有太守朱兩輪。", "還鄉據勢與古並，豈有漢戟窺城闉。", "論安較利乃公勝，行矣正及汴水勻。"]'),
('deffa50b-e6c7-42a6-bc60-86debd5e3206','藤樽','蘇洵','宋','宋诗','song-poetry','','[]','枯藤生幽谷，蹙縮似無材。',96,'全唐诗/poet.song.20000.json','["枯藤生幽谷，蹙縮似無材。", "不意猶爲累，刳中作酒杯。", "君知我好異，贈我酌村醅。", "衰意方多感，爲君當數開。", "藤樽結如螺，村酒綠如水。", "開樽自獻酬，竟日成野醉。", "青莎可爲席，白石可爲機。", "何當酌清泉，永以思君子。"]'),
('8ace5b35-d11b-4b4e-961c-5d44880f71e9','送任師中任清江','蘇洵','宋','宋诗','song-poetry','','[]','吾喜送任師，羨君方少年。',192,'全唐诗/poet.song.20000.json','["吾喜送任師，羨君方少年。", "有如伏櫪馬，看彼始及鞍。", "奔騰過吾目，蕭條正思邊。", "誰知脫吾羈，傲睨登太山。", "君今始得縣，翱翔大江干。", "大江多風波，渺然勢欲翻。", "浩蕩吞九野，開闔壯士肝。", "人生患不出，局束守一廛。", "未常見大物，不識天地寬。", "今君吾鄉秀，固已見西川。", "去年人邊吏，出入烽火閒。", "儒冠雜武弁，屈與氊裘言。", "又當適南土，大浪泛目前。", "胸中芥蔕心，吹盡爲平田。", "陳湯喜刑勝，所至常縱觀。", "吾想君至彼，胸膽當豁然。"]'),
('4145c715-cda3-40f6-ac28-41763fe15174','送吳待制中復知潭州二首  其一','蘇洵','宋','宋诗','song-poetry','','[]','十年嘗作犍爲令，四脉嘗聞愍俗詩。',64,'全唐诗/poet.song.20000.json','["十年嘗作犍爲令，四脉嘗聞愍俗詩。", "共歎才高堪御史，果能忠諫致戎麾。", "會稽特欲榮公子，馮翊猶將試望之。", "船繫河隄無幾日，南公應已慳來遲。"]'),
('64427d9d-156b-4254-9efe-4c60d090edc5','送吳待制中復知潭州二首  其二','蘇洵','宋','宋诗','song-poetry','','[]','臺省留身凡幾歲，江湖得郡喜今行。',64,'全唐诗/poet.song.20000.json','["臺省留身凡幾歲，江湖得郡喜今行。", "卧聽曉鼓朝眠穩，行入淮流鄉味生。", "細雨滿村蓴菜長，高風吹旆綵船獰。", "到家應有壺觸勞，倚頼比鄰不畏卿。"]'),
('090b4976-360b-4a43-a1ca-4a65bff22279','從叔母楊氏輓詞','蘇洵','宋','宋诗','song-poetry','','[]','老人凋喪悲宗黨，寒月淒涼葬舊林。',64,'全唐诗/poet.song.20000.json','["老人凋喪悲宗黨，寒月淒涼葬舊林。", "白髮已知鄰里暮，傷懷難盡子孫心。", "幾年贈命涵幽壤，當有銘文記德音。", "千里緘詞託哀恨，鳴鳴引者涕中吟。"]'),
('31920790-6323-4600-8354-dda54253afba','次韻和縉叔遊仲容西園二首  其一','蘇洵','宋','宋诗','song-poetry','','[]','春入禁城懷舊隠，偶來芳圃似還家。',64,'全唐诗/poet.song.20000.json','["春入禁城懷舊隠，偶來芳圃似還家。", "番番翠蔓纏松上，粲粲朱梅入竹花。", "客慢空勞嚴置兕，酒多無用早成虵。", "相公猶有遺書在，欲問郎君借五車。"]'),
('de501f89-5402-4b88-8497-ac7499b3df6f','次韻和縉叔遊仲容西園二首  其二','蘇洵','宋','宋诗','song-poetry','','[]','栽松成徑百餘尺，隔徑開堂似兩家。',64,'全唐诗/poet.song.20000.json','["栽松成徑百餘尺，隔徑開堂似兩家。", "厭事共邀終日飲，渴春先賞後開花。", "客來庭樹鳴寒鵲，酒入肌膚憶冷虵。", "衰病不勝杯酒處，醉歸傾倒欲乘車。"]'),
('753c556f-59b9-4cbf-8387-6ff649f389d8','遊嘉州龍巖','蘇洵','宋','宋诗','song-poetry','','[]','繫舟長堤下，日夕事南征。',72,'全唐诗/poet.song.20000.json','["繫舟長堤下，日夕事南征。", "往意紛何速，空巖幽自明。", "使君憐遠客，高會有餘情。", "酌酒何能飲，去鄉懷獨驚。", "山川隨望闊，氣候带霜清。", "佳境日已去，何時休遠行。"]'),
('456669ee-3979-4ac6-9c7c-7fd757e256cc','初發嘉州','蘇洵','宋','宋诗','song-poetry','','[]','家託舟航千里速，心期京國十年還。',32,'全唐诗/poet.song.20000.json','["家託舟航千里速，心期京國十年還。", "烏牛山下水如箭，忽失峨眉枕席間。"]'),
('8a0dbb46-df59-4fb7-bc94-ce077f857298','襄陽懷古','蘇洵','宋','宋诗','song-poetry','','[]','我行襄陽野，山色向人明。',156,'全唐诗/poet.song.20000.json','["我行襄陽野，山色向人明。", "何以洗懷抱，悠哉漢水清。", "遼遼峴山道，千載幾人行。", "踏盡山上士，山腰爲之平。", "道逢墮淚碣，不覺涕亦零。", "借問羊叔子，何異葛孔明。", "今人固已遠，誰識前輩情。", "朅來萬山下，潭水轉相縈。", "水深不見底，中有杜預銘。", "潭水竟未涸，後世自知名。", "成功本無敵，好譽真儒生。", "自從三子亡，草中無豪英。", "聊登峴山首，淚與漢流傾。"]'),
('0941cbc1-d2fd-42e0-8fdc-aa468099fbd0','寄楊緯','蘇洵','宋','宋诗','song-poetry','','[]','家居對山木，謂是忘言伴。',132,'全唐诗/poet.song.20000.json','["家居對山木，謂是忘言伴。", "去鄉不能致，回顧頗自短。", "誰知有楊子，磊落收百段。", "揀贈最奇峰，慰我苦長歎。", "連城盡如削，邃洞幽可款。", "回合抱空虛，天地聳其半。", "舟行因樂載，陸挈敢辭懶。", "飄飄忽千里，有客來就看。", "自言此地無，愛惜苦欲換。", "低頭笑不答，解纜風帆滿。", "京洛有幽居，吾將隠而玩。"]'),
('401eb932-f4b8-4de3-9023-6817cf5c8a33','和楊節推見贈','蘇洵','宋','宋诗','song-poetry','','[]','與君多乖睽，邂逅同泛峽。',156,'全唐诗/poet.song.20000.json','["與君多乖睽，邂逅同泛峽。", "宋子雖世舊，談笑頃不接。", "二君比宦遊，疇昔共科甲。", "唯我老且閑，獨得離圈柙。", "少年實强銳，議論今我怯。", "有如乘風箭，勇發豈顧帖。", "置酒來相邀，慇懃爲留楫。", "楊君舊痛飲，淺水安足涉。", "嗟我素不任，一酌己頳頰。", "去生別懷愴，有子旅意愜。", "捨棹治陸行，歲晚筋力乏。", "予懶本不出，實爲人事劫。", "相將犯苦寒，大雪滿馬鬣。"]'),
('dc9e759d-a236-4ce9-beda-23c3e8796b73','答張子立見寄','蘇洵','宋','宋诗','song-poetry','','[]','舟行道里日夜殊，佳士恨不久與俱。',270,'全唐诗/poet.song.20000.json','["舟行道里日夜殊，佳士恨不久與俱。", "峽山行盡見平楚，捨舡登岸身無虞。", "念君治所自有處，不復放縱如吾徒。", "憶昨相見巴子國，謁我江上顔何娛。", "求文得卷讀不已，有似駿馬行且且。", "自言好學老未厭，方冊幾許魯作魚。", "古書今文遍天下，架上未有耿不愉。", "示我近所集，漫如遊通衢。", "通衢衆所入，癃殘詭怪雜沓不辨可嘆吁。", "文人大約可數者，不過皆在衆所譽。", "此外何足愛，刓破無四隅。", "況予固魯鈍，老蒼處羣雛。", "入趙抱五絃，客齊不吹竽。", "山林自竄久不出，回視衆俊驚錕鋙。", "豈意誤見取，騏驥參羸駑。", "將觀馳騁鬭雄健，無乃獨不堪長途。", "凄風臘月客荆楚，千里適魏勞奔趨。", "將行紛亂苦無思，强說鄙意慙區區。"]'),
('6c83a1d6-b481-44bb-a8a8-9e9992ee5f08','送蜀僧去塵','蘇洵','宋','宋诗','song-poetry','','[]','十年讀易費膏火，盡日吟詩愁肺肝。',64,'全唐诗/poet.song.20000.json','["十年讀易費膏火，盡日吟詩愁肺肝。", "不解丹青追世好，欲將芹芷薦君盤。", "誰爲善相應嫌瘦，後有知音可廢彈。", "拄杖掛經須倍道，故山春蕨已闌干。"]'),
('ed30f7e2-8dc4-4bcf-818c-b8139fdead01','九日和魏公','蘇洵','宋','宋诗','song-poetry','','["\u611f\u53f9", "\u91cd\u9633\u8282", "\u6000\u624d\u4e0d\u9047"]','晚歲登門最不才，蕭蕭華髮映金罍。',64,'全唐诗/poet.song.20000.json','["晚歲登門最不才，蕭蕭華髮映金罍。", "不堪丞相延東閣，閑伴諸儒老曲臺。", "佳節久從愁裏過，壯心偶傍醉中來。", "暮歸衝雨寒無睡，自把新詩百遍開。"]'),
('4316ec86-508c-4077-9102-6cafec67af20','題仙都觀','蘇洵','宋','宋诗','song-poetry','','[]','飄蕭古仙子，寂寞蒼山上。',108,'全唐诗/poet.song.20000.json','["飄蕭古仙子，寂寞蒼山上。", "觀世眇無言，無人獨惆悵。", "深岩聳喬木，古觀靄遺像。", "超超不可揖，真意誰復亮。", "蜿蜒乘長龍，倏忽變萬狀。", "朝食白雲英，暮飲石髓鬯。", "心肝化瓊玉，千歲已無恙。", "世人安能知，服藥本虛妄。", "嗟哉世無人，江水空蕩漾。"]'),
('f8b95364-9a5a-4a83-9eea-78a70a2774db','遊陵雲寺','蘇洵','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江觸山山欲摧，古佛咒水山之隈。',176,'全唐诗/poet.song.20000.json','["長江觸山山欲摧，古佛咒水山之隈。", "千航萬舸𣍿前過，仰視絕頂皆徘徊。", "足踏重濤怒洶涌，背負喬嶽高崔嵬。", "予昔過此下荆渚，班班滿面生蒼苔。", "今來重到非舊觀，金翠晃蕩祥光開。", "縈回一徑上嶮絕，却立下視驚心骸。", "蜀江迤邐漸不見，沫水騰掉震百雷。", "山川變化禹力盡，獨有道者嘗閔哀。", "琢山决水通萬里，奔走荆蜀如長街。", "世人至今不敢嫚，坐上蛻骨冷不埋。", "余今劫劫何所往，媿爾前人空自咍。"]'),
('ea7bce4f-7d33-4207-8e84-330bee619152','過木櫪觀','蘇洵','宋','宋诗','song-poetry','','[]','聞道精陽令，當時此學仙。',48,'全唐诗/poet.song.20000.json','["聞道精陽令，當時此學仙。", "鍊形初似鶴，蛻質竟如蟬。", "蘚上搘棺石，雲生晝影莚。", "舟中望山上，唯見柏森然。"]'),
('f09fe64b-6b9b-4c78-b44b-82487f530181','神女廟','蘇洵','宋','宋诗','song-poetry','','[]','巫陽仙子雲爲裾，高情杳眇與世踈。',64,'全唐诗/poet.song.20000.json','["巫陽仙子雲爲裾，高情杳眇與世踈。", "微有薄酒安足獻，願採山下霜中蔬。", "仙壇古洞何清虛，中有瓊樓白玉除。", "江上浩蕩誰來過，聞道琴高駕鯉魚。"]'),
('99479eba-19e4-4356-9994-a678306c40e6','題白帝廟','蘇洵','宋','宋诗','song-poetry','','[]','誰開三峽纔容練，長使羣雄苦力爭。',64,'全唐诗/poet.song.20000.json','["誰開三峽纔容練，長使羣雄苦力爭。", "熊氏凋零餘舊族，成家寂寞閉空城。", "永安就死悲玄德，八陣勞神嘆孔明。", "白帝有靈應自笑，諸公皆敗豈由兵。"]'),
('4cdf95d1-eeb4-49fa-b1db-ae628831cbec','萬山','蘇洵','宋','宋诗','song-poetry','','[]','萬山臨漢江，傑立與峴偶。',60,'全唐诗/poet.song.20000.json','["萬山臨漢江，傑立與峴偶。", "杜公破三吳，磊落叔子後。", "當年愛山意，無乃求自附。", "自比誠不慙，山水亦奇秀。", "羊公苟有知，當爲頷其首。"]'),
('9d1e75f2-ec23-4833-ba40-a48c4e1f416e','荆門惠泉','蘇洵','宋','宋诗','song-poetry','','[]','古郡带荒山，寒泉出西郭。',96,'全唐诗/poet.song.20000.json','["古郡带荒山，寒泉出西郭。", "嘈嘈幽響遠，衮衮清光活。", "當年我少年，繫馬弄潺湲。", "愛此泉旁鷺，高姿不可攀。", "今逾二十載，我老泉依舊。", "臨流照衰顔，始覺老且瘦。", "當時同遊子，半作泉下塵。", "流水去不返，遊人歲歲新。"]'),
('315b61c9-0bd5-4865-8740-023346253f95','昆陽城','蘇洵','宋','宋诗','song-poetry','','[]','昆陽城外土非土，戰骨多年化牆堵。',96,'全唐诗/poet.song.20000.json','["昆陽城外土非土，戰骨多年化牆堵。", "當時尋邑驅市人，未必三軍皆反虜。", "江河填滿道流血，始信武成真不誤。", "殺人應更多長平，薄賦寬征已無補。", "英雄爭鬭豈得已，盜賊縱橫亦何數。", "御之失道誰使然，長使哀魂啼夜雨。"]'),
('6c3499c1-df93-4ef4-86f5-b88e5fece243','題三遊洞石壁','蘇洵','宋','宋诗','song-poetry','','[]','洞門蒼石流成乳，山下長溪冷欲冰。',32,'全唐诗/poet.song.20000.json','["洞門蒼石流成乳，山下長溪冷欲冰。", "天寒二子苦求去，我欲居之爾不能。"]'),
('91be7411-b934-4a27-8d48-a8094815c244','與可許惠所畫舒景以詩督之','蘇洵','宋','宋诗','song-poetry','','[]','枯松怪石霜竹枝，中有可愛知者誰。',160,'全唐诗/poet.song.20000.json','["枯松怪石霜竹枝，中有可愛知者誰。", "我能知之不能說，欲說常恐天真非。", "羨君筆端有新意，倏忽萬狀成一揮。", "使我忘言惟獨笑，意所欲說輒見之。", "問胡爲然笑不答，無乃君亦難爲辭。", "晝行書空夜畫被，方其得意尤若癡。", "紛紛落紙不自惜，坐客爭奪相謾欺。", "貴豪滿前謝不與，獨許見贈憐我衰。", "我當枕簟卧其下，暮續膏火朝忘炊。", "門前剝喙不須應，老病人誰稱我爲。"]'),
('36de110f-6629-48a9-a29c-4b40f653b288','仙都山鹿','蘇洵','宋','宋诗','song-poetry','','[]','客來未到何從見，昨夜數聲高出雲。',32,'全唐诗/poet.song.20000.json','["客來未到何從見，昨夜數聲高出雲。", "應是仙君老僮僕，當時掌客意猶勤。"]'),
('4847d8e9-193f-4ea6-8593-4eb7eb6aa013','自尤','蘇洵','宋','宋诗','song-poetry','','[]','五月之旦茲何辰，有女强死無由伸。',384,'全唐诗/poet.song.20000.json','["五月之旦茲何辰，有女强死無由伸。", "嗟予爲父亦不武，使汝孤塚埋冤魂。", "死生壽夭固無定，我豈以此輒怨人。", "當時此事最驚衆，行道聞者皆醉辛。", "余家世世本好學，生女不獨治組紃。", "讀書未省事華飾，下筆亹亹能屬文。", "家貧不敢嫁豪貴，恐彼非偶難爲親。", "汝母之兄汝叔舅，求以厥子來結姻。", "鄉人婚嫁重母族，雖我不肯將安云。", "生年十六亦已嫁，日負憂責無歡欣。", "歸寧見我悲且泣，告我家事不可陳。", "舅姑叔妹不知道，棄禮自快紛如雲。", "人多我寡勢不勝，祗欲强學非天真。", "昨朝告以此太甚，捩耳不聽生怒嗔。", "余言如此非乃事，爲婦何不善一身。", "嗟哉爾夫任此責，可奈狂狠如癡麏。", "忠臣汝不見洩冶，諫死世不非陳君。", "誰知余言果不妄，明年會汝初生孫。", "一朝有疾莫肯視，此意豈尚求爾存。", "憂惶百計獨汝母，復有汝父驚且奔。", "此時汝舅擁愛妾，呼盧握槊如隔鄰。", "狂言發病若有怪，里有老婦能降神。", "呼來問訊豈得已，汝舅責我學不純。", "急難造次不可動，堅坐有類天王尊。"]'),
('7e2d2678-bf88-4469-80f1-63e525fa2ea8','老翁井','蘇洵','宋','宋诗','song-poetry','','[]','井中老翁誤年華，白沙翠石公之家。',64,'全唐诗/poet.song.20000.json','["井中老翁誤年華，白沙翠石公之家。", "公來無蹤去無迹，井面團團水生花。", "翁今與世兩何與，無事紛紛驚牧豎。", "改顔易服與世同，無使市人知有翁。"]'),
('2a497005-16ec-4841-8ee3-be5773f430ee','題閻立本畫水官','蘇洵','宋','宋诗','song-poetry','','[]','水官騎蒼龍，龍行欲上天。',240,'全唐诗/poet.song.20000.json','["水官騎蒼龍，龍行欲上天。", "手攀時且住，浩若乘風船。", "不知幾何長，足尾猶在淵。", "下有二從臣，左右乘魚黿。", "矍鑠相顧視，風舉衣袂翻。", "女子侍君側，白頰垂雙鬟。", "手執雉尾扇，容如未開蓮。", "從者八九人，非鬼非戎蠻。", "出水未成列，先登揚旗旜。", "長刀擁旁牌，白羽注强拳。", "雖服甲與裳，狀貌猶鯨鱣。", "水獸不得從，仰面以手扳。", "空虛走雷霆，雨電晦九川。", "風師黑虎囊，面目昏塵煙。", "翼從三神人，萬里朝天關。", "我從大覺師，得此詭怪編。", "畫者古閻子，于今三百年。", "見者誰不愛，予者誠已難。", "在我猶在子，此理寧非禪。", "報之以好詞，何必畫在前。"]'),
('7f477295-8dbe-41fd-9250-6fa0b632649a','菊花','蘇洵','宋','宋诗','song-poetry','','[]','騷人足奇思，香草比君子。',60,'全唐诗/poet.song.20000.json','["騷人足奇思，香草比君子。", "況此霜下傑，清芬絕蘭茝。", "氣稟金行秀，德備黄中美。", "古來鶴髮翁，餐英飲其水。", "但恐蓬藋傷，課僕加料理。"]'),
('db35fc7a-9888-4107-856e-67f4b4370869','涵虛閣','蘇洵','宋','宋诗','song-poetry','','[]','幽居少塵事，瀟灑似江村。',48,'全唐诗/poet.song.20000.json','["幽居少塵事，瀟灑似江村。", "苔蘇深三徑，衣冠盛一門。", "嶺雲時聚散，湖水自清渾。", "世德書芳史，傳家有令孫。"]'),
('91ea3afd-0a2d-4271-9f33-b775d4c5d977','香','蘇洵','宋','宋诗','song-poetry','','[]','擣麝篩檀入範模，潤分薇露合雞蘇。',64,'全唐诗/poet.song.20000.json','["擣麝篩檀入範模，潤分薇露合雞蘇。", "一絲吐出青煙細，半炷燒成玉筯粗。", "道士每占經次第，佳人惟驗繡工夫。", "軒窗几席隨宜用，不待高擎鵲尾爐。"]'),
('01be4199-4d9e-4e19-8d0f-e0a116d9062d','句  其一','蘇洵','宋','宋诗','song-poetry','','[]','談詩究乎而。',6,'全唐诗/poet.song.20000.json','["談詩究乎而。"]'),
('f4b27b0c-c128-4c13-866b-1408ae69f408','句  其二','蘇洵','宋','宋诗','song-poetry','','[]','雀鷇含淳音，竹蔭抱靜節。',12,'全唐诗/poet.song.20000.json','["雀鷇含淳音，竹蔭抱靜節。"]'),
('77b2159e-7cd7-4f9d-b545-4d21d608b0c5','句','董傳','宋','宋诗','song-poetry','','[]','古來風義遺才少，近世公卿薦士稀。',16,'全唐诗/poet.song.20000.json','["古來風義遺才少，近世公卿薦士稀。"]'),
('1c8de99d-5536-4e07-8bbb-e2265eccd940','同遊柏谷山','王舉元','宋','宋诗','song-poetry','','[]','曉出東郊迥，路穿桑柘林。',48,'全唐诗/poet.song.20000.json','["曉出東郊迥，路穿桑柘林。", "人耕新雨地，寺隠半巖陰。", "遠目窮天宇，和風爽醉襟。", "停驂顧遺老，同是勸農心。"]'),
('35d2684e-60ce-4d41-9002-c6b752874a36','懷荆南舊遊','元絳','宋','宋诗','song-poetry','','[]','去年曾醉海棠叢，聞說新枝發舊紅。',32,'全唐诗/poet.song.20000.json','["去年曾醉海棠叢，聞說新枝發舊紅。", "昨夜夢回花下飲，不知身在玉堂中。"]'),
('339bc951-de31-4aa5-a1ce-cb51476fd920','和','元絳','宋','宋诗','song-poetry','','[]','晼晚年垂盡，陰沈氣始凝。',288,'全唐诗/poet.song.20000.json','["晼晚年垂盡，陰沈氣始凝。", "雲霄方一色，霰雪忽相仍。", "何處茲辰好，吾州自古稱。", "稽山呈刻畫，鑑水弄鮮澄。", "佛土橫銀界，天文露玉繩。", "緶珠壓簾翠，礱璧累臺層。", "崑露朝垂木，郇鹽夕滿塍。", "濃梅明庾嶺，亂蝶鬧青陵。", "舞緩來還轉，驚多下忽騰。", "藏崖未見睍，著霤即垂冰。", "密處情何極，狂時力不勝。", "奪鮮迷野鶴，汙白絕藩蠅。", "孫幌方開卷，焦廬正曲肱。", "悲鳴跧老驥，怒擊下豪鷹。", "顧我雖遲暮，當歡亦彊能。", "醉懷思日富，病眼喜晨興。", "賀帳催休吏，賓筵幸得朋。", "周詩誦昌滿，鄴酌對劉應。", "賞爲良辰樂，高宜善賦登。", "鸘裘欣未至，青簡使先蒸。", "富歲還相慶，陽春各自矜。", "𨠑顔均玉氣，泚墨出珪稜。", "句待呼胡續，舟期訪戴乘。", "長謠辱君贈，珍感服吾膺。"]'),
('c28dd8b6-5179-4b74-9e18-72f7c31f352d','因覽狀元節推和詩再和一首','元絳','宋','宋诗','song-poetry','','[]','緹籥驚年杪，鈴齋戒夙興。',288,'全唐诗/poet.song.20000.json','["緹籥驚年杪，鈴齋戒夙興。", "連空集霙霰，撇席命賓朋。", "菌閣盤虛出，箯輿選勝登。", "出川方晻藹，縞素競飛騰。", "密著珠簾重，低沈粉水澄。", "迷藏秦洞穴，刻鏤禹溝塍。", "蓬島三番抃，瑶峰四徹繩。", "風傳天外籟，湖寫鑑中冰。", "銀色三千界，琳臺十二層。", "折梅思陸凱，詠絮對王凝。", "妬舞輕飄燕，臨書細字繩。", "光凌射的鶴，氣壓沃洲鷹。", "櫂月谿翁共，歌蘭楚客能。", "瓊輈走油壁，練馬頓鉤膺。", "澤滲陽膏動，和薰氣燭蒸。", "冬權時已正，尺瑞歲將應。", "鄙也同民樂，油然弗自勝。", "平時陪法從，長憶奉昭陵。", "拂旦開金殿，鳴鞘下玉乘。", "六花朝服滿，萬歲壽觴稱。", "就望堯雲日，賡歌舜股肱。", "冰醪霑飫賜，竹唱聽哀矜。", "爾後孤蹤遠，頻年老病仍。", "兩朝還觀魏，何日見觚稜。"]'),
('fb3ef36f-12dd-487c-b6f3-66c892a81f41','石傘峯書堂','元絳','宋','宋诗','song-poetry','','[]','奇峰如繖見遥青，玉笥山頭地有靈。',64,'全唐诗/poet.song.20000.json','["奇峰如繖見遥青，玉笥山頭地有靈。", "三徑荒凉丞相隠，一篇清絕放夫銘。", "孤標竦處天門近，直影圓時日御停。", "誰躡巖梯訪遺迹，遠孫高謝在鴻冥。"]'),
('bb750c11-cf6a-4902-bf14-0436f3180d49','題溪口廣慈寺','元絳','宋','宋诗','song-poetry','','[]','雲外軒窗切斗牛，翛然三伏亦生秋。',32,'全唐诗/poet.song.20000.json','["雲外軒窗切斗牛，翛然三伏亦生秋。", "青山屈曲無重數，俱束溪光款款流。"]'),
('f129255f-576e-483e-a803-37d90ed2eaab','送程給事知越州','元絳','宋','宋诗','song-poetry','','[]','四十年來出處同，交情偏見歲寒中。',96,'全唐诗/poet.song.20000.json','["四十年來出處同，交情偏見歲寒中。", "相先各上青雲路，鬭在俱爲白髮翁。", "萬里厭勞方稍稍，一麾乘興又忽忽。", "清風冠劍辭仙殿，流水旌旗下越宮。", "山半樓臺迎日動，帳前鐃鼓入秋雄。", "因君更憶蓬萊雪，不覺吟魂過剡東。"]'),
('00bae034-bad4-44da-a12b-e6413064676d','和聖徒洛中九老會','元絳','宋','宋诗','song-poetry','','[]','五日佳辰郡政閑，延賓談笑豁幽關。',64,'全唐诗/poet.song.20000.json','["五日佳辰郡政閑，延賓談笑豁幽關。", "閶門歌舞尊罍上，林屋煙霞指顧間。", "德應華星臨潁尾，年拘皓髮下商顔。", "名花美酒疎鐘永，坐見斜暉隠半山。"]'),
('638daf88-1b08-4f81-8905-d6a27865fd6e','趙潛叔殉節詩','元絳','宋','宋诗','song-poetry','','[]','轉戰譙門日再晡，空拳由自冒戈殳。',64,'全唐诗/poet.song.20000.json','["轉戰譙門日再晡，空拳由自冒戈殳。", "身垂虎口方安坐，命棄鴻毛更疾呼。", "柱下杲卿存斷節，袴間杵臼得遺孤。", "可憐三尺英雄氣，不愧西山士大夫。"]'),
('14b0c097-d36e-4f73-8e6d-4ac237d6c13d','送梵才大師歸天台','元絳','宋','宋诗','song-poetry','','[]','責重憂多兩鬢斑，十年長夢赤城山。',32,'全唐诗/poet.song.20000.json','["責重憂多兩鬢斑，十年長夢赤城山。", "何時得似凈名子，潄石眠雲恣意閒。"]'),
('08444ee6-9847-4ae3-a6f2-e51f33803640','題秀野亭','元絳','宋','宋诗','song-poetry','','[]','亭占青山口，郊原四望平。',48,'全唐诗/poet.song.20000.json','["亭占青山口，郊原四望平。", "遥林連崦黑，白水隔田明。", "翠麥波濤動，飛泉劍珮輕。", "長年便野趣，擬欲解塵纓。"]'),
('37e255d1-f684-4436-a6c4-17b050ee5ac4','將去郡席上呈同僚','元絳','宋','宋诗','song-poetry','','[]','在官七百二十日，只爲云州不爲身。',64,'全唐诗/poet.song.20000.json','["在官七百二十日，只爲云州不爲身。", "民事勤勞心力盡，世涂憂畏鬢華新。", "離筵欲醉樽前月，美景難留洞口春。", "他日相逢應更好，諸君皆是眼中人。"]'),
('c04b5893-2225-4bb8-b58d-048d34d800da','巡按睦州過烏龍山','元絳','宋','宋诗','song-poetry','','[]','羣山衮衮卷波濤，舉手天門尺五高。',32,'全唐诗/poet.song.20000.json','["羣山衮衮卷波濤，舉手天門尺五高。", "塵土多年昏病眼，猶能千里見秋毫。"]'),
('3eed77ad-f1c3-46fc-bb87-e5acce913772','桐廬晚景','元絳','宋','宋诗','song-poetry','','[]','向晚西風急，扁舟下瀨輕。',48,'全唐诗/poet.song.20000.json','["向晚西風急，扁舟下瀨輕。", "帆檣掛山影，鼓吹壓潮聲。", "白鳥煙中沒，斜陽雨外明。", "汕然五湖意，渾欲薄功名。"]'),
('aeb58194-5aba-44f5-adf9-3f5eb7039ee4','賀王禹玉','元絳','宋','宋诗','song-poetry','','[]','前殿聽宣中禁制，南宮看集外朝班。',32,'全唐诗/poet.song.20000.json','["前殿聽宣中禁制，南宮看集外朝班。", "星辰影落三階下，桃李陰成四海閒。"]'),
('75cd2501-d25d-4eaa-abb7-199dcf94b937','詔修兩朝國史開局日賜筵史院和首相吳公席上韻','元絳','宋','宋诗','song-poetry','','[]','殿帷昕對罷，省戶雨陰餘。',48,'全唐诗/poet.song.20000.json','["殿帷昕對罷，省戶雨陰餘。", "詔賜堯尊酒，人探禹穴書。", "夔龍方客右，班馬蓋徒歟。", "徑醉俄婦弁，雲西見日車。"]'),
('636057de-f90e-4c27-b7bb-610eee4848b3','流觸亭詩','元絳','宋','宋诗','song-poetry','','[]','春風流水出巖扉，載酒輕舟颺綵旗。',32,'全唐诗/poet.song.20000.json','["春風流水出巖扉，載酒輕舟颺綵旗。", "把得玉杯還自笑，老翁真令似童兒。"]'),
('f23b84fd-4558-4e62-aca4-ea4e087f7bd4','隠几菴詩','元絳','宋','宋诗','song-poetry','','[]','分得藩符近海濱，溪山清處養天真。',32,'全唐诗/poet.song.20000.json','["分得藩符近海濱，溪山清處養天真。", "幅巾隠几春菴靜，直是羲皇已上人。"]'),
('6b17dc7d-a157-4b66-84a9-dfc91e522972','題鼓山元公亭','元絳','宋','宋诗','song-poetry','','[]','誰書吾姓揭亭顔，棟宇飛騰氣象完。',64,'全唐诗/poet.song.20000.json','["誰書吾姓揭亭顔，棟宇飛騰氣象完。", "谷口秋風吹鬢髮，海東朝日上蘭干。", "地高頓覺羣山小，天近須知六合寬。", "三到巖扉殊不厭，異時長向畫圖看。"]'),
('467acb84-7faa-4662-9a1b-2fe358aaa24b','鳳池山','元絳','宋','宋诗','song-poetry','','[]','州人未識鳳池山，朱轂時來此往還。',64,'全唐诗/poet.song.20000.json','["州人未識鳳池山，朱轂時來此往還。", "四坐杯盤在天上，滿軒雲雨落人間。", "千圍老木排旌蓋，百尺飛泉響珮環。", "誰爲霜綃圖景象，翠微高處一開顔。"]'),
('20264b41-9c3c-47a1-8a15-3d6c49e21a52','愛亭','元絳','宋','宋诗','song-poetry','','[]','朱轓何事獨來頻，不爲溪山只爲民。',32,'全唐诗/poet.song.20000.json','["朱轓何事獨來頻，不爲溪山只爲民。", "最愛年年禾稻熟，時豐自有壤歌人。"]'),
('a8e4d57b-7dfb-4a17-8a58-fe8df9c84f77','謝京師故人','元絳','宋','宋诗','song-poetry','','[]','丹荔黄甘北苑茶，勞君誘我向天涯。',32,'全唐诗/poet.song.20000.json','["丹荔黄甘北苑茶，勞君誘我向天涯。", "爭如太液樓邊看，池北池南總是春。"]'),
('2df1417e-8fcb-40c2-aa37-9a2135614897','泗洲嶺','元絳','宋','宋诗','song-poetry','','[]','萬里一朱轓，崎嶇度嶺關。',24,'全唐诗/poet.song.20000.json','["萬里一朱轓，崎嶇度嶺關。", "路盤雲雨際，人在斗牛間。"]'),
('0a5dbc4b-6d43-41eb-8512-7874ab9dafb9','詩一首','元絳','宋','宋诗','song-poetry','','[]','閩山過盡見吳山，三載天涯五馬還。',64,'全唐诗/poet.song.20000.json','["閩山過盡見吳山，三載天涯五馬還。", "舊列未歸青瑣闥，餘生方入玉門關。", "林巒迤邐平無數，星斗闌干近可攀。", "回首冶城何處所，只應煙雨渺茫間。"]'),
('419fa5ca-8245-42d1-8f35-52be670ebe23','戊戌清明在吳去春閱武于河朔今被召參貳大農悅然有感','元絳','宋','宋诗','song-poetry','','[]','前載賞花鄉國中，三行粉面綺羅紅。',64,'全唐诗/poet.song.20000.json','["前載賞花鄉國中，三行粉面綺羅紅。", "去看持斧邊城下，十萬軍聲鼓吹雄。", "每歲春輝長忽忽，此時朝騎又怱怱。", "却將半暗塵沙眼，去看東都御柳風。"]'),
('7c028c4c-3aee-419e-b595-42413c2b87f3','次韻和君貺會趙叔平少師','元絳','宋','宋诗','song-poetry','','[]','黄髮逍遥并舊臣，燕閒加意占先春。',64,'全唐诗/poet.song.20000.json','["黄髮逍遥并舊臣，燕閒加意占先春。", "成龍天外惟三友，積雪筵中止數人。", "昔日薦才聞最課，當年誦賦得魁倫。", "會須共作遊河侶，五老星飛事更新。"]'),
('b645c2d2-2502-4b8d-9c68-bf56322cba35','和上巳西湖勝遊','元絳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','清明風日戰方酣，朱轂雍容擁旆鬖。',96,'全唐诗/poet.song.20000.json','["清明風日戰方酣，朱轂雍容擁旆鬖。", "火令正嚴綿上俗，禊遊仍勝會稽巖。", "馬盤金埒連乾濕，人映氊車帽角攙。", "湖水綠煙浮醉席，杏花紅雨拂春衫。", "公如庾老情非淺，客似淵君調不凡。", "只恐潁川飛召節，便隨五鳳降綈函。"]'),
('f451e0aa-d613-4337-82a4-cd7c161d1ea0','和梅龍圖遊西湖見寄','元絳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖上喜明霽，尋春偶嘯儔。',48,'全唐诗/poet.song.20000.json','["湖上喜明霽，尋春偶嘯儔。", "花多紅夾馬，山遠翠藏樓。", "水氣煙中合，風光草際流。", "都人待千騎，快作謝公遊。"]'),
('df0f0ff2-898f-42eb-ad6f-15ddc2a18ff7','早梅','元絳','宋','宋诗','song-poetry','','[]','照夜直爲明月侶，倚風先作艷陽媒。',32,'全唐诗/poet.song.20000.json','["照夜直爲明月侶，倚風先作艷陽媒。", "多情欲著紅粧面，故上含章白玉臺。"]'),
('0f976bb8-a1cc-424f-852d-8f5c50b58089','和人','元絳','宋','宋诗','song-poetry','','[]','筆下雲霞落彩牋，諸君清思盡佳篇。',32,'全唐诗/poet.song.20000.json','["筆下雲霞落彩牋，諸君清思盡佳篇。", "誰人讀得郊居字，流水湯湯正滿弦。"]'),
('068f813e-97aa-4c8f-9bb7-ccbb34dde6a1','過牛光祿故居','元絳','宋','宋诗','song-poetry','','[]','白頭重到故人家，境是人非起歎嗟。',64,'全唐诗/poet.song.20000.json','["白頭重到故人家，境是人非起歎嗟。", "三徑未荒陶令菊，四時長放庾郎花。", "林風光動藏鶑葉，溪漲痕生宿鷺沙。", "肯構有材移病久，會憑詩酒傲煙霞。"]'),
('8eb99bc3-3d50-41a9-bb15-2a784c1040ba','永新縣春風亭','元絳','宋','宋诗','song-poetry','','[]','三年到此百無功，種得桃花滿縣紅。',32,'全唐诗/poet.song.20000.json','["三年到此百無功，種得桃花滿縣紅。", "此日不能收拾去，一時分付與東風。"]'),
('beb2cbf7-aba5-4fd9-b0b6-fcd0f9766b98','挽贈太常少卿封川曹使君覲','元絳','宋','宋诗','song-poetry','','[]','倉卒蠻鼙上水濱，使君忠憤獨亡身。',64,'全唐诗/poet.song.20000.json','["倉卒蠻鼙上水濱，使君忠憤獨亡身。", "平明戈劍摧城闔，俄頃衣冠落路塵。", "志士一門能許國，老夫當日亦知人。", "朝延贈襚哀榮極，青骨千金合有神。"]'),
('e3ee99b1-2118-49a2-90f8-821a85ce0e47','句  其一','元絳','宋','宋诗','song-poetry','','[]','九重侍從三明主，四紀乾坤一老臣。',16,'全唐诗/poet.song.20000.json','["九重侍從三明主，四紀乾坤一老臣。"]'),
('96c77b2d-17f9-4d1c-9ea9-b60786d23570','句  其二','元絳','宋','宋诗','song-poetry','','[]','過廬都失眼前人。',8,'全唐诗/poet.song.20000.json','["過廬都失眼前人。"]'),
('4fd25680-1307-4ed8-8284-65a95011e324','句  其三','元絳','宋','宋诗','song-poetry','','[]','仙驥籋雲穿仗下，佛花吹雨匝天流。',16,'全唐诗/poet.song.20000.json','["仙驥籋雲穿仗下，佛花吹雨匝天流。"]'),
('662fa985-cf15-40b1-ad44-5c2091f816f6','句  其四','元絳','宋','宋诗','song-poetry','','[]','黄閣勢連東鳳闕，紫樞光直右銀臺。',16,'全唐诗/poet.song.20000.json','["黄閣勢連東鳳闕，紫樞光直右銀臺。"]'),
('444ed599-e5bf-4124-b9c9-f87473794157','句  其五','元絳','宋','宋诗','song-poetry','','[]','聯名適似三株樹，傳玩驚看五朵雲。',16,'全唐诗/poet.song.20000.json','["聯名適似三株樹，傳玩驚看五朵雲。"]'),
('cc5a0f01-56e4-4144-b187-ff2ce4289cfe','句  其六','元絳','宋','宋诗','song-poetry','','[]','英翰五五出南閩。',8,'全唐诗/poet.song.20000.json','["英翰五五出南閩。"]'),
('4d5c1075-9615-42bf-b5c1-4b44732efe39','句  其七','元絳','宋','宋诗','song-poetry','','[]','可惜閩州風物好，一生魂夢到三山。',16,'全唐诗/poet.song.20000.json','["可惜閩州風物好，一生魂夢到三山。"]'),
('1502de92-f776-43af-b75f-38a276b64d52','句  其八','元絳','宋','宋诗','song-poetry','','[]','何人更得通天带，謀合君心只晉公。',16,'全唐诗/poet.song.20000.json','["何人更得通天带，謀合君心只晉公。"]'),
('8cd69ee3-5f53-4260-975f-e09d287e484b','句  其九','元絳','宋','宋诗','song-poetry','','[]','笙歌車馬東方曉，風月山川北固涼。',16,'全唐诗/poet.song.20000.json','["笙歌車馬東方曉，風月山川北固涼。"]'),
('a747f5ef-7c12-4b0c-ba46-62a47843f39a','句  其一○','元絳','宋','宋诗','song-poetry','','[]','玉露精神山合沓，溪成文字水橫斜。',16,'全唐诗/poet.song.20000.json','["玉露精神山合沓，溪成文字水橫斜。"]'),
('b77e11f1-621a-46a6-8f31-ab267c6ab8f0','句  其一一','元絳','宋','宋诗','song-poetry','','[]','神石溪頭好明月，夜來誰此凭蘭橈。',16,'全唐诗/poet.song.20000.json','["神石溪頭好明月，夜來誰此凭蘭橈。"]'),
('17533164-200f-4233-8bab-9bdba8b1c90d','句  其一二','元絳','宋','宋诗','song-poetry','','[]','使君麾蓋傲煙霞。',8,'全唐诗/poet.song.20000.json','["使君麾蓋傲煙霞。"]'),
('d15037a8-3928-4232-80bb-c688c53b6741','句  其一三','元絳','宋','宋诗','song-poetry','','[]','陳前輿服同桓傅，拜後金珠有魯公。',16,'全唐诗/poet.song.20000.json','["陳前輿服同桓傅，拜後金珠有魯公。"]'),
('16273a3d-e942-496b-92f5-9ce346f8320a','句  其一四','元絳','宋','宋诗','song-poetry','','[]','花陰轉午清風細，玉燕釵頭艾虎輕。',16,'全唐诗/poet.song.20000.json','["花陰轉午清風細，玉燕釵頭艾虎輕。"]'),
('9d7a9684-9991-4b8c-b323-47e8043f3573','句  其一五','元絳','宋','宋诗','song-poetry','','[]','五蓂開端莢，百草鬭香苕。',12,'全唐诗/poet.song.20000.json','["五蓂開端莢，百草鬭香苕。"]'),
('55da9d3c-04b6-421d-87ea-821e6675402a','句  其一六','元絳','宋','宋诗','song-poetry','','[]','五日看花憐并葉，今朝鬭草得宜男。',16,'全唐诗/poet.song.20000.json','["五日看花憐并葉，今朝鬭草得宜男。"]'),
('2e76f7c5-dd52-4b47-b9b4-3c6c2faaf1ab','句  其一七','元絳','宋','宋诗','song-poetry','','[]','菖酒朝觸滿，蘭湯曉浴溫。',12,'全唐诗/poet.song.20000.json','["菖酒朝觸滿，蘭湯曉浴溫。"]'),
('9a1742e7-8825-44e6-86ea-5394a916e0f2','句  其一八','元絳','宋','宋诗','song-poetry','','[]','絲竹漸高橈鼓急，瑶津亭下競鳬車。',16,'全唐诗/poet.song.20000.json','["絲竹漸高橈鼓急，瑶津亭下競鳬車。"]');
